// ── SUBSCRIPTION READ-ONLY GUARD ─────────────────────────────────────────────
// Returns true and shows toast if subscription is expired (read-only mode).
// Call at the top of any write action: if (subReadOnlyGuard()) return;
function subReadOnlyGuard() {
  if (window._subStatus && window._subStatus.is_read_only) {
    toast('🔒 Subscription expired — contact your FuelBunk Pro admin to renew', 'error');
    return true;
  }
  return false;
}

// ── ALLOCATION CONFLICT AUDIT — scans all saved allocations for overlaps ─────
window._renderAllocConflictBanner = function(D2, allocObj) {
  try {
    if (!D2 || !allocObj) return '';
    const shifts2 = D2.shifts || [];
    if (shifts2.length < 2) return '';

    // Self-contained overlap check — no external dependencies
    function _localOverlap(sA, sB) {
      var toMin = function(t) { var p=(t||'00:00').split(':'); return parseInt(p[0]||0)*60+parseInt(p[1]||0); };
      var as=toMin(sA.start), ae=toMin(sA.end), bs=toMin(sB.start), be=toMin(sB.end);
      // overnight: end <= start means crosses midnight, add 1440
      var ae2 = ae <= as ? ae+1440 : ae;
      var be2 = be <= bs ? be+1440 : be;
      // a shift equal start+end (e.g. 06:00-06:00) = full 24h
      if (ae2 === as) ae2 = as + 1440;
      if (be2 === bs) be2 = bs + 1440;
      function ov(a1,a2,b1,b2){ return a1 < b2 && a2 > b1; }
      return ov(as,ae2,bs,be2) || ov(as+1440,ae2+1440,bs,be2) || ov(as,ae2,bs+1440,be2+1440);
    }

    // Self-contained sanitize — no external dependencies
    function _san(s) { return String(s||'').replace(/[<>&"']/g, function(c){return({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;',"'":'&#39;'}[c]);}); }

    var allConflicts = [];
    var allKeys = Object.keys(allocObj);

    allKeys.forEach(function(dkA) {
      if (!dkA || dkA.length < 12) return;
      var date = dkA.slice(0, 10);
      if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) return;
      var shiftNameA = dkA.slice(11);
      var sA = null;
      for (var i=0;i<shifts2.length;i++) { if (shifts2[i].name === shiftNameA) { sA=shifts2[i]; break; } }
      if (!sA) return;
      var allocA = allocObj[dkA] || {};
      var nKeysA = Object.keys(allocA);
      if (nKeysA.length === 0) return;

      allKeys.forEach(function(dkB) {
        if (dkB <= dkA) return;
        if (dkB.slice(0,10) !== date) return;
        var shiftNameB = dkB.slice(11);
        var sB = null;
        for (var j=0;j<shifts2.length;j++) { if (shifts2[j].name === shiftNameB) { sB=shifts2[j]; break; } }
        if (!sB) return;
        if (!_localOverlap(sA, sB)) return;
        var allocB = allocObj[dkB] || {};

        nKeysA.forEach(function(nKey) {
          if (!allocB[nKey]) return;
          var empA = null, empB = null;
          for (var k=0;k<(D2.employees||[]).length;k++) {
            if (parseInt(D2.employees[k].id) === parseInt(allocA[nKey])) empA = D2.employees[k];
            if (parseInt(D2.employees[k].id) === parseInt(allocB[nKey])) empB = D2.employees[k];
          }
          var nParts = nKey.split('_');
          var pumpId = nParts[0], nozzle = nParts[1];
          var pump2 = null;
          for (var m=0;m<(D2.pumps||[]).length;m++) { if (String(D2.pumps[m].id)===pumpId) { pump2=D2.pumps[m]; break; } }
          allConflicts.push({
            date: date, nKey: nKey, pumpId: pumpId, nozzle: nozzle,
            pump: pump2 ? pump2.name : ('Pump '+pumpId),
            shiftA: shiftNameA, shiftB: shiftNameB,
            empA: empA ? empA.name : '?', empB: empB ? empB.name : '?'
          });
        });
      });
    });

    console.log('[ConflictBanner] scanned', allKeys.length, 'keys, found', allConflicts.length, 'conflicts');
    if (allConflicts.length === 0) return '';

    var rows = allConflicts.map(function(c) {
      var dateLabel = new Date(c.date).toLocaleDateString('en-IN', {day:'numeric',month:'short'});
      return '<div style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:rgba(239,68,68,0.06);border-radius:6px;margin-bottom:6px;flex-wrap:wrap;font-size:12px">'
        + '<span style="color:var(--red);font-weight:700;white-space:nowrap">⚠ '+_san(c.pump)+' · N'+c.nozzle+' · '+dateLabel+'</span>'
        + '<span style="color:var(--text-2);white-space:nowrap"><strong>'+_san(c.shiftA)+'</strong> → '+_san(c.empA)+'</span>'
        + '<span style="color:var(--text-3)">vs</span>'
        + '<span style="color:var(--text-2);white-space:nowrap"><strong>'+_san(c.shiftB)+'</strong> → '+_san(c.empB)+'</span>'
        + '<div style="display:flex;gap:6px;margin-left:auto;flex-shrink:0">'
        + '<button class="btn btn-ghost btn-sm" style="font-size:10px;color:var(--red);border-color:rgba(239,68,68,0.4)" onclick="window._fixAlloc(this)" data-shift="'+c.shiftA+'" data-date="'+c.date+'">Fix '+_san(c.shiftA)+'</button>'
        + '<button class="btn btn-ghost btn-sm" style="font-size:10px;color:var(--red);border-color:rgba(239,68,68,0.4)" onclick="window._fixAlloc(this)" data-shift="'+c.shiftB+'" data-date="'+c.date+'">Fix '+_san(c.shiftB)+'</button>'
        + '</div></div>';
    }).join('');

    return '<div style="padding:12px 16px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.3);border-radius:10px;margin-bottom:16px">'
      + '<div style="font-size:13px;font-weight:700;color:var(--red);margin-bottom:10px">'
      + '⚠️ '+allConflicts.length+' pump conflict'+(allConflicts.length>1?'s':'')+' — same nozzle assigned to two overlapping shifts'
      + '</div>'+rows
      + '<div style="font-size:11px;color:var(--text-3);margin-top:8px">Use Fix buttons to open that shift on that date, then click ✕ on the conflicting assignment.</div>'
      + '</div>';
  } catch(e) {
    console.error('[ConflictBanner] ERROR:', e.message, e.stack);
    return '';
  }
};

// Helper called by conflict banner Fix buttons
window._fixAlloc = function(btn) {
  var shift = btn.getAttribute('data-shift');
  var date  = btn.getAttribute('data-date');
  if (shift) allocShift = shift;
  if (date)  allocDate  = date;
  window.staffTab = 'allocation';
  renderPage();
};

// ── Normalize null shift times — auto-heals missing start/end in DB ─────────
// Saves corrected shifts back to DB so they're fixed permanently after first load.
function _normalizeShiftTimes(shifts) {
  if (!Array.isArray(shifts)) return;
  const DEFAULTS = {
    'morning':   { start: '06:00', end: '14:00' },
    'noon':      { start: '14:00', end: '22:00' },
    'afternoon': { start: '14:00', end: '22:00' },
    'evening':   { start: '18:00', end: '02:00' },
    'night':     { start: '22:00', end: '06:00' },
    '24':        { start: '06:00', end: '06:00' },
  };
  shifts.forEach(s => {
    if (!s.start || !s.end) {
      const key = Object.keys(DEFAULTS).find(k => (s.name||'').toLowerCase().includes(k));
      const def = DEFAULTS[key] || { start: '06:00', end: '14:00' };
      if (!s.start) s.start = def.start;
      if (!s.end)   s.end   = def.end;
      // Persist fix to DB so it never happens again
      if (typeof db !== 'undefined') db.put('shifts', s).catch(() => {});
      console.log('[FuelBunk] Auto-fixed shift times for:', s.name, s.start, '-', s.end);
    }
  });
}

function renderDashboard(D) {
  // FIX 31: use IST today() to prevent off-by-one during 18:30-00:00 UTC
  const todayIso = (typeof window.today === 'function') ? window.today() : new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10);
  const todaySales = D.sales.filter(s => (s.date || '').slice(0, 10) === todayIso);
  const totalRevenue = todaySales.reduce((a, s) => a + s.amount, 0);
  const totalLiters = todaySales.reduce((a, s) => a + s.liters, 0);
  const cashSales = todaySales.filter(s => s.mode === 'cash').reduce((a, s) => a + s.amount, 0);

  // ── Build weekly chart data from real D.sales ──
  const dayNames = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  D.weekly = Array.from({length: 7}, (_, i) => {
    const d = new Date(); d.setDate(d.getDate() - (6 - i));
    const iso = d.toISOString().slice(0, 10);
    const daySales = D.sales.filter(s => (s.date || '').slice(0, 10) === iso);
    return {
      day: dayNames[d.getDay()],
      petrol:  daySales.filter(s => s.fuelType === 'petrol').reduce((a,s) => a + s.liters, 0),
      diesel:  daySales.filter(s => s.fuelType === 'diesel').reduce((a,s) => a + s.liters, 0),
      premium: daySales.filter(s => s.fuelType !== 'petrol' && s.fuelType !== 'diesel').reduce((a,s) => a + s.liters, 0),
      revenue: daySales.reduce((a,s) => a + s.amount, 0),
    };
  });
  // Credit pending = customer outstanding balances (authoritative source)
  const totalCredit = D.creditCustomers.reduce((a, c) => a + (c.outstanding || 0), 0);
  const h = new Date().getHours();

  // Payment breakdown
  let payBars = '';
  ['cash', 'upi', 'card', 'credit'].forEach(mode => {
    const total = todaySales.filter(s => s.mode === mode).reduce((a, s) => a + s.amount, 0);
    const pct = totalRevenue > 0 ? (total / totalRevenue) * 100 : 0;
    payBars += `<div style="margin-bottom:10px">
      <div class="flex-between" style="font-size:12px;margin-bottom:4px">
        <span style="text-transform:capitalize">${mode}</span>
        <span style="color:${payColors[mode]}" class="fw-700 mono">${cur(total)} (${pct.toFixed(1)}%)</span>
      </div>
      <div class="progress progress-xs"><div class="progress-bar" style="width:${pct}%;background:${payColors[mode]}"></div></div>
    </div>`;
  });

  // Tank gauges
  let tanksHtml = [...D.tanks].sort((a, b) => (parseInt(a.id)||0) - (parseInt(b.id)||0)).map(t => {
    const fuel = getFuel(t.fuelType);
    const pct = t.capacity > 0 ? (t.current / t.capacity) * 100 : 0;
    const isLow = pct < 25;
    const barColor = isLow ? '#ef4444' : fuel.color;
    return `<div class="card card-pad">
      <div class="flex-between mb-10">
        <span class="fw-600" style="color:var(--text-0);font-size:13px">Tank ${t.id} — <span style="color:${fuel.color}">${fuel.short}</span></span>
        ${isLow ? badge('LOW', 'badge-red') : ''}
      </div>
      ${progressBar(pct, barColor, 'progress-lg')}
      <div class="flex-between mt-8" style="font-size:11px;color:var(--text-3)"><span class="mono">${fmt(t.current)} L</span><span>/ ${fmt(t.capacity)} L</span></div>
    </div>`;
  }).join('');

  // Weekly charts
  const petrolBars = miniBar(D.weekly.map(d => ({ l: d.day, v: d.petrol })), '#ef4444');
  const dieselBars = miniBar(D.weekly.map(d => ({ l: d.day, v: d.diesel })), '#f97316');
  const premiumBars = miniBar(D.weekly.map(d => ({ l: d.day, v: d.premium })), '#a855f7');
  const revBars = miniBar(D.weekly.map(d => ({ l: d.day, v: d.revenue })), '#22c55e');
  const weeklyTotal = D.weekly.reduce((a, d) => a + d.revenue, 0);
  const avgRev = weeklyTotal / 7;

  // Active shift — normalize null start/end before use
  _normalizeShiftTimes(D.shifts);
  let shiftsHtml = D.shifts.map(s => {
    const [sh] = (s.start||'00:00').split(':').map(Number);
    const [eh] = (s.end||'00:00').split(':').map(Number);
    const isActive = sh < eh ? (h >= sh && h < eh) : (h >= sh || h < eh);
    return `<div class="shift-block ${isActive ? 'is-active' : ''}" style="margin-bottom:8px">
      <div class="flex-between">
        <div><span class="fw-600" style="color:${isActive ? 'var(--accent-light)' : 'var(--text-3)'};font-size:13px">${s.name}</span>
        <span style="font-size:12px;color:var(--text-3);margin-left:8px" class="mono">${s.start} – ${s.end}</span></div>
        ${isActive ? badge('LIVE', 'badge-accent') : ''}
      </div>
      ${(() => {
        // Resolve manager live: by ID first, then fall back to name match
        let managerName = s.manager || '—';
        if (s.managerId) {
          const me = D.employees.find(e => e.id === s.managerId);
          if (me) managerName = me.name;
        } else if (s.manager) {
          // legacy: name stored, try to find current name by matching Shift Manager role
          const me = D.employees.find(e => e.role === 'Shift Manager' && e.name === s.manager);
          if (!me) {
            // name may have changed — show whatever is in s.manager but flag it
            managerName = s.manager;
          }
        }
        return managerName !== '—'
          ? `<div style="font-size:12px;color:var(--text-3);margin-top:4px">Manager: <span style="color:var(--text-1);font-weight:600">${sanitize(managerName)}</span></div>`
          : '';
      })()}
    </div>`;
  }).join('');

  const petrolLiters  = todaySales.filter(s => s.fuelType === 'petrol').reduce((a, s) => a + s.liters, 0);
  const dieselLiters  = todaySales.filter(s => s.fuelType === 'diesel').reduce((a, s) => a + s.liters, 0);
  const premiumLiters = todaySales.filter(s => s.fuelType !== 'petrol' && s.fuelType !== 'diesel').reduce((a, s) => a + s.liters, 0);

  // ── Nozzle meter variance alert ──────────────────────────────────────────
  const nmlToday = (window._nozzleMeterLog || []).filter(e => e.date === todayIso && e.flagged);
  const nmlAlert = nmlToday.length > 0
    ? `<div style="grid-column:1/-1;padding:12px 16px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.3);border-radius:10px;display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:8px;flex-wrap:wrap">
        <div style="display:flex;align-items:center;gap:10px">
          <span style="font-size:20px">🚨</span>
          <div>
            <div class="fw-700" style="color:var(--red);font-size:13px">${nmlToday.length} Nozzle Variance${nmlToday.length>1?'s':''} Flagged Today</div>
            <div style="font-size:11px;color:var(--text-3)">${nmlToday.map(e=>sanitize(e.pumpName)+' N'+e.nozzle+': '+fmt(Math.abs(e.variance))+'L').join(' · ')}</div>
          </div>
        </div>
        <button class="btn btn-ghost btn-sm" onclick="navigate('pumps')" style="color:var(--red);border-color:rgba(239,68,68,0.3)">View Pumps →</button>
      </div>`
    : '';

  // Subscription status badge — fetch if not loaded or stale (>60s)
  const _subAge = window._subStatusAt ? (Date.now() - window._subStatusAt) : Infinity;
  if (!window._subStatus || _subAge > 60000) {
    const tid = APP.tenant?.id;
    if (tid) {
      fetch('/api/public/subscription/' + encodeURIComponent(tid))
        .then(r => r.json()).then(s => {
          var wasExpired = window._subStatus && window._subStatus.is_read_only;
          window._subStatus = s;
          window._subStatusAt = Date.now();
          // Only re-render if status changed (avoid loop)
          if (wasExpired !== s.is_read_only && APP.page === 'dashboard') renderPage();
        }).catch(()=>{});
    }
  }
  const sub = window._subStatus;
  const subBadge = sub ? (() => {
    const STATUS_MAP = {
      trial:     { bg:'rgba(59,130,246,0.12)', col:'#60a5fa', icon:'⏱️', label: sub.trial_days_left > 0 ? `Trial — ${sub.trial_days_left} days left` : 'Trial Expired' },
      active:    { bg:'rgba(34,197,94,0.12)',  col:'var(--green)', icon:'✅', label: sub.days_left > 7 ? `Active — expires ${new Date(sub.sub_end).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})}` : `Active — ${sub.days_left} days left` },
      grace:     { bg:'rgba(249,115,22,0.12)', col:'var(--orange)', icon:'⚠️', label: `Grace period — renew now` },
      expired:   { bg:'rgba(239,68,68,0.12)',  col:'var(--red)', icon:'🔒', label: 'Subscription expired — Read only mode' },
      suspended: { bg:'rgba(148,163,184,0.12)',col:'var(--text-3)', icon:'⏸️', label: 'Subscription suspended' },
    };
    const s = STATUS_MAP[sub.status] || STATUS_MAP.expired;
    return `<div style="padding:8px 14px;background:${s.bg};border-radius:8px;margin-bottom:16px;display:flex;align-items:center;gap:8px;font-size:12px">
      <span>${s.icon}</span>
      <span style="color:${s.col};font-weight:700">${s.label}</span>
      ${sub.status === 'expired' || sub.status === 'grace' ? '<span style="margin-left:auto;font-size:11px;color:var(--text-3)">Contact support to renew</span>' : ''}
    </div>`;
  })() : '';

  const readOnlyBanner = (sub && sub.is_read_only) ? `
    <div style="padding:12px 16px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.3);border-radius:10px;margin-bottom:16px;text-align:center">
      <div style="font-size:15px;font-weight:700;color:var(--red);margin-bottom:4px">🔒 Subscription Expired — Read Only Mode</div>
      <div style="font-size:12px;color:var(--text-3)">You can view all your data but cannot add new sales, purchases or records. Please renew your subscription to continue.</div>
    </div>` : '';

  return `
    ${readOnlyBanner}
    ${nmlAlert}
    ${subBadge}
    <div class="g g-auto-sm mb-24 gap-16">
      ${statCard('Today\'s Revenue', cur(totalRevenue), 'all pumps today', '💰')}
      ${statCard('Petrol Sold', fmt(petrolLiters) + ' L', 'today', '🔴')}
      ${statCard('Diesel Sold', fmt(dieselLiters) + ' L', 'today', '🟠')}
      ${statCard('Premium Sold', fmt(premiumLiters) + ' L', 'today', '🟣')}
    </div>

    <div class="g g-2 gap-16 mb-24">
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">📊 Weekly Sales Volume (Liters)</h4>
        <div class="flex" style="gap:20px">
          <div style="flex:1"><div class="c-petrol fw-700 mb-8" style="font-size:11px">Petrol</div>${petrolBars}</div>
          <div style="flex:1"><div class="c-diesel fw-700 mb-8" style="font-size:11px">Diesel</div>${dieselBars}</div>
          <div style="flex:1"><div class="c-premium fw-700 mb-8" style="font-size:11px">Premium</div>${premiumBars}</div>
        </div>
      </div>
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">📈 Weekly Revenue</h4>
        ${revBars}
        <div class="flex-between mt-12" style="font-size:11px;color:var(--text-3)">
          <span>Avg: <span class="mono fw-600">${cur(avgRev)}</span>/day</span>
          <span>Peak: <span class="mono fw-600">${cur(D.weekly.length ? Math.max(...D.weekly.map(d => d.revenue)) : 0)}</span></span>
        </div>
      </div>
    </div>

    <h4 class="mb-14 fw-700" style="color:var(--text-0);font-size:13px">🛢️ Tank Levels</h4>
    <div class="g g-auto mb-24 gap-16">${tanksHtml}</div>

    <div class="g g-2 gap-16 mb-24">
      <div class="card card-pad"><h4 class="mb-14 fw-700" style="color:var(--text-0);font-size:13px">💳 Sales by Payment</h4>${payBars}</div>
      <div class="card card-pad"><h4 class="mb-14 fw-700" style="color:var(--text-0);font-size:13px">⏰ Shift Status</h4>${shiftsHtml}</div>
    </div>
    <div class="card card-pad">
      <div class="flex-between mb-16">
        <h4 class="fw-700" style="color:var(--text-0);font-size:13px">🕐 Hourly Sales Pattern</h4>
        <span style="font-size:11px;color:var(--text-3)">${todaySales.length} txns today</span>
      </div>
      ${(() => {
        // Build 24-hour revenue buckets from today's sales
        const hourBuckets = Array(24).fill(0);
        todaySales.forEach(s => {
          const t = s.time || '';
          const hr = parseInt(t.slice(0,2));
          if (!isNaN(hr) && hr >= 0 && hr < 24) hourBuckets[hr] += (s.amount || 0);
        });
        const maxVal = Math.max(...hourBuckets, 1);
        const barCols = hourBuckets.map((v, i) => {
          const pct = Math.round((v / maxVal) * 100);
          const isNow = i === h;
          const isPeak = v === maxVal && v > 0;
          const bg = isNow ? 'var(--accent-light)' : isPeak ? 'var(--green)' : 'var(--bg-3)';
          return `<div style="display:flex;flex-direction:column;align-items:center;flex:1;min-width:0;gap:2px">
            <div style="width:100%;height:50px;display:flex;align-items:flex-end">
              <div style="width:100%;height:${Math.max(pct,2)}%;background:${bg};border-radius:3px 3px 0 0;transition:height 0.3s" title="${v>0?cur(v):''} at ${String(i).padStart(2,'0')}:00"></div>
            </div>
            <div style="font-size:9px;color:${isNow?'var(--accent-light)':'var(--text-3)'};font-weight:${isNow?'700':'400'}">${i%4===0?String(i).padStart(2,'0'):''}</div>
          </div>`;
        }).join('');
        const peakHr = hourBuckets.indexOf(maxVal);
        const peakVal = hourBuckets[peakHr];
        return `<div style="display:flex;gap:1px;align-items:flex-end;margin-bottom:4px">${barCols}</div>
          ${peakVal > 0 ? `<div style="font-size:11px;color:var(--text-3);margin-top:4px">Peak hour: <span style="color:var(--green);font-weight:700">${String(peakHr).padStart(2,'0')}:00–${String(peakHr+1).padStart(2,'0')}:00</span> · <span class="mono">${cur(peakVal)}</span></div>` : '<div style="font-size:11px;color:var(--text-3)">No sales recorded today yet</div>'}`;
      })()}
    </div>

    <div class="card card-pad">
      <div class="flex-between mb-16">
        <h4 class="fw-700" style="color:var(--text-0);font-size:13px">🧑‍🔧 Employee Status</h4>
        <span style="font-size:11px;color:var(--text-3)">${D.employees.filter(e=>e.status!=='inactive').length} active staff</span>
      </div>
      ${(() => {
        // Check for active employee session (same tab or cross-tab via localStorage)
        let activeSessions = [];
        try {
          const raw = localStorage.getItem('fb_emp_session');
          if (raw) {
            const s = verifyData(raw);
            if (s && s.active && s.user) {
              const sales = (s.sales || []).length;
              const opens = Object.keys(s.openReadings || {}).length;
              const closes = Object.keys(s.closeReadings || {}).length;
              const totalNozzles = (() => {
                const emp = D.employees.find(e => e.id === s.user.id);
                return emp ? 1 : 0; // rough check
              })();
              activeSessions.push({ ...s.user, sales, opens, closes, page: s.page || 'readings' });
            }
          }
        } catch(e) {}
        if (activeSessions.length === 0) {
          return '<div style="text-align:center;padding:16px 0;color:var(--text-3);font-size:12px">No employee sessions active right now</div>';
        }
        return activeSessions.map(u => {
          const emp = D.employees.find(e => e.id === u.id);
          const shift = emp?.shift || '—';
          const pageLabels = {readings:'Taking Readings',sales:'Recording Sales',overview:'Overview',dip:'Dip Reading',expense:'Logging Expense',history:'Viewing History',complete:'Shift Complete'};
          const pageLabel = pageLabels[u.page] || u.page;
          const statusColor = u.page === 'complete' ? 'var(--green)' : 'var(--accent-light)';
          const ini = sanitize(u.name||'').charAt(0).toUpperCase();
          return '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px 0;border-bottom:1px solid var(--border-light)">'
            + '<div style="display:flex;align-items:center;gap:10px">'
            + '<div style="width:32px;height:32px;border-radius:50%;background:rgba(34,197,94,0.12);border:2px solid rgba(34,197,94,0.3);display:grid;place-items:center;font-size:13px;font-weight:800;color:var(--green)">' + ini + '</div>'
            + '<div>'
            + '<div class="fw-700" style="color:var(--text-0);font-size:13px">' + sanitize(u.name||'') + ' <span style="font-size:10px;color:var(--text-3);font-weight:500">' + sanitize(u.role||'') + '</span></div>'
            + '<div style="font-size:11px;color:var(--text-3)">Shift: ' + sanitize(shift) + ' &nbsp;·&nbsp; <span style="color:' + statusColor + ';font-weight:600">' + pageLabel + '</span></div>'
            + '</div></div>'
            + '<div style="text-align:right;display:flex;gap:6px">'
            + badge(u.opens + ' readings', 'badge-blue')
            + badge(u.sales + ' sales', 'badge-green')
            + '</div></div>';
        }).join('');
      })()}
    </div>`;
}

// ── TANKS & INVENTORY ────────────────────────────────────────
function renderTanks(D) {
  const tanksHtml = [...D.tanks].sort((a, b) => {
    const ai = parseInt(a.id) || 0, bi = parseInt(b.id) || 0;
    return ai - bi; // ascending: Tank 1 first
  }).map(t => {
    const fuel = getFuel(t.fuelType);
    const pct = t.capacity > 0 ? Math.min(100, (t.current / t.capacity) * 100) : 0;
    const barColor = pct < 20 ? '#ef4444' : pct < 40 ? '#f97316' : fuel.color;
    const pctLabel = pct < 20 ? '⚠️ LOW' : pct < 40 ? '⚡ MED' : '✅ OK';
    const pctBg = pct < 20 ? 'rgba(239,68,68,0.12)' : pct < 40 ? 'rgba(249,115,22,0.1)' : 'rgba(34,197,94,0.1)';
    const pctColor = pct < 20 ? 'var(--red)' : pct < 40 ? '#f97316' : 'var(--green)';
    const dipSource = t.lastDip ? `Last dip: ${t.lastDip}` : 'No dip recorded';
    return `<div class="card card-pad" style="border-top:3px solid ${fuel.color}">
      <!-- Tank header -->
      <div class="flex-between mb-10">
        <div>
          <div class="fw-800" style="color:var(--text-0);font-size:15px">Tank ${t.id}
            <span style="font-size:14px;font-weight:800;color:${fuel.color};background:${fuel.color}22;padding:3px 10px;border-radius:5px;margin-left:8px">${fuel.short}</span>
          </div>
          <div style="font-size:10px;color:var(--text-3);margin-top:2px">${dipSource}</div>
        </div>
        <span style="font-size:10px;font-weight:800;padding:3px 9px;border-radius:5px;background:${pctBg};color:${pctColor}">${pctLabel} ${Math.round(pct)}%</span>
      </div>

      <!-- Main qty — this IS the dip reading / available fuel -->
      <div style="background:${fuel.color}0f;border:1px solid ${fuel.color}33;border-radius:10px;padding:14px 16px;margin-bottom:12px;text-align:center">
        <div style="font-size:11px;font-weight:700;color:${fuel.color};text-transform:uppercase;letter-spacing:0.8px;margin-bottom:4px">⛽ Available to Dispense</div>
        <div class="mono fw-900" style="font-size:32px;color:var(--text-0);line-height:1">${fmt(t.current)}<span style="font-size:14px;color:var(--text-3);font-weight:400"> L</span></div>
        <div style="font-size:11px;color:var(--text-3);margin-top:4px">Tank capacity: ${fmt(t.capacity)} L &nbsp;·&nbsp; Empty: ${fmt(Math.max(0, t.capacity - t.current))} L</div>
      </div>

      <!-- Fill bar -->
      ${progressBar(pct, barColor, 'progress-lg')}

      <!-- Action buttons -->
      <div style="display:flex;gap:6px;margin-top:12px">
        <button class="btn btn-accent btn-sm" style="flex:2" onclick="openDipModal(${t.id})">📏 Record Dip</button>
        <button class="btn btn-ghost btn-sm" style="flex:1" onclick="openEditTankModal(${t.id})">✏️</button>
        <button class="btn btn-ghost btn-sm" style="color:var(--red)" onclick="confirmDeleteTank(${t.id})">🗑</button>
      </div>
    </div>`;
  }).join('');

  const dipRows = D.dipReadings.map(r => {
    const diff = r.reading - r.calculated;
    const diffHtml = diff === 0 ? `<span style="color:var(--green)" class="fw-700">OK</span>` :
      `<span style="color:${diff < 0 ? 'var(--red)' : 'var(--orange)'}" class="fw-700">${diff > 0 ? '+' : ''}${fmt(diff)} L</span>`;
    const dipTank = D.tanks.find(t => parseInt(t.id) === parseInt(r.tankId));
    const dipFuel = dipTank ? getFuel(dipTank.fuelType) : null;
    const tankLabel = dipTank ? `Tank ${r.tankId} <span style="font-size:10px;color:${dipFuel?.color||'var(--text-3)'}">${dipFuel?.short||''}</span>` : `Tank ${r.tankId}`;
    return `<tr><td>${r.date}</td><td class="mono">${r.time}</td><td>${tankLabel}</td><td class="r mono fw-700" style="color:var(--accent-light)">${fmt(r.reading)}</td><td class="r mono" style="color:var(--text-3)">${fmt(r.calculated)}</td><td class="r">${diffHtml}</td></tr>`;
  }).join('');

  const purchaseRows = D.fuelPurchases.map(r => {
    const ft = r.fuelType || r.fuel_type || '';
    const fuel = getFuel(ft);
    const total = r.total || r.amount || (r.liters * r.rate) || 0;
    return `<tr><td>${r.date}</td><td style="color:${fuel.color}" class="fw-600">${fuel.name}</td><td class="r mono">${fmt(r.liters)}</td><td class="r mono">${cur(r.rate)}</td><td class="r mono fw-700">${cur(total)}</td><td class="mono" style="font-size:12px">${r.invoice||'—'}</td><td class="mono" style="font-size:11px;color:var(--text-3)">${r.supplier||''}</td></tr>`;
  }).join('');

  return `
    <div class="page-hdr">
      <h3>🛢️ Tank & Inventory</h3>
      <div class="flex" style="gap:8px">
        <button class="btn btn-ghost btn-sm" onclick="openAddTankModal()">+ Add Tank</button>
        <button class="btn btn-accent" onclick="openDipModal()">+ Record Dip</button>
        <button class="btn btn-ghost" onclick="openPurchaseModal()">+ Fuel Purchase</button>
      </div>
    </div>
    <div class="g g-auto gap-16 mb-24">${tanksHtml}</div>
    <div class="card mb-24">
      <div class="card-head"><h4>📏 Recent Dip Readings</h4><button class="btn btn-ghost btn-sm" onclick="exportDipCSV()">↓ Export</button></div>
      <div class="card-body"><div class="tbl-wrap"><table><thead><tr><th>Date</th><th>Time</th><th>Tank</th><th class="r">Available Qty (L)</th><th class="r">Prev Book Stock (L)</th><th class="r">Variance</th></tr></thead><tbody>${dipRows}</tbody></table></div></div>
    </div>
    <div class="card">
      <div class="card-head"><h4>🚛 Fuel Purchases</h4></div>
      <div class="card-body"><div class="tbl-wrap"><table><thead><tr><th>Date</th><th>Fuel</th><th class="r">Qty (L)</th><th class="r">Rate/L</th><th class="r">Total</th><th>Invoice</th><th>Supplier</th></tr></thead><tbody>${purchaseRows}</tbody></table></div></div>
    </div>`;
}

// ── PUMPS & METERS ───────────────────────────────────────────
function renderPumps(D) {
  const pumpCards = [...D.pumps].sort((a, b) => {
    const ai = parseInt(a.id) || 0, bi = parseInt(b.id) || 0;
    return ai - bi; // ascending: Pump 1 first
  }).map(p => {
    const fuel = getFuel(p.fuelType);
    const _nOpen = (p.openReading || 0);
    const _nCur  = (p.currentReading || 0);
    const meterSoldAgg = Math.max(0, _nCur - _nOpen);
    // Use today's sales-based revenue when opening reading is 0 (no shift data yet)
    const todayIso_card = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
    const pumpTodaySales = _nOpen === 0 && _nCur === 0 ? D.sales.filter(s => String(s.pump) === String(p.id) && (s.date||'').slice(0,10) === todayIso_card) : [];
    const salesRevAgg = pumpTodaySales.reduce((a,s) => a + (s.amount||0), 0);
    const salesSoldAgg = pumpTodaySales.reduce((a,s) => a + (s.liters||0), 0);
    const sold = meterSoldAgg > 0 ? meterSoldAgg : salesSoldAgg;
    const rev  = meterSoldAgg > 0 ? meterSoldAgg * (D.prices[p.fuelType] || 0) : salesRevAgg;

    // Per-nozzle fuel display
    const nozzleLabels = p.nozzleLabels || (p.nozzles === 1 ? ['A'] : p.nozzles === 2 ? ['A','B'] : ['A','B','C'].slice(0, p.nozzles));
    const nozzleFuels  = p.nozzleFuels  || {};  // { 'A': 'petrol', 'B': 'diesel' }
    const nozzlePills  = nozzleLabels.map(n => {
      const nf   = getFuel(nozzleFuels[n] || p.fuelType);
      return `<span style="background:${nf.color}18;border:1px solid ${nf.color}44;color:${nf.color};padding:2px 8px;border-radius:4px;font-size:10px;font-weight:800">N${n}: ${nf.short}</span>`;
    }).join('');

    // Per-nozzle breakdown for mixed-fuel pumps
    const allSameFuel = nozzleLabels.every(n => (nozzleFuels[n]||p.fuelType) === (nozzleFuels[nozzleLabels[0]]||p.fuelType));
    const todayIso_pumps = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
    const nozzleBreakdown = nozzleLabels.length <= 1 ? '' : nozzleLabels.map(n => {
      const nft  = getFuel(nozzleFuels[n] || p.fuelType);
      const nOpen  = (p.nozzleOpen || {})[n] ?? 0;
      const nClose = (p.nozzleReadings || {})[n] ?? 0;
      const meterSold = Math.max(0, nClose - nOpen);
      // Fallback to today's sales when no meter readings exist
      const nozzleSales = D.sales.filter(s => String(s.pump) === String(p.id) && (s.nozzle === n || s.nozzle === String(n)) && (s.date||'').slice(0,10) === todayIso_pumps);
      const salesSold = nozzleSales.reduce((a,s) => a + (s.liters||0), 0);
      const salesRev  = nozzleSales.reduce((a,s) => a + (s.amount||0), 0);
      const nSold = meterSold > 0 ? meterSold : salesSold;
      const nRev  = meterSold > 0 ? meterSold * (D.prices[nozzleFuels[n] || p.fuelType] || 0) : salesRev;
      const srcTag = meterSold > 0 ? '' : salesSold > 0 ? ' <span style="font-size:9px;color:var(--text-3)">(sales)</span>' : '';
      return `<div style="display:flex;justify-content:space-between;align-items:center;padding:5px 8px;background:${nft.color}0f;border-radius:6px;border:1px solid ${nft.color}22;margin-bottom:4px">
        <span style="font-size:11px;font-weight:700;color:${nft.color}">N${n}: ${nft.short}</span>
        <span class="mono fw-700" style="font-size:12px;color:var(--green)">${fmt(nSold)} L${srcTag}</span>
        <span class="mono" style="font-size:11px;color:var(--text-3)">${cur(nRev)}</span>
      </div>`;
    }).join('');

    return `<div class="card card-pad">
      <div class="flex-between mb-10">
        <div>
          <div class="fw-800" style="color:var(--text-0);font-size:15px">${p.name}</div>
          <div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:5px">${nozzlePills}</div>
        </div>
        <div style="display:flex;align-items:flex-start;gap:6px">
          ${badge(p.status.toUpperCase(), p.status === 'active' ? 'badge-green' : 'badge-red')}
          <button onclick="openEditPumpModal(${p.id})" style="background:var(--bg-2);border:1px solid var(--border);color:var(--text-3);border-radius:6px;padding:3px 7px;cursor:pointer;font-size:12px" title="Edit Pump & Nozzles">✏️</button>
        </div>
      </div>
      ${ nozzleLabels.length > 1 ? `<div style="margin-bottom:10px">${nozzleBreakdown}</div>` : `<div class="g" style="grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:10px">
        <div class="dbox"><div class="dbox-label">Opening</div><div class="dbox-value mono" style="font-size:13px">${fmt(p.openReading)}</div></div>
        <div class="dbox"><div class="dbox-label">Current</div><div class="dbox-value mono" style="font-size:13px">${fmt(p.currentReading)}</div></div>
        <div class="dbox"><div class="dbox-label">Sold</div><div class="dbox-value mono" style="font-size:13px;color:var(--green)">${fmt(sold)} L</div></div>
      </div>
      <div class="flex-between mb-10" style="font-size:12px">
        <span style="color:var(--text-3)">Revenue</span>
        <span class="mono fw-700" style="color:var(--text-0)">${cur(rev)}</span>
      </div>`}
      <button class="btn btn-ghost btn-sm btn-block" onclick="openReadingModal(${p.id})">⚙️ Update Reading</button>
    </div>`;
  }).join('');

  const reconRows = D.pumps.flatMap(p => {
    const labels = p.nozzleLabels || (p.nozzles === 1 ? ['A'] : p.nozzles === 2 ? ['A','B'] : ['A','B','C'].slice(0, p.nozzles));
    const nf = p.nozzleFuels || {};
    const nr = p.nozzleReadings || {};
    // If all nozzles have same fuel, keep single row using aggregate readings
    const fuels = labels.map(n => nf[n] || p.fuelType);
    const allSameFuel = fuels.every(f => f === fuels[0]);
    // Always show per-nozzle rows (clearer and more accurate)
    return labels.map((n, i) => {
      const ft   = nf[n] || p.fuelType;
      const fuel = getFuel(ft);
      const open  = nr[n] !== undefined ? (nr[n] - (p.nozzleOpen?.[n] || 0)) >= 0 ? (p.nozzleOpen?.[n] || 0) : 0 : (p.openReading || 0);
      const close = nr[n] !== undefined ? nr[n] : (p.currentReading || 0);
      // Use sales data as source for per-nozzle sold when nozzleReadings available
      const nozzleSales = D.sales.filter(s => String(s.pump) === String(p.id) && (s.nozzle === n || s.nozzle === String(n)));
      const todayIso = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
      const todayNozzleSales = nozzleSales.filter(s => (s.date||'').slice(0,10) === todayIso);
      const soldL = todayNozzleSales.reduce((a,s) => a + (s.liters||0), 0);
      const soldR = todayNozzleSales.reduce((a,s) => a + (s.amount||0), 0);
      // Fall back to nozzleReading diff if we have it
      const openR = p.nozzleOpen?.[n] ?? 0;
      const closeR = nr[n] ?? 0;
      const meterSold = closeR > openR ? closeR - openR : soldL;
      const meterRev  = meterSold * ((D.prices || {})[ft] || 0);
      const rowspan = i === 0 ? ` rowspan="${labels.length}" style="vertical-align:middle"` : 'style="display:none"';
      return `<tr>
        ${i === 0 ? `<td class="fw-600" rowspan="${labels.length}" style="vertical-align:middle">${p.name}</td>` : ''}
        <td style="color:${fuel.color};padding-left:${i>0?'28':''}px" class="fw-600">N${n}: ${fuel.short}</td>
        <td class="r mono">${fmt(open)}</td><td class="r mono">${fmt(close)}</td>
        <td class="r mono fw-700" style="color:var(--green)">${fmt(meterSold)}</td>
        <td class="r mono fw-700">${cur(meterRev)}</td>
      </tr>`;
    });
  }).join('');

  return `
    <div class="page-hdr"><h3>⛽ Pumps & Meters</h3><button class="btn btn-accent btn-sm" onclick="openAddPumpModal()">+ Add Pump</button></div>
    ${pumpCards.trim() ? `<div class="g g-auto gap-16 mb-24">${pumpCards}</div>` : `
      <div style="text-align:center;padding:48px 20px;color:var(--text-3)">
        <div style="font-size:48px;margin-bottom:12px;opacity:0.4">⛽</div>
        <div class="fw-700" style="font-size:16px;color:var(--text-2);margin-bottom:6px">No pumps added yet</div>
        <div style="font-size:13px;margin-bottom:20px">Add your first pump to start recording meter readings</div>
        <button class="btn btn-accent" onclick="openAddPumpModal()">+ Add Your First Pump</button>
      </div>`}
    <div class="card">
      <div class="card-head"><h4>📋 Pump Reconciliation</h4><button class="btn btn-ghost btn-sm" onclick="exportPumpCSV()">↓ Export</button></div>
      <div class="card-body"><div class="tbl-wrap"><table><thead><tr><th>Pump</th><th>Fuel</th><th class="r">Opening</th><th class="r">Current</th><th class="r">Sold (L)</th><th class="r">Revenue</th></tr></thead><tbody>${reconRows}</tbody></table></div></div>
    </div>

    ${(() => {
      // ── Nozzle Meter Log ─────────────────────────────────────────────────
      const log = window._nozzleMeterLog || [];
      const today = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
      const logDate = window._nmlDate || today;
      const logRows = log.filter(e => e.date === logDate);

      const totalVariance = logRows.reduce((a, e) => a + Math.abs(e.variance||0), 0);
      const flaggedCount  = logRows.filter(e => e.flagged).length;

      const nozzleSelOpts = D.pumps.flatMap(p => {
        const labels = p.nozzleLabels || (p.nozzles===1?['A']:p.nozzles===2?['A','B']:['A','B','C'].slice(0,p.nozzles));
        return labels.map(n => `<option value="${n}" data-pump="${p.id}">${p.name} · N${n}</option>`);
      }).join('');

      const logTableRows = logRows.length > 0
        ? logRows.map(e => {
            const fi = getFuel(e.fuelType);
            const varColor = e.flagged ? 'var(--red)' : Math.abs(e.variance||0) > 0 ? 'var(--orange)' : 'var(--green)';
            const varBg    = e.flagged ? 'rgba(239,68,68,0.07)' : '';
            const srcBadge = e.source === 'employee' ? badge('Auto','badge-blue') : badge('Manual','badge-accent');
            return `<tr style="background:${varBg}">
              <td class="fw-600">${e.date}</td>
              <td style="font-size:11px">${sanitize(e.shift||'—')}</td>
              <td style="font-size:11px">${sanitize(e.employee||'—')}</td>
              <td class="fw-700">${sanitize(e.pumpName||'')} <span style="font-size:10px;color:${fi.color};font-weight:700">N${e.nozzle} · ${fi.short}</span></td>
              <td class="r mono">${fmt(e.openReading||0)}</td>
              <td class="r mono">${fmt(e.closeReading||0)}</td>
              <td class="r mono fw-700" style="color:var(--accent-light)">${fmt(e.meterSold||0)}</td>
              <td class="r mono" style="color:var(--text-2)">${fmt(e.systemSold||0)}</td>
              <td class="r mono fw-800" style="color:${varColor}">${e.variance > 0 ? '+' : ''}${fmt(e.variance||0)} L ${e.flagged ? '🚨' : ''}</td>
              <td>${srcBadge}</td>
            </tr>`;
          }).join('')
        : `<tr><td colspan="10" style="text-align:center;color:var(--text-3);padding:20px">No meter readings for ${logDate}</td></tr>`;

      return `<div class="card mt-16">
        <div class="card-head">
          <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap">
            <h4>📟 Nozzle Meter Log</h4>
            ${flaggedCount > 0 ? `<span style="font-size:11px;font-weight:700;color:var(--red);background:rgba(239,68,68,0.1);padding:2px 8px;border-radius:20px">🚨 ${flaggedCount} variance${flaggedCount>1?'s':''} flagged</span>` : ''}
            <input type="date" value="${logDate}" max="${today}" onchange="window._nmlDate=this.value;renderPage()"
              style="font-size:12px;background:var(--bg-0);border:1px solid var(--border);border-radius:6px;padding:3px 8px;color:var(--text-1);cursor:pointer" />
          </div>
          <button class="btn btn-accent btn-sm" onclick="openNozzleMeterModal(${D.pumps[0]?.id||1},'A')">+ Add Reading</button>
        </div>
        ${logRows.length > 0 ? `
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px;padding:12px 16px;border-bottom:1px solid var(--border-light)">
          <div class="dbox text-center" style="padding:10px"><div class="mono fw-800" style="color:var(--accent-light)">${logRows.length}</div><div style="font-size:10px;color:var(--text-3)">Nozzle Readings</div></div>
          <div class="dbox text-center" style="padding:10px"><div class="mono fw-800" style="color:var(--green)">${fmt(logRows.reduce((a,e)=>a+(e.meterSold||0),0))} L</div><div style="font-size:10px;color:var(--text-3)">Meter Total</div></div>
          <div class="dbox text-center" style="padding:10px"><div class="mono fw-800" style="color:var(--text-2)">${fmt(logRows.reduce((a,e)=>a+(e.systemSold||0),0))} L</div><div style="font-size:10px;color:var(--text-3)">System Total</div></div>
          <div class="dbox text-center" style="padding:10px"><div class="mono fw-800" style="color:${totalVariance>=0.5?'var(--red)':'var(--green)'}">${totalVariance>=0.5?'🚨 ':'✅ '}${fmt(totalVariance)} L</div><div style="font-size:10px;color:var(--text-3)">Total Variance</div></div>
          <div class="dbox text-center" style="padding:10px"><div class="mono fw-800" style="color:${flaggedCount>0?'var(--red)':'var(--green)'}">${flaggedCount}</div><div style="font-size:10px;color:var(--text-3)">Flagged</div></div>
        </div>` : ''}
        <div class="card-body"><div class="tbl-wrap"><table>
          <thead><tr><th>Date</th><th>Shift</th><th>Employee</th><th>Pump · Nozzle</th><th class="r">Open</th><th class="r">Close</th><th class="r">Meter L</th><th class="r">System L</th><th class="r">Variance</th><th>Source</th></tr></thead>
          <tbody>${logTableRows}</tbody>
        </table></div></div>
      </div>`;
    })()}`;
}

// ── SALES ────────────────────────────────────────────────────
function renderSales(D, filter = 'all') {
  // FIX 31: use IST today()
  const todayIso = (typeof window.today === 'function') ? window.today() : new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10);

  // ── Date navigation state ──────────────────────────────────
  if (!APP.salesDate) APP.salesDate = todayIso;
  const selDate = APP.salesDate;
  const isToday = selDate === todayIso;

  // Prev / Next date helpers
  const dateOffset = (iso, days) => {
    const d = new Date(iso); d.setDate(d.getDate() + days);
    return d.toISOString().slice(0, 10);
  };
  const fmtDateLabel = iso => {
    if (iso === todayIso) return 'Today';
    const yesterday = dateOffset(todayIso, -1);
    if (iso === yesterday) return 'Yesterday';
    return new Date(iso).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
  };

  // ── Employee filter state ──────────────────────────────────
  if (!APP.salesEmpFilter) APP.salesEmpFilter = 'all';

  // All sales for selected date, fuel-filtered
  const dateFiltered = D.sales.filter(s => (s.date || '').slice(0, 10) === selDate);
  const fuelFiltered = filter === 'all' ? dateFiltered : dateFiltered.filter(s => s.fuelType === filter);

  // Unique employees who have sales on this date
  const empNames = [...new Set(fuelFiltered.map(s => s.employee || '').filter(Boolean))].sort();

  // Final filtered rows (fuel + employee)
  const filtered = APP.salesEmpFilter === 'all'
    ? fuelFiltered
    : fuelFiltered.filter(s => s.employee === APP.salesEmpFilter);

  // Sort by time
  const sorted = [...filtered].sort((a, b) => (a.time || '').localeCompare(b.time || ''));

  const total   = filtered.reduce((a, s) => a + (s.amount || 0), 0);
  const liters  = filtered.reduce((a, s) => a + (s.liters || 0), 0);

  // ── Fuel type filter chips ─────────────────────────────────
  const fuelChips = [{ id: 'all', name: 'All' }, ...FUEL_TYPES].map(f =>
    `<button class="filter-chip ${APP.salesFilter === f.id ? 'active' : ''}"
      onclick="APP.salesFilter='${f.id}';renderPage()">${f.short || f.name}</button>`
  ).join('');

  // ── Per-employee summary cards ─────────────────────────────
  const empCards = empNames.map(emp => {
    const empSales = fuelFiltered.filter(s => s.employee === emp);
    const empAmt   = empSales.reduce((a, s) => a + (s.amount || 0), 0);
    const empLtrs  = empSales.reduce((a, s) => a + (s.liters || 0), 0);
    const isActive = APP.salesEmpFilter === emp;
    const empData  = D.employees?.find(e => e.name === emp);
    const initials = emp.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
    const avatarBg = empData ? empColor(empData) : '#6b7280';
    return `<div onclick="APP.salesEmpFilter='${isActive ? 'all' : emp}';renderPage()"
      style="cursor:pointer;padding:12px 14px;background:${isActive ? 'rgba(212,148,15,0.12)' : 'var(--bg-1)'};
      border:2px solid ${isActive ? 'var(--accent)' : 'var(--border-light)'};border-radius:10px;
      display:flex;align-items:center;gap:10px;transition:all 0.15s;min-width:160px"
      onmouseover="this.style.borderColor='var(--accent)'"
      onmouseout="this.style.borderColor='${isActive ? 'var(--accent)' : 'var(--border-light)'}'">
      <div style="width:32px;height:32px;border-radius:8px;background:${avatarBg};display:grid;place-items:center;
        color:#fff;font-size:11px;font-weight:900;flex-shrink:0">${initials}</div>
      <div>
        <div style="font-size:12px;font-weight:800;color:var(--text-0)">${sanitize(emp)}</div>
        <div style="font-size:11px;color:var(--text-3)">${empSales.length} sales · <span style="color:var(--green);font-weight:700">${cur(empAmt)}</span></div>
        <div style="font-size:10px;color:var(--text-3)">${empLtrs.toFixed(1)} L</div>
      </div>
      ${isActive ? '<span style="margin-left:auto;color:var(--accent);font-size:14px">✓</span>' : ''}
    </div>`;
  }).join('');

  // ── Table rows ─────────────────────────────────────────────
  const rows = sorted.map(s => {
    const fuel = getFuel(s.fuelType);
    const empName = s.employee ? sanitize(s.employee) : '—';
    return `<tr>
      <td class="mono" style="font-size:11px;white-space:nowrap">${s.time || '—'}</td>
      <td class="mono fw-600">${sanitize(s.vehicle || '—')}</td>
      <td style="color:${fuel.color}" class="fw-600">${fuel.short}</td>
      <td class="r mono">${fmt(s.liters)}</td>
      <td class="r mono fw-700">${cur(s.amount)}</td>
      <td class="mono" style="font-size:11px">${s.pump ? 'P'+s.pump : '—'}</td>
      <td>
        <div style="display:flex;align-items:center;gap:5px">
          ${(() => { const e = D.employees?.find(x => x.name === s.employee); const init = s.employee ? s.employee.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase() : '?'; const bg = e ? empColor(e) : '#6b7280'; return s.employee ? `<span style="width:20px;height:20px;border-radius:4px;background:${bg};display:grid;place-items:center;color:#fff;font-size:8px;font-weight:900">${init}</span>` : ''; })()}
          <span style="font-size:11px;font-weight:600;color:var(--text-1)">${empName}</span>
        </div>
      </td>
      <td>${badgeColor(s.mode, payColors[s.mode])}</td>
      <td style="font-size:11px;color:var(--text-2)">${sanitize(s.customer || '') || '—'}</td>
    </tr>`;
  }).join('');

  const emptyMsg = sorted.length === 0
    ? `<tr><td colspan="9" style="text-align:center;padding:32px;color:var(--text-3)">
        ${dateFiltered.length === 0 ? '📭 No sales recorded for this date' : '🔍 No sales match the selected filters'}
      </td></tr>`
    : '';

  return `
    <div class="page-hdr">
      <h3>💰 Sales${(APP.data?.dayLocks||{})[selDate] ? ' <span style="font-size:12px;background:rgba(34,197,94,0.15);color:var(--green);padding:2px 8px;border-radius:4px;font-weight:700;vertical-align:middle">🔒 LOCKED</span>' : ''}</h3>
      <div class="flex" style="gap:8px;flex-wrap:wrap;align-items:center">
        <div class="filters">${fuelChips}</div>
        <button class="btn btn-accent" onclick="openSaleModal()">+ New Sale</button>
      </div>
    </div>

    <!-- Date navigator -->
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:16px;flex-wrap:wrap">
      <button class="btn btn-ghost btn-sm" onclick="APP.salesDate='${dateOffset(selDate,-1)}';APP.salesEmpFilter='all';renderPage()">◀ Prev</button>
      <div style="display:flex;align-items:center;gap:8px;background:var(--bg-1);border:1px solid var(--border);border-radius:8px;padding:4px 10px">
        <span style="font-size:13px;font-weight:700;color:var(--text-0)">${fmtDateLabel(selDate)}</span>
        <input type="date" value="${selDate}" max="${todayIso}"
          onchange="APP.salesDate=this.value;APP.salesEmpFilter='all';renderPage()"
          style="opacity:0;position:absolute;width:120px;cursor:pointer" title="Pick a date" />
        <span style="font-size:11px;color:var(--text-3);font-family:var(--mono)">${selDate}</span>
        <span style="font-size:14px;cursor:pointer" title="Pick a date">📅</span>
      </div>
      ${!isToday ? `<button class="btn btn-ghost btn-sm" onclick="APP.salesDate='${todayIso}';APP.salesEmpFilter='all';renderPage()">Today</button>` : ''}
      ${selDate < todayIso ? `<button class="btn btn-ghost btn-sm" onclick="APP.salesDate='${dateOffset(selDate,1)}';APP.salesEmpFilter='all';renderPage()">Next ▶</button>` : ''}
      <span style="font-size:12px;color:var(--text-3)">${dateFiltered.length} sale${dateFiltered.length!==1?'s':''} on this day</span>
    </div>

    <!-- Employee summary cards -->
    ${empNames.length > 0 ? `
    <div style="margin-bottom:16px">
      <div style="font-size:11px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px">
        Employee Summary ${APP.salesEmpFilter !== 'all' ? `— <span style="color:var(--accent-light)">Filtered: ${sanitize(APP.salesEmpFilter)}</span> <button class="btn btn-ghost btn-sm" style="font-size:10px;padding:1px 6px" onclick="APP.salesEmpFilter='all';renderPage()">✕ Clear</button>` : ''}
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:10px">${empCards}</div>
    </div>` : ''}

    <!-- Sales table -->
    <div class="card">
      <div class="card-head">
        <div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap">
          <span style="color:var(--text-3);font-size:13px">${sorted.length} transaction${sorted.length!==1?'s':''}</span>
          <span style="font-size:12px;color:var(--text-2)">· <span class="mono">${liters.toFixed(1)} L</span></span>
        </div>
        <span class="mono fw-700" style="color:var(--green);font-size:16px">Total: ${cur(total)}</span>
      </div>
      <div class="card-body">
        <div class="tbl-wrap">
          <table>
            <thead>
              <tr>
                <th>Time</th><th>Vehicle</th><th>Fuel</th>
                <th class="r">Liters</th><th class="r">Amount</th>
                <th>Pump</th><th>Employee</th><th>Payment</th><th>Customer</th>
              </tr>
            </thead>
            <tbody>${rows}${emptyMsg}</tbody>
          </table>
        </div>
      </div>
    </div>

    <div class="flex" style="gap:8px;margin-top:16px">
      <button class="btn btn-ghost" onclick="exportSalesCSV()">↓ Export CSV</button>
      <button class="btn btn-ghost" onclick="shareSalesSummary()">📤 Share Summary</button>
    </div>`;
}

// ── CREDIT MANAGEMENT ────────────────────────────────────────
function renderCredit(D) {
  const totalOut = D.creditCustomers.reduce((a, c) => a + c.outstanding, 0);
  const totalLimit = D.creditCustomers.reduce((a, c) => a + c.limit, 0);

  const cards = D.creditCustomers.map(c => {
    const pct = c.limit > 0 ? Math.min(100, (c.outstanding / c.limit) * 100) : 0;
    const barColor = pct > 80 ? '#ef4444' : pct > 60 ? '#f97316' : '#22c55e';
    return `<div class="card card-pad">
      <div class="flex-between mb-14" style="align-items:flex-start">
        <div><div class="fw-800" style="color:var(--text-0);font-size:16px">${sanitize(c.name)}</div>
          ${badge(c.type, c.type === 'Fleet' ? 'badge-blue' : 'badge-purple')}
          ${c.loyaltyEnrolled
            ? `<span style="margin-left:6px;font-size:11px;font-weight:700;color:var(--accent-light);background:rgba(212,148,15,0.1);border:1px solid rgba(212,148,15,0.3);padding:1px 7px;border-radius:99px">⭐ Loyalty${(c.loyaltyPoints||0)>0?' · '+(c.loyaltyPoints||0).toLocaleString('en-IN')+' pts':''}</span>`
            : `<span style="margin-left:6px;font-size:11px;color:var(--text-3);background:var(--bg-2);border:1px solid var(--border);padding:1px 7px;border-radius:99px">No loyalty</span>`}
        </div>
        <div class="text-right"><div class="mono fw-800" style="color:${pct > 80 ? 'var(--red)' : 'var(--orange)'};font-size:20px">${cur(c.outstanding)}</div>
          <div style="font-size:11px;color:var(--text-3)">of ${cur(c.limit)}</div></div>
      </div>
      <div class="progress progress-sm mb-12"><div class="progress-bar" style="width:${pct}%;background:${barColor}"></div></div>
      <div class="flex-between" style="font-size:12px;color:var(--text-3)"><span>Used: ${pct.toFixed(0)}%</span><span>Free: ${cur(c.limit - c.outstanding)}</span></div>
      <div class="mt-8" style="font-size:12px;color:var(--text-3)">Last paid: <span style="color:var(--text-1)" class="mono">${c.lastPayment}</span></div>
      <div class="flex mt-14" style="gap:8px">
        <button class="btn btn-green-ghost btn-sm" style="flex:1" onclick="openPaymentModal(${c.id})">💵 Record Payment</button>
        <button class="btn btn-blue-ghost btn-sm" style="flex:1" onclick="openUPIModal('${sanitize(c.name)}', ${c.outstanding})">📱 UPI Request</button>
        ${c.phone ? `<button class="btn btn-ghost btn-sm" style="color:#25d366" onclick="wa_sendCreditReminder(APP.data.creditCustomers.find(x=>x.id===${c.id}))" title="WhatsApp reminder">💬</button>` : ''}
        ${(c.loyaltyPoints||0) >= 100 ? `<button class="btn btn-ghost btn-sm" style="color:var(--accent-light)" onclick="openLoyaltyRedeemModal(${c.id})" title="Redeem points">⭐</button>` : ''}
        <button class="btn btn-ghost btn-sm" onclick="openLoyaltyHistoryModal(${c.id})" title="Loyalty history">🎁</button>
        <button class="btn btn-ghost btn-sm" onclick="openEditCreditModal(${c.id})">✏️ Edit</button>
        <button class="btn btn-ghost btn-sm" style="color:var(--red)" onclick="confirmDeleteCredit(${c.id})">🗑</button>
      </div>
      ${(() => {
        const txns = (APP.data.creditTransactions || []).filter(t => String(t.customerId) === String(c.id)).slice(0, 4);
        if (!txns.length) return '';
        return `<div style="margin-top:10px;border-top:1px solid var(--border-light);padding-top:8px">
          <div style="font-size:10px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px">Recent Payments</div>
          ${txns.map(t => `<div style="display:flex;justify-content:space-between;padding:3px 0;border-bottom:1px solid var(--border-light);font-size:11px">
            <span style="color:var(--text-2)">${t.date} · <span style="color:var(--text-3)">${sanitize((t.mode||'').toUpperCase())}</span></span>
            <span style="color:var(--green);font-weight:700">+${cur(t.amount)}</span>
          </div>`).join('')}
        </div>`;
      })()}
    </div>`;
  }).join('');

  return `
    <div class="page-hdr"><h3>💳 Credit Management</h3><button class="btn btn-accent" onclick="openCreditCustomerModal()">+ Add Customer</button></div>
    <div class="g g-auto-sm mb-24 gap-16">
      ${statCard('Total Outstanding', cur(totalOut), '', '📋')}
      ${statCard('Credit Limit', cur(totalLimit), '', '🏦')}
      ${statCard('Active Accounts', D.creditCustomers.length, 'fleet & govt', '👥')}
    </div>
    <div class="g g-auto-lg gap-16">${cards}</div>`;
}

// ── STAFF & SHIFTS ───────────────────────────────────────────
function renderStaff(D) {
  // Show fix banner if any shifts have missing times
  const nullShifts = (D.shifts||[]).filter(s => !s.start || !s.end);
  const shiftFixBanner = nullShifts.length > 0
    ? `<div style="display:flex;align-items:center;gap:12px;padding:10px 16px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.3);border-radius:8px;margin-bottom:16px;flex-wrap:wrap">
        <span style="font-size:13px;color:var(--red);font-weight:700">⚠️ ${nullShifts.length} shift${nullShifts.length>1?'s have':' has'} missing start/end times — this crashes Dashboard and Staff pages.</span>
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-left:auto">
          ${nullShifts.map(s=>`<button class="btn btn-ghost btn-sm" style="color:var(--red);border-color:rgba(239,68,68,0.4)" onclick="openEditShiftModal('${s.id}')">Fix: ${sanitize(s.name)}</button>`).join('')}
        </div>
      </div>`
    : '';
  const payroll = D.employees.reduce((a, e) => a + e.salary, 0);
  const totalNozzles = D.pumps.reduce((a, p) => a + (p.nozzleLabels || ['A','B']).length, 0);
  const allocKey = allocShift + '_' + allocDate;
  const shiftAlloc = allocations[allocDate + '_' + allocShift] || {};
  const assignedCount = Object.values(shiftAlloc).filter(v => v && D.employees.some(e => parseInt(e.id) === parseInt(v))).length;

  // ── Filter employees by Roster for the selected date+shift ──────────────
  // Roster key format: "YYYY-MM-DD_ShiftName"
  const rosterKey = allocDate + '_' + allocShift;
  const rosteredIds = (window._rosterData && window._rosterData[rosterKey]) || [];
  // If roster has assignments for this date+shift, show only those employees
  // Otherwise fall back to employees whose shift field includes this shift
  const shiftEmps = rosteredIds.length > 0
    ? D.employees.filter(e => rosteredIds.includes(String(e.id)))
    : D.employees.filter(e => { const sh=(e.shift||'').trim(); return !sh || sh.split(',').map(s=>s.trim()).includes(allocShift); });
  const rosterFiltered = rosteredIds.length > 0;

  const empOptions = shiftEmps.map(e => `<option value="${e.id}">${e.name} (${e.role})</option>`).join('')
    || `<option value="" disabled>No employees rostered for this shift</option>`;

  // Shift sort helper: Morning → Noon/Afternoon → Evening → Night (ascending time-of-day order)
  const SHIFT_ORDER = ['morning','noon','afternoon','evening','night'];
  function shiftSortKey(s) {
    const n = (s.name || '').toLowerCase();
    const idx = SHIFT_ORDER.findIndex(k => n.includes(k));
    return idx >= 0 ? idx : 99;
  }
  const sortedShifts = [...D.shifts].sort((a, b) => shiftSortKey(a) - shiftSortKey(b));

  // Shift tabs
  const shiftTabs = sortedShifts.map(s =>
    `<button class="shift-tab ${allocShift === s.name ? 'active' : ''}" onclick="allocShift='${s.name}'; renderPage()">${s.name} <span style="font-size:10px;opacity:0.6;margin-left:3px">${s.start}–${s.end}</span></button>`
  ).join('');
  // Date navigation for allocation
  const todayIsoAlloc = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();

  // ── Week range for week view ──────────────────────────────────────────────
  // anchorDate drives the week — default to current week's Monday
  if (!window.allocWeekAnchor) {
    const d = new Date(); const day = d.getDay(); const diff = (day === 0 ? -6 : 1 - day);
    d.setDate(d.getDate() + diff); window.allocWeekAnchor = d.toISOString().slice(0,10);
  }
  const weekStart = new Date(window.allocWeekAnchor);
  const weekDays = Array.from({length:7}, (_,i) => {
    const d = new Date(weekStart); d.setDate(d.getDate() + i);
    return d.toISOString().slice(0,10);
  });
  const prevWeekAnchor = new Date(weekStart); prevWeekAnchor.setDate(prevWeekAnchor.getDate()-7);
  const nextWeekAnchor = new Date(weekStart); nextWeekAnchor.setDate(nextWeekAnchor.getDate()+7);
  const pvW = prevWeekAnchor.toISOString().slice(0,10);
  const nxW = nextWeekAnchor.toISOString().slice(0,10);
  const weekLabel = weekStart.toLocaleDateString('en-IN',{day:'numeric',month:'short'}) + ' – ' +
    new Date(weekDays[6]).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'});
  // also keep allocDate in sync with selected week (default today or weekStart)
  if (!weekDays.includes(allocDate)) allocDate = weekDays.includes(todayIsoAlloc) ? todayIsoAlloc : weekDays[0];

  const dateNavHTML = `<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;flex-wrap:wrap">
    <button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor='${pvW}';renderPage()">&#8249; Prev Week</button>
    <span style="font-weight:700;font-size:13px;color:var(--text-1);flex:1;text-align:center">${weekLabel}</span>
    <button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor='${nxW}';renderPage()">Next Week &#8250;</button>
    ${!weekDays.includes(todayIsoAlloc) ? `<button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor=null;allocDate='${todayIsoAlloc}';renderPage()">This Week</button>` : ''}
  </div>`;

  // Fuel info helper
  const fuelInfo = {
    petrol: { name:'Petrol (MS)', short:'Petrol', color:'var(--petrol-color)', cls:'badge-red' },
    diesel: { name:'Diesel (HSD)', short:'Diesel', color:'var(--diesel-color)', cls:'badge-orange' },
    premium_petrol: { name:'XP95 Premium', short:'Premium', color:'var(--premium-color)', cls:'badge-purple' },
  };

  // ═══ ALLOCATION WEEK GRID ═══
  // Build week-grid: rows = pump nozzles, columns = 7 days
  // Helper: get rostered employees for a specific date+shift
  function getRosteredEmps(date) {
    const rk = date + '_' + allocShift;
    const ids = (window._rosterData && window._rosterData[rk]) || [];
    return ids.length > 0
      ? D.employees.filter(e => ids.includes(String(e.id)))
      : D.employees.filter(e => { const sh=(e.shift||'').trim(); return !sh || sh.split(',').map(s=>s.trim()).includes(allocShift); });
  }

  // Day header row
  const dayHeaders = weekDays.map(date => {
    const isToday = date === todayIsoAlloc;
    const isPast  = date < todayIsoAlloc;
    const isSelected = date === allocDate;
    const d = new Date(date);
    const dayName = d.toLocaleDateString('en-IN',{weekday:'short'});
    const dayNum = d.getDate();
    return `<th style="padding:8px 4px;text-align:center;min-width:100px;cursor:pointer;border-bottom:2px solid ${isSelected?'var(--accent)':isToday?'var(--green)':'var(--border)'};${isPast?'opacity:0.4':''}"
      onclick="allocDate='${date}';renderPage()">
      <div style="font-size:10px;font-weight:700;color:${isToday?'var(--green)':isSelected?'var(--accent-light)':'var(--text-3)'};letter-spacing:0.5px">${dayName.toUpperCase()}</div>
      <div style="font-size:15px;font-weight:800;color:${isToday?'var(--green)':isSelected?'var(--accent-light)':'var(--text-0)'}">${dayNum}</div>
      ${isPast ? '<div style="font-size:9px;color:var(--text-3);margin-top:1px">locked</div>' : ''}
    </th>`;
  }).join('');

  // Build rows: one per pump-nozzle combination (sorted ascending: Pump 1 first)
  const allocTableRows = [];
  [...D.pumps].sort((a, b) => {
    const ai = parseInt(a.id) || parseInt(a.name?.replace(/\D/g,'')) || 0;
    const bi = parseInt(b.id) || parseInt(b.name?.replace(/\D/g,'')) || 0;
    return ai - bi;
  }).forEach(p => {
    const pNozzleFuels = p.nozzleFuels || {};
    const nLabels = p.nozzleLabels || (p.nozzles === 1 ? ['A'] : ['A','B']);
    nLabels.forEach(n => {
      const nKey = `${String(p.id)}_${n}`;
      const nFuelType = pNozzleFuels[n] || p.fuelType;
      const nFuelInfo = fuelInfo[nFuelType] || fuelInfo.petrol;

      const rowLabel = `<td style="padding:10px 12px;white-space:nowrap;border-right:1px solid var(--border);background:var(--bg-3);position:sticky;left:0;z-index:1">
        <div style="font-weight:800;font-size:12px;color:var(--text-0)">${p.name}</div>
        <div style="font-size:10px;margin-top:2px"><span style="color:${nFuelInfo.color};font-weight:700">N${n}</span> <span style="color:var(--text-3)">${nFuelInfo.short}</span></div>
      </td>`;

      const dayCells = weekDays.map(date => {
        const dk = date + '_' + allocShift;
        const dayAlloc = allocations[dk] || {};
        const empId = dayAlloc[nKey];
        const emp = empId ? D.employees.find(e => parseInt(e.id) === parseInt(empId)) : null;
        const isToday = date === todayIsoAlloc;
        const isPastAllocDay = date < todayIsoAlloc;
        const isSelected = date === allocDate;
        const dayEmps = getRosteredEmps(date);

        const selectOpts = dayEmps.map(e =>
          `<option value="${e.id}" ${emp && parseInt(e.id)===parseInt(emp.id) ? 'selected' : ''}>${sanitize(e.name)}</option>`
        ).join('');

        // Check if this nozzle has a conflict on this date across other shifts
        const cellHasConflict = (APP.data.shifts||[]).some(otherS => {
          if (otherS.name === allocShift) return false;
          if (!_shiftsOverlap((APP.data.shifts||[]).find(s=>s.name===allocShift)||{}, otherS)) return false;
          const otherDk = date+'_'+otherS.name;
          return !!(allocations[otherDk]?.[nKey]);
        });

        // Past day — show assigned employee as read-only chip, no dropdown
        if (isPastAllocDay) {
          return `<td style="padding:5px;background:transparent;border-right:1px solid var(--border-light);vertical-align:middle;min-width:110px;opacity:0.45">
            ${emp ? `
              <div style="display:flex;align-items:center;gap:5px;background:var(--bg-1);border:1px solid var(--border);border-radius:7px;padding:5px 7px">
                <span style="width:22px;height:22px;border-radius:6px;background:${empColor(emp)};display:grid;place-items:center;color:#fff;font-size:9px;font-weight:800;flex-shrink:0">${empInitials(emp.name)}</span>
                <span style="font-size:11px;font-weight:700;color:var(--text-2);flex:1">${sanitize(emp.name)}</span>
              </div>
            ` : `<div style="font-size:10px;color:var(--text-3);text-align:center;padding:4px">—</div>`}
          </td>`;
        }

        return `<td style="padding:5px;background:${cellHasConflict?'rgba(239,68,68,0.05)':isSelected?'rgba(212,148,15,0.04)':isToday?'rgba(34,197,94,0.03)':'transparent'};border-right:1px solid ${cellHasConflict?'rgba(239,68,68,0.3)':'var(--border-light)'};vertical-align:middle;min-width:110px">
          ${emp ? `
            <div style="display:flex;align-items:center;gap:5px;background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.25);border-radius:7px;padding:5px 7px;margin-bottom:4px">
              <span style="width:22px;height:22px;border-radius:6px;background:${empColor(emp)};display:grid;place-items:center;color:#fff;font-size:9px;font-weight:800;flex-shrink:0">${empInitials(emp.name)}</span>
              <span style="font-size:11px;font-weight:700;color:var(--green);flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${sanitize(emp.name)}</span>
              <button style="background:none;border:none;color:var(--red);cursor:pointer;font-size:12px;padding:0;line-height:1;opacity:0.7" title="Remove"
                onclick="allocDate='${date}';removeAllocForDate(${p.id},'${n}','${date}')">✕</button>
            </div>
          ` : ''}
          <select onchange="allocDate='${date}';assignNozzleForDate(${p.id},'${n}','${date}',this.value);this.value=''"
            style="width:100%;font-size:11px;padding:5px 7px;border-radius:7px;background:var(--bg-1);border:1px solid var(--border);color:var(--text-2);cursor:pointer;outline:none">
            <option value="">${emp ? '↺ Change' : '＋ Assign'}</option>
            ${selectOpts}
          </select>
        </td>`;
      }).join('');

      allocTableRows.push(`<tr style="border-bottom:1px solid var(--border-light)">${rowLabel}${dayCells}</tr>`);
    });
  });

  const allocBoard = `<div style="overflow-x:auto;border-radius:var(--radius);border:1px solid var(--border)">
    <table style="width:100%;border-collapse:collapse;min-width:700px">
      <thead>
        <tr style="background:var(--bg-3)">
          <th style="padding:10px 12px;text-align:left;font-size:11px;color:var(--text-3);font-weight:700;border-right:1px solid var(--border);position:sticky;left:0;z-index:2;background:var(--bg-3)">PUMP / NOZZLE</th>
          ${dayHeaders}
        </tr>
      </thead>
      <tbody>${allocTableRows.join('')}</tbody>
    </table>
  </div>`;

  // ═══ EMPLOYEE ASSIGNMENT SUMMARY ═══
  const empSummaryRows = shiftEmps.map(emp => {
    const assignedNozzles = [];
    Object.entries(shiftAlloc).forEach(([key, id]) => {
      if (parseInt(id) === parseInt(emp.id)) {
        const [pumpId, nozzle] = key.split('_');
        const pump = D.pumps.find(p => String(p.id) === String(pumpId));
        assignedNozzles.push({ pump: pump?.name || `Pump ${pumpId}`, nozzle, fuelType: pump?.fuelType });
      }
    });
    return `<tr>
      <td><div style="display:flex;align-items:center;gap:8px">
        <span class="emp-av" style="width:28px;height:28px;border-radius:8px;background:${empColor(emp)};display:grid;place-items:center;color:#fff;font-size:10px;font-weight:800;flex-shrink:0">${empInitials(emp.name)}</span>
        <div><div class="fw-700" style="color:var(--text-0)">${sanitize(emp.name)}</div><div style="font-size:10px;color:var(--text-3)">${sanitize(emp.role)}</div></div>
      </div></td>
      <td style="font-size:12px">${assignedNozzles.length > 0 ? assignedNozzles.map(a => {
        const fi = fuelInfo[a.fuelType] || fuelInfo.petrol;
        return `<span class="nozzle-tag"><span class="dot" style="background:${fi.color}"></span>${a.pump}‑${a.nozzle}</span>`;
      }).join('') : '<span style="color:var(--red);font-weight:600;font-size:11px">⚠ No nozzles assigned</span>'}</td>
      <td class="r"><span class="mono fw-700" style="color:${assignedNozzles.length > 0 ? 'var(--green)' : 'var(--red)'}">${assignedNozzles.length}</span></td>
    </tr>`;
  }).join('');

  // ═══ SHIFT SCHEDULE ═══
  _normalizeShiftTimes(D.shifts);
  const h = new Date().getHours();
  const shiftCards = sortedShifts.map(s => {
    const emps = D.employees.filter(e => { const sh=(e.shift||'').trim(); return !sh || sh.split(',').map(x=>x.trim()).includes(s.name); });
    const [sh] = (s.start||'00:00').split(':').map(Number);
    const [eh] = (s.end||'00:00').split(':').map(Number);
    const isActive = sh < eh ? (h >= sh && h < eh) : (h >= sh || h < eh);
    return `<div class="dbox-lg" style="border:1px solid ${isActive ? 'rgba(212,148,15,0.3)' : 'var(--border-light)'};border-radius:var(--radius);${isActive ? 'background:rgba(212,148,15,0.04)' : ''}">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
        <div style="display:flex;align-items:center;gap:8px">
          <span class="fw-700" style="color:${isActive ? 'var(--accent-light)' : 'var(--text-0)'};font-size:15px">${s.name} Shift</span>
          ${isActive ? badge('ACTIVE', 'badge-accent') : ''}
        </div>
        <div style="display:flex;gap:4px">
          <button class="btn btn-ghost btn-sm" onclick="openEditShiftModal('${s.id}')" title="Edit Shift" style="padding:4px 8px">✏️</button>
          <button class="btn btn-sm" onclick="confirmDeleteShift('${s.id}')" title="Delete Shift" style="background:rgba(239,68,68,0.08);color:var(--red);border:none;padding:4px 8px">🗑</button>
        </div>
      </div>
      <div class="mono fw-800 mb-8" style="color:var(--text-0);font-size:20px">${s.start} — ${s.end}</div>
      <div style="font-size:12px;color:var(--text-3)">Manager: <span style="color:var(--text-1)">${(() => { const me = s.managerId ? D.employees.find(e=>e.id===s.managerId) : D.employees.find(e=>e.role==='Shift Manager'&&e.name===s.manager); return sanitize(me ? me.name : (s.manager||'—')); })()}</span> · Staff: ${emps.length}</div>
      <div style="display:flex;gap:4px;margin-top:8px;flex-wrap:wrap">${emps.map(e =>
        `<span style="width:24px;height:24px;border-radius:6px;background:${empColor(e)};display:grid;place-items:center;color:#fff;font-size:8px;font-weight:800" title="${e.name}">${empInitials(e.name)}</span>`
      ).join('')}</div>
    </div>`;
  }).join('');

  // ═══ EMPLOYEE DIRECTORY ═══
  const empRows = D.employees.map(e => {
    const hasPIN = !!getEmpPinHash(e.id);
    const pendingBal = e.pendingBalance || 0;
    const pendingEntries = (e.balanceEntries || []).filter(b => b.status === 'pending');
    return `<tr>
      <td><div style="display:flex;align-items:center;gap:8px">
        <span style="width:28px;height:28px;border-radius:8px;background:${empColor(e)};display:grid;place-items:center;color:#fff;font-size:10px;font-weight:800;flex-shrink:0">${empInitials(e.name)}</span>
        <div>
          <div class="fw-700" style="color:var(--text-0)">${sanitize(e.name)}</div>
          <div style="font-size:10px;color:var(--text-3)">${sanitize(e.phone||'')}</div>
          ${pendingBal > 0 ? `<div style="font-size:10px;font-weight:700;color:var(--red);margin-top:2px">⚠ Balance: ${cur(pendingBal)}</div>` : ''}
        </div>
      </div></td>
      <td>${badge(e.role, e.role === 'Shift Manager' ? 'badge-accent' : 'badge-blue')}</td>
      <td>${(e.shift||'').split(',').map(s=>`<span style="font-size:10px;font-weight:600;color:var(--accent-light);background:rgba(212,148,15,0.08);padding:1px 7px;border-radius:3px;margin-right:3px">${sanitize(s.trim())}</span>`).join('')}</td>
      <td class="r mono fw-600">${cur(e.salary)}</td>
      <td class="r">
        ${pendingEntries.length > 0
          ? `<button class="btn btn-sm" style="background:rgba(239,68,68,0.1);color:var(--red);border:1px solid rgba(239,68,68,0.25);font-size:11px;padding:4px 10px" onclick="openEmpBalanceModal(${e.id})">
               ⚠️ ${cur(pendingBal)} pending
             </button>`
          : `<span style="font-size:11px;color:var(--green);font-weight:600">✅ No balance</span>`
        }
      </td>
      <td class="r">${hasPIN ? '<span style="color:var(--green);font-size:11px;font-weight:700">✓ PIN Set</span>' : '<span style="color:var(--red);font-size:11px;font-weight:700">⚠ No PIN</span>'}</td>
      <td class="r">
        <div style="display:flex;gap:4px;justify-content:flex-end">
          <button class="btn btn-ghost btn-sm" onclick="openEditEmployeeModal(${e.id})" title="Edit">✏️</button>
          <button class="btn btn-ghost btn-sm" onclick="openSetPINModal(${e.id})" title="Set PIN" style="color:var(--accent-light)">🔑</button>
          <button class="btn btn-sm" onclick="confirmDeleteEmployee(${e.id})" title="Delete" style="background:rgba(239,68,68,0.08);color:var(--red);border:none">🗑</button>
        </div>
      </td>
    </tr>`;
  }).join('');

  // ── Internal tab rendering ──────────────────────────────────
  const tabs = [
    { id: 'shifts',     icon: '⏰', label: 'Shifts' },
    { id: 'roster',     icon: '🗓️', label: 'Roster' },
    { id: 'allocation', icon: '⛽', label: 'Allocation' },
    { id: 'attendance', icon: '✅', label: 'Attendance' },
    { id: 'directory',  icon: '📋', label: 'Directory' },
  ];

  const tabBar = `<div style="display:flex;gap:0;background:var(--bg-1);border-radius:var(--radius);padding:4px;margin-bottom:20px;border:1px solid var(--border-light);overflow-x:auto">
    ${tabs.map(t => `<button onclick="window.staffTab='${t.id}';renderPage()" style="flex:1;min-width:80px;padding:8px 10px;border-radius:calc(var(--radius) - 2px);border:none;background:${window.staffTab===t.id?'var(--bg-3)':'transparent'};color:${window.staffTab===t.id?'var(--accent-light)':'var(--text-3)'};font-family:var(--font);font-size:11px;font-weight:700;cursor:pointer;letter-spacing:0.3px;transition:background 0.15s;white-space:nowrap">
      ${t.icon} ${t.label}
    </button>`).join('')}
  </div>`;

  // ── Context-aware header buttons ─────────────────────────────
  const hdrBtns = window.staffTab === 'shifts'
    ? `<button class="btn btn-ghost" onclick="openAddShiftModal()">+ Add Shift</button><button class="btn btn-accent" onclick="openEmployeeModal()">+ Add Employee</button>`
    : window.staffTab === 'allocation'
    ? `<button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor=(()=>{const _a=window.allocWeekAnchor?new Date(window.allocWeekAnchor):new Date();_a.setDate(_a.getDate()-7);return _a.toISOString().slice(0,10);})();renderPage()">◀ Prev</button><button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor=(()=>{const _a=window.allocWeekAnchor?new Date(window.allocWeekAnchor):new Date();_a.setDate(_a.getDate()+7);return _a.toISOString().slice(0,10);})();renderPage()">Next ▶</button><button class="btn btn-ghost btn-sm" onclick="autoAssignAlloc()">⚡ Auto</button><button class="btn btn-ghost btn-sm" onclick="clearShiftAllocConfirm()">🗑 Clear</button>`
    : window.staffTab === 'attendance'
    ? `<input type="date" class="form-input" style="padding:6px 12px;font-size:13px;width:160px" value="${window._attDate||(()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})()}" onchange="window._attDate=this.value;renderPage()" /><button class="btn btn-accent btn-sm" onclick="attSave()">💾 Save</button><button class="btn btn-ghost btn-sm" onclick="attMarkAllPresent('${window._attDate||(()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})()}')">✅ All Present</button>`
    : window.staffTab === 'roster'
    ? `<button class="btn btn-ghost btn-sm" onclick="rosterNavWeek(-1)">◀ Prev</button><button class="btn btn-ghost btn-sm" onclick="rosterNavWeek(1)">Next ▶</button>${(()=>{const _o=window._rosterWeekOffset||0;const _t=new Date();const _d=_t.getDay()===0?6:_t.getDay()-1;const _w=new Date(_t);_w.setDate(_t.getDate()-_d+_o*7);_w.setHours(0,0,0,0);const _m=new Date(_t);_m.setDate(_t.getDate()-_d);_m.setHours(0,0,0,0);return _w<_m?'':'<button class="btn btn-accent btn-sm" onclick="rosterSave()">💾 Save</button>';})()}`
    : `<button class="btn btn-accent" onclick="openEmployeeModal()">+ Add Employee</button>`;

  // ── Tab content ───────────────────────────────────────────────
  let tabContent = '';

  if (window.staffTab === 'shifts') {
    tabContent = `
      ${(() => {
        const totalPending = D.employees.reduce((a,e) => a + (e.pendingBalance||0), 0);
        const pendingCount = D.employees.filter(e => (e.pendingBalance||0) > 0).length;
        return `<div class="g g-auto-sm mb-24 gap-16">
          ${statCard('Total Staff', D.employees.length, 'across all shifts', '👤')}
          ${statCard('Monthly Payroll', cur(payroll), '', '💰')}
          ${statCard('Total Nozzles', totalNozzles, D.pumps.length + ' pumps', '⛽')}
          ${totalPending > 0
            ? `<div class="stat-card" style="border:1px solid rgba(239,68,68,0.3);background:rgba(239,68,68,0.04);cursor:pointer" onclick="window.staffTab='directory';renderPage()">
                 <div style="font-size:22px;margin-bottom:4px">⚠️</div>
                 <div class="stat-value" style="color:var(--red)">${cur(totalPending)}</div>
                 <div class="stat-label">${pendingCount} employee${pendingCount>1?'s':''} with balance</div>
               </div>`
            : statCard('Assigned', assignedCount + '/' + totalNozzles, allocShift + ' shift', '✅')}
        </div>`;
      })()}
      <div class="card">
        <div class="card-head"><h4>⏰ Shift Schedule</h4></div>
        <div class="card-body" style="padding:14px"><div class="g" style="grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:14px">${shiftCards}</div></div>
      </div>`;

  } else if (window.staffTab === 'allocation') {
    tabContent = `
      ${window._renderAllocConflictBanner ? window._renderAllocConflictBanner(APP.data, allocations) : ''}
      <div class="card mb-24">
        <div class="card-head">
          <h4>⛽ Pump & Nozzle Allocation Board</h4>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button class="btn btn-accent btn-sm" onclick="copyAllocModal()">📋 Copy to Shift</button>
          </div>
        </div>
        <div style="padding:16px 20px 4px">
          <div class="shift-tabs mb-12">${shiftTabs}</div>
          <div style="font-size:12px;color:var(--text-3);margin-bottom:14px">
            Assign employees to individual pump nozzles for <strong style="color:var(--accent-light)">${allocShift}</strong> shift
            · <span style="color:var(--text-2)">${shiftEmps.length} employees available</span>
            ${rosterFiltered ? `<span style="margin-left:6px;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700;background:rgba(34,197,94,0.12);color:var(--green);border:1px solid rgba(34,197,94,0.25)">🗓️ Roster filtered</span>` : `<span style="margin-left:6px;font-size:10px;color:var(--text-3)">(set roster to filter by day)</span>`}
            · <span style="font-size:11px;color:var(--text-3)">Click any cell to assign · Week view shows 7 days</span>
          </div>
        </div>
        <div style="padding:0 20px 20px">
          <div class="alloc-board">${allocBoard}</div>
        </div>
      </div>
      <div class="card">
        <div class="card-head"><h4>👥 Employee Assignment Summary — ${allocShift} Shift</h4></div>
        <div class="card-body"><div class="tbl-wrap"><table><thead><tr><th>Employee</th><th>Assigned Nozzles</th><th class="r">Count</th></tr></thead><tbody>${empSummaryRows}</tbody></table></div></div>
      </div>`;

  } else if (window.staffTab === 'roster') {
    tabContent = renderRoster(D).replace(/<div class="page-hdr">.*?<\/div>\s*/s, '');

  } else if (window.staffTab === 'attendance') {
    tabContent = renderAttendance(D).replace(/<div class="page-hdr">.*?<\/div>\s*/s, '');

  } else { // directory
    tabContent = `
      <div class="card" id="empDirectorySection">
        <div class="card-head"><h4>📋 Employee Directory</h4></div>
        <div class="card-body"><div class="tbl-wrap"><table><thead><tr><th>Name</th><th>Role</th><th>Shift</th><th class="r">Salary</th><th class="r">PIN</th><th class="r">Actions</th></tr></thead><tbody>${empRows}</tbody></table></div></div>
      </div>`;
  }

  return `
    ${shiftFixBanner}
    <div class="page-hdr"><h3>👥 Staff & Allocation</h3><div style="display:flex;gap:8px;align-items:center">${hdrBtns}</div></div>
    ${tabBar}
    ${tabContent}
  `;
}

// ── FINANCE ──────────────────────────────────────────────────
function renderFinance(D) {
  const totalRevenue = D.sales.reduce((a, s) => a + s.amount, 0);
  const lubesRevenue = (window._lubesSales || []).reduce((a, s) => a + (s.amount||0), 0);
  const lubesCost    = (window._lubesProducts || []).reduce((a, p) => {
    const sold = (window._lubesSales || []).filter(s => s.productId === p.id).reduce((x,s) => x + s.qty, 0);
    return a + sold * (p.costPrice || 0);
  }, 0);
  const gross = totalRevenue + lubesRevenue; // Revenue is gross before fuel purchase cost

  // ── Fuel Purchases — listed individually by transaction ──
  const fuelPurchases = (D.fuelPurchases || []).sort((a, b) => (b.id||0) - (a.id||0));
  const totalFuelCost = fuelPurchases.reduce((a, p) => a + (p.total || 0), 0);

  // Real non-fuel expenses from expense register
  const allExpenses = D.expenses || [];
  const opExpenses = allExpenses.filter(e => (e.source !== 'fuel_purchase') && !(e.category || '').includes('Fuel'));
  const opEx = opExpenses.reduce((a, e) => a + e.amount, 0);

  // Group opExpenses by category
  const expByCategory = {};
  opExpenses.forEach(e => {
    const cat = e.category || 'Misc';
    expByCategory[cat] = (expByCategory[cat] || 0) + e.amount;
  });

  // ── Salary: only count employees marked paid in payroll for current month ──
  const _plMonth = window._payMonth || (new Date().getMonth() + 1);
  const _plYear  = window._payYear  || new Date().getFullYear();
  const _paidSlips = Object.values(window._payrollSaved || {})
    .filter(p => p.status === 'paid' && p.month === _plMonth && p.year === _plYear);
  const salary    = _paidSlips.reduce((a, p) => a + (p.net || 0), 0);
  const paidCount = _paidSlips.length;
  const totalEmps = (D.employees || []).length;
  const netProfit = totalRevenue - totalFuelCost - opEx - salary;

  // ── Build P&L rows ──
  // Section 1: Revenue
  const revenueRow = `
    <div class="flex-between" style="padding:9px 0;border-bottom:1px solid var(--border-light)">
      <span style="color:var(--text-2);font-size:13px">Fuel Sales Revenue</span>
      <span style="color:var(--green)" class="mono fw-700">${cur(totalRevenue)}</span>
    </div>
    ${lubesRevenue > 0 ? `<div class="flex-between" style="padding:9px 0 9px 14px;border-bottom:1px solid var(--border-light);background:rgba(168,85,247,0.02)">
      <span style="color:var(--text-3);font-size:13px">🛢️ Lubes &amp; Products</span>
      <span style="color:var(--green)" class="mono fw-700">${cur(lubesRevenue)}</span>
    </div>
    <div class="flex-between" style="padding:9px 0;border-bottom:2px solid var(--border-light)">
      <span style="color:var(--text-1);font-weight:700;font-size:13px">Total Revenue</span>
      <span style="color:var(--green)" class="mono fw-800">${cur(totalRevenue + lubesRevenue)}</span>
    </div>` : ''}
  `;

  // Section 2: Fuel Purchases — each purchase as its own line
  let fuelPurchaseRows = '';
  if (fuelPurchases.length > 0) {
    fuelPurchaseRows = fuelPurchases.map(p => {
      const fi = getFuel(p.fuelType) || { short: p.fuelType, name: p.fuelType, color: '#f97316' };
      const inv = p.invoice ? `<span style="font-size:9px;color:var(--text-3);margin-left:6px;font-family:var(--mono)">${sanitize(p.invoice)}</span>` : '';
      const taxBreakdown = p.basicRate
        ? `<span style="font-size:9px;color:var(--text-3);margin-left:6px">Basic ₹${(p.basicRate/1000).toFixed(3)}/L + ${p.taxName||'Tax'} ${p.taxPct||0}% → ₹${(p.rate||0).toFixed(3)}/L</span>`
        : `<span style="font-size:10px;color:var(--text-3);margin-left:6px">${fmt(p.liters)}L @ ₹${(p.rate||0).toFixed(2)}/L</span>`;
      return `<div style="padding:8px 0 8px 14px;border-bottom:1px solid var(--border-light);background:rgba(249,115,22,0.03)">
        <div style="display:flex;justify-content:space-between;align-items:flex-start">
          <div style="display:flex;align-items:center;flex-wrap:wrap;gap:3px">
            <span style="font-size:10px;font-weight:800;color:${fi.color};background:${fi.color}18;padding:1px 7px;border-radius:3px">${fi.short}</span>
            <span style="font-size:10px;color:var(--text-2);font-weight:600">${fmt(p.liters)}L</span>
            ${inv}
            <span style="font-size:10px;color:var(--text-3);margin-left:2px">${p.date||''}</span>
          </div>
          <span style="color:var(--red);white-space:nowrap;margin-left:8px" class="mono fw-700">-${cur(p.total||0)}</span>
        </div>
        <div style="margin-top:3px">${taxBreakdown}</div>
      </div>`;
    }).join('');
    fuelPurchaseRows = `
      <div style="padding:8px 0 4px;font-size:10px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.8px">⛽ Fuel Purchases</div>
      ${fuelPurchaseRows}
      <div class="flex-between" style="padding:7px 0;border-bottom:2px solid var(--border)">
        <span style="color:var(--text-2);font-size:12px;font-weight:600">Total Fuel Cost</span>
        <span style="color:var(--red)" class="mono fw-700">-${cur(totalFuelCost)}</span>
      </div>`;
  } else {
    fuelPurchaseRows = `<div style="padding:8px 14px;font-size:11px;color:var(--text-3);border-bottom:1px solid var(--border-light)">No fuel purchases recorded</div>`;
  }

  // Gross Profit row (Revenue - Fuel Cost - Lubes COGS)
  const grossProfit = (totalRevenue + lubesRevenue) - totalFuelCost - lubesCost;
  const grossRow = `
    ${lubesCost > 0 ? `<div class="flex-between" style="padding:7px 0 7px 14px;border-bottom:1px solid var(--border-light);background:rgba(168,85,247,0.02)">
      <span style="color:var(--text-3);font-size:13px">🛢️ Lubes Cost of Goods</span>
      <span style="color:var(--red)" class="mono fw-700">-${cur(lubesCost)}</span>
    </div>` : ''}
    <div class="flex-between" style="padding:10px 0;border-bottom:2px solid var(--border)">
      <span style="color:var(--text-0);font-weight:800;font-size:13px">Gross Profit</span>
      <span style="color:${grossProfit >= 0 ? 'var(--accent-light)' : 'var(--red)'}" class="mono fw-800">${grossProfit < 0 ? '-' : ''}${cur(Math.abs(grossProfit))}</span>
    </div>`;

  // Section 3: Other operating expenses grouped by category
  const hasOpEx = salary > 0 || Object.keys(expByCategory).length > 0;
  let opExpRows = '';
  if (hasOpEx) {
    const opLines = [];
    if (salary > 0) opLines.push(`<div class="flex-between" style="padding:7px 0 7px 14px;border-bottom:1px solid var(--border-light)"><span style="color:var(--text-3);font-size:13px">Salaries <span style="font-size:10px;opacity:0.7">(${paidCount} of ${totalEmps} paid)</span></span><span style="color:var(--red)" class="mono fw-700">-${cur(salary)}</span></div>`);
    Object.entries(expByCategory).forEach(([cat, amt]) => {
      opLines.push(`<div class="flex-between" style="padding:7px 0 7px 14px;border-bottom:1px solid var(--border-light)"><span style="color:var(--text-3);font-size:13px">${cat}</span><span style="color:var(--red)" class="mono fw-700">-${cur(amt)}</span></div>`);
    });
    opExpRows = `<div style="padding:8px 0 4px;font-size:10px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.8px">🧾 Operating Expenses</div>` + opLines.join('');
  }

  const pnlHtml = revenueRow + fuelPurchaseRows + grossRow + opExpRows;

  const marginCards = FUEL_TYPES.map(f => {
    const sell = D.prices[f.id] || 0, buy = D.purchasePrices[f.id] || 0, margin = sell - buy, pct = sell > 0 ? (margin / sell) * 100 : 0;
    const sold = D.sales.filter(s => s.fuelType === f.id).reduce((a, s) => a + s.liters, 0);
    return `<div class="dbox-lg mb-12" style="border:1px solid var(--border-light);border-radius:var(--radius)">
      <div class="flex-between mb-8"><span style="color:${f.color}" class="fw-700">${f.name}</span><span class="mono fw-800" style="color:var(--green)">₹${margin.toFixed(2)}/L</span></div>
      <div class="g" style="grid-template-columns:1fr 1fr 1fr;gap:8px;font-size:11px">
        <div><div style="color:var(--text-3)">Purchase</div><div class="mono fw-600">${cur(buy)}</div></div>
        <div><div style="color:var(--text-3)">Selling</div><div class="mono fw-600">${cur(sell)}</div></div>
        <div><div style="color:var(--text-3)">Margin</div><div class="mono fw-600" style="color:var(--green)">${pct.toFixed(1)}%</div></div>
      </div>
      <div class="mt-8" style="font-size:12px;color:var(--text-3)">Today: ${fmt(sold)}L → <span class="mono fw-700" style="color:var(--green)">${cur(sold * margin)}</span></div>
    </div>`;
  }).join('');

  // Merge all expenses (incl. fuel purchases auto-entries) sorted by date desc
  const allExpRows = [...(D.expenses || [])].sort((a, b) => (b.id || 0) - (a.id || 0));
  const expRows = allExpRows.length > 0
    ? allExpRows.map(e => {
        const isFuel = (e.category || '') === 'Fuel Purchase';
        const catColor = catColors[e.category] || '#6b7080';
        return `<tr style="${isFuel ? 'background:rgba(249,115,22,0.04)' : ''}">
          <td style="font-size:12px">${e.date}</td>
          <td>${badgeColor(e.category || 'Misc', catColor)}${e.taxType === 'gst' ? ' <span style="font-size:9px;background:rgba(6,182,212,0.15);color:#06b6d4;padding:1px 5px;border-radius:3px;font-weight:700">GST</span>' : ''}${e.taxType === 'local_sales_tax' ? ' <span style="font-size:9px;background:rgba(212,148,15,0.15);color:var(--accent-light);padding:1px 5px;border-radius:3px;font-weight:700">SALES TAX</span>' : ''}</td>
          <td style="font-size:12px;color:var(--text-2)">${sanitize(e.desc || '')}${e.billFuels ? ' <span style="font-size:10px;color:var(--text-3)">[' + e.billFuels + ']</span>' : ''}${e.gstRate ? ' <span style="font-size:10px;color:var(--text-3)">GST ' + e.gstRate + '%</span>' : ''}</td>
          <td class="r mono fw-700" style="color:var(--red)">${cur(e.amount)}</td>
        </tr>`;
      }).join('')
    : `<tr><td colspan="4" style="text-align:center;padding:24px;color:var(--text-3)">No expenses recorded yet</td></tr>`;

  return `
    <div class="page-hdr"><h3>📈 Financial Management</h3>
      <div class="flex" style="gap:8px;flex-wrap:wrap">
        <button class="btn btn-accent" onclick="openExpenseModal()">+ Add Expense</button>
        <button class="btn btn-ghost" style="font-size:11px;padding:6px 10px" onclick="openExpenseModal('Local Sales Tax (Bill)')" title="Record local sales tax on petrol">🏷 Tax</button>
        <button class="btn btn-ghost" style="font-size:11px;padding:6px 10px" onclick="openExpenseModal('GST — Lube / Lubricants')" title="Record GST on lube purchase">📦 Lube GST</button>
        <button class="btn btn-ghost" onclick="generatePLReport()">📄 P&L Report</button>
      </div>
    </div>
    <div class="g g-auto-sm mb-24 gap-16">
      ${statCard("Today's Revenue", cur(totalRevenue), 'all sales', '💰')}
      ${statCard('Fuel Purchased', cur(totalFuelCost), fuelPurchases.length + ' purchase(s)', '🛢️')}
      ${statCard('Gross Profit', cur(grossProfit), totalRevenue > 0 ? ((grossProfit / totalRevenue) * 100).toFixed(1) + '% margin' : '—', '📊')}
      ${statCard('Operating Exp', cur(opEx), 'this month', '🧾')}
    </div>
    <div class="g g-2 gap-16 mb-24">
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">📊 P&L — Monthly Estimate</h4>
        ${pnlHtml}
        <div class="flex-between" style="padding:14px 0 0;margin-top:10px;border-top:2px solid rgba(212,148,15,0.3)">
          <span class="fw-800" style="color:var(--accent-light);font-size:15px">Net Profit</span>
          <span class="mono fw-800" style="color:${netProfit >= 0 ? 'var(--green)' : 'var(--red)'};font-size:15px">${netProfit < 0 ? '-' : ''}${cur(Math.abs(netProfit))}</span>
        </div>
      </div>
      <div class="card card-pad"><h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">⛽ Fuel Margins</h4>${marginCards}</div>
    </div>
    <div class="card">
      <div class="card-head"><h4>🧾 Expense Register</h4><button class="btn btn-ghost btn-sm" onclick="exportExpenseCSV()">↓ Export</button></div>
      <div class="card-body"><div class="tbl-wrap"><table><thead><tr><th>Date</th><th>Category</th><th>Description</th><th class="r">Amount</th></tr></thead>
        <tbody>${expRows}</tbody>
        ${allExpRows.length > 0 ? `<tfoot><tr style="border-top:2px solid var(--border)"><td colspan="3" style="padding:8px;font-weight:700;color:var(--text-0)">Total</td><td class="r mono fw-800" style="color:var(--red);padding:8px">${cur(allExpRows.reduce((a,e)=>a+e.amount,0))}</td></tr></tfoot>` : ''}
      </table></div></div>
    </div>`;
}

// ── REPORTS ───────────────────────────────────────────────────
function renderReports(D) {
  if (!D) return '<div style="padding:40px;text-align:center;color:var(--text-3)">Loading...</div>';
  const totalRevenue = D.sales.reduce((a, s) => a + s.amount, 0);
  const cogs = D.sales.reduce((a, s) => a + s.liters * ((D.purchasePrices||{})[s.fuelType]||0), 0);
  const totalLiters = D.sales.reduce((a, s) => a + s.liters, 0);
  const totalStock = D.tanks.reduce((a, t) => a + (t.current || 0), 0);

  const todayIso2 = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
  const dsrFilterDate = reportDate || todayIso2;
  const todaySalesOnly = D.sales.filter(s => (s.date||'').slice(0,10) === dsrFilterDate);
  const totalSoldToday = todaySalesOnly.reduce((a,s) => a + (s.liters||0), 0);
  const openingStock = totalStock + totalSoldToday; // closing stock + what was sold = opening stock
  const todayLiters = totalSoldToday;
  const todayRev = todaySalesOnly.reduce((a,s) => a + (s.amount||0), 0);
  const fuelReceived = D.fuelPurchases ? D.fuelPurchases.filter(f=>(f.date||'').slice(0,10)===todayIso2).reduce((a,f)=>a+(f.liters||0),0) : 0;
  const dsrItems = [
    { l: 'Closing Stock', v: fmt(totalStock) + ' L' },
    { l: 'Fuel Received', v: fmt(fuelReceived) + ' L' },
    { l: 'Total Sales', v: fmt(todayLiters) + ' L' },
    { l: 'Revenue', v: cur(todayRev), cls: 'color:var(--green)' },
    { l: 'Transactions', v: todaySalesOnly.length },
    { l: 'Cash Collected', v: cur(todaySalesOnly.filter(s=>s.mode==='cash').reduce((a,s)=>a+s.amount,0)) },
  ].map(i => `<div class="dbox"><div class="dbox-label">${i.l}</div><div class="dbox-value mono" style="font-size:14px;${i.cls || ''}">${i.v}</div></div>`).join('');

  const reports = [
    { n: 'Monthly P&L Statement', d: 'Revenue, COGS, expenses, net profit', fn: 'generatePLReport()', csv: 'exportPLCSV()' },
    { n: 'Daily Shift Report', d: 'Complete DSR with pump readings', fn: 'generateDSRReport()', csv: 'exportDSRCSV()' },
    { n: 'Credit Outstanding', d: 'Customer-wise aging report', fn: 'generateCreditReport()', csv: 'exportCreditCSV()' },
    { n: 'Tank Reconciliation', d: 'Dip vs book stock variance', fn: 'generateTankReport()', csv: 'exportDipCSV()' },
    { n: 'Pump Sales Report', d: 'Per-pump meter & sales data', fn: 'generatePumpReport()', csv: 'exportPumpCSV()' },
    { n: 'GST Summary', d: 'Tax computation for filing', fn: 'generateGSTReport()', csv: 'exportGSTCSV()' },
    { n: 'Employee Shift Report', d: 'Monthly attendance & shift history per employee', fn: 'generateShiftReport()', csv: 'exportShiftCSV()' },
  ].map(r => `<div class="flex-between" style="padding:10px 0;border-bottom:1px solid var(--border-light)">
    <div><div class="fw-600" style="font-size:13px;color:var(--text-1)">${r.n}</div><div style="font-size:11px;color:var(--text-3)">${r.d}</div></div>
    <div style="display:flex;gap:6px">
      <button class="btn btn-ghost btn-sm" onclick="${r.fn}" style="font-size:11px">📄 PDF</button>
      <button class="btn btn-ghost btn-sm" onclick="${r.csv}" style="font-size:11px;color:var(--green)">📊 Excel</button>
    </div>
  </div>`).join('');

  const creditPct = totalRevenue ? ((D.sales.filter(s => s.mode === 'credit').reduce((a, s) => a + s.amount, 0) / totalRevenue) * 100).toFixed(1) : 0;
  const upiPct = totalRevenue ? ((D.sales.filter(s => s.mode === 'upi').reduce((a, s) => a + s.amount, 0) / totalRevenue) * 100).toFixed(1) : 0;
  const kpis = [
    { l: 'Avg Sale Value', v: cur(D.sales.length ? totalRevenue / D.sales.length : 0), c: '#22c55e' },
    { l: 'Avg Liters/Txn', v: (D.sales.length ? totalLiters / D.sales.length : 0).toFixed(1) + ' L', c: '#3b82f6' },
    { l: 'Gross Margin', v: (totalRevenue ? ((totalRevenue - cogs) / totalRevenue * 100) : 0).toFixed(1) + '%', c: '#d4940f' },
    { l: 'Credit Ratio', v: creditPct + '%', c: '#ef4444' },
    { l: 'UPI Adoption', v: upiPct + '%', c: '#a855f7' },
    { l: 'Total Transactions', v: D.sales.length, c: '#f97316' },
  ].map(k => `<div class="dbox text-center" style="padding:16px;border-radius:var(--radius)">
    <div class="mono fw-800" style="color:${k.c};font-size:22px">${k.v}</div>
    <div class="fw-600 mt-8" style="font-size:10px;color:var(--text-3);text-transform:uppercase;letter-spacing:0.8px">${k.l}</div>
  </div>`).join('');

  return `
    <div class="page-hdr"><h3>📄 Reports & Analytics</h3></div>
    <div class="g g-2 gap-16 mb-24">
      <div class="card card-pad">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
          <h4 class="fw-700" style="color:var(--text-0);font-size:13px">📋 Daily Shift Report (DSR)</h4>
          <div style="display:flex;align-items:center;gap:6px">
            <button class="btn btn-ghost btn-sm" onclick="reportDate=new Date(new Date(reportDate).getTime()-86400000).toISOString().slice(0,10);renderPage()">&#8249;</button>
            <input type="date" value="${dsrFilterDate}" onchange="reportDate=this.value;renderPage()"
              style="background:var(--bg-0);border:1px solid var(--border);border-radius:6px;padding:3px 8px;color:var(--text-1);font-size:12px;cursor:pointer" />
            <button class="btn btn-ghost btn-sm" onclick="reportDate=new Date(new Date(reportDate).getTime()+86400000).toISOString().slice(0,10);renderPage()">&#8250;</button>
            ${reportDate!==todayIso2?`<button class="btn btn-ghost btn-sm" onclick="reportDate='${todayIso2}';renderPage()">Today</button>`:''}
          </div>
        </div>
        <div class="g" style="grid-template-columns:1fr 1fr;gap:10px">${dsrItems}</div>
        <div style="display:flex;gap:8px;margin-top:16px">
        <button class="btn btn-accent" style="flex:2" onclick="generateDSRReport()">📄 PDF Report</button>
        <button class="btn btn-ghost" style="flex:1;font-size:12px;color:var(--green)" onclick="exportDSRCSV()">📊 Excel</button>
        <button class="btn btn-ghost" style="flex:1;font-size:12px;color:#25d366" onclick="wa_sendDailySummary('${dsrFilterDate}')" title="Send via WhatsApp">💬 WA</button>
      </div>
      </div>
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">⚡ Quick Reports</h4>
        ${reports}
      </div>
    </div>
    <div class="card card-pad">
      <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">📊 Key Performance Indicators</h4>
      <div class="g" style="grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:14px">${kpis}</div>
    </div>
    <div class="card card-pad mt-16">
      <div class="flex-between mb-16"><h4 class="fw-700" style="color:var(--text-0);font-size:13px">🔒 Audit Trail</h4><span class="badge badge-green">${(APP.auditLog||[]).length} entries</span></div>
      <div class="tbl-wrap"><table><thead><tr><th>Time</th><th>User</th><th>Action</th><th>Details</th></tr></thead><tbody>
      ${(APP.auditLog||[]).slice(0,50).map(l => `<tr>
        <td style="font-size:11px;white-space:nowrap;color:var(--text-3)">${sanitize((l.timestamp||'').substring(0,19).replace('T',' '))}</td>
        <td class="fw-600" style="font-size:12px">${sanitize(l.user||'')}</td>
        <td>${badge(sanitize(l.action||''), l.action==='login'||l.action==='logout'?'badge-blue':l.action==='price_change'||l.action==='data_clear'?'badge-red':'badge-accent')}</td>
        <td style="font-size:10px;color:var(--text-3);max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${sanitize(JSON.stringify(l.details||{})).substring(0,80)}</td>
      </tr>`).join('') || '<tr><td colspan="4" style="text-align:center;color:var(--text-3);padding:20px">No audit entries yet</td></tr>'}
      </tbody></table></div>
    </div>`;
}

// ── SETTINGS ─────────────────────────────────────────────────
function renderSettings(D) {
  const priceCards = FUEL_TYPES.map(f => {
    const margin = ((D.prices||{})[f.id]||0) - ((D.purchasePrices||{})[f.id]||0);
    return `<div class="flex-between" style="padding:14px;background:var(--bg-0);border-radius:var(--radius);margin-bottom:10px;border:1px solid var(--border-light)">
      <div><div style="color:${f.color}" class="fw-700">${f.name}</div></div>
      <div class="text-right"><div class="mono fw-800" style="color:var(--text-0);font-size:22px">₹${((D.prices||{})[f.id]||0).toFixed(2)}</div>
        <div class="mono fw-600" style="font-size:11px;color:var(--green)">Margin: ₹${margin.toFixed(2)}/L</div></div>
    </div>`;
  }).join('');

  const _t = APP.tenant || {};
  const info = [
    ['Station Name', _t.name || 'FuelBunk Station'],
    ['Owner', _t.ownerName || '—'],
    ['Location', _t.location || '—'],
    ['Contact', _t.phone || '—'],
    ['Tanks', D.tanks.length + ' Underground Tanks'],
    ['Pumps', D.pumps.length + ' Dispensing Units'],
    ['Station ID', _t.id || 'demo'],
  ].map(([l, v]) => `<div class="flex-between" style="padding:10px 0;border-bottom:1px solid var(--border-light);font-size:13px">
    <span style="color:var(--text-3)">${l}</span><span class="fw-600" style="color:var(--text-1)">${v}</span>
  </div>`).join('');

  // Build subscription info card — always fetch fresh when viewing Settings
  if (APP.page === 'settings') {
    const _tid = APP.tenant?.id;
    if (_tid) {
      fetch('/api/public/subscription/' + encodeURIComponent(_tid))
        .then(r => r.json())
        .then(s => {
          if (JSON.stringify(s) !== JSON.stringify(window._subStatus)) {
            window._subStatus = s;
            window._subStatusAt = Date.now();
            if (APP.page === 'settings') {
              var el = document.getElementById('content');
              if (el) try { el.innerHTML = renderSettings(APP.data); } catch(e2) {}
            }
          }
        }).catch(() => {});
    }
  }
  const sub = window._subStatus;
  const subCard = sub ? (function() {
    var statusMap = {
      trial:    { col:'#60a5fa', icon:'⏱️', label:'Trial Period' },
      active:   { col:'var(--green)', icon:'✅', label:'Active Subscription' },
      grace:    { col:'var(--orange)', icon:'⚠️', label:'Grace Period' },
      expired:  { col:'var(--red)', icon:'🔒', label:'Expired' },
      suspended:{ col:'var(--text-3)', icon:'⏸️', label:'Suspended' },
    };
    var s = statusMap[sub.status] || statusMap.expired;
    var dateInfo = '';
    if (sub.status === 'trial') {
      var trialEnd = sub.trial_end ? new Date(sub.trial_end).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'}) : '—';
      var dLeft = sub.trial_days_left !== undefined ? sub.trial_days_left : (sub.days_left || 0);
      dateInfo = '<div style="margin-top:8px;font-size:12px;color:var(--text-2)">Trial ends: <strong>' + trialEnd + '</strong> · <span style="color:' + (dLeft <= 7 ? 'var(--orange)' : '#60a5fa') + '">' + dLeft + ' days remaining</span></div>';
    } else if (sub.sub_end) {
      var endDate = new Date(sub.sub_end).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'});
      var dLeft2 = sub.days_left !== null ? sub.days_left : 0;
      var planLabel = {monthly:'Monthly',quarterly:'Quarterly',halfyearly:'Half-Yearly',yearly:'Yearly'}[sub.plan] || sub.plan || '';
      dateInfo = '<div style="margin-top:8px;font-size:12px;color:var(--text-2)">Plan: <strong>' + planLabel + '</strong> · Valid until: <strong>' + endDate + '</strong>'
        + (dLeft2 !== null ? ' · <span style="color:' + (dLeft2 <= 7 ? 'var(--orange)' : 'var(--green)') + '">' + dLeft2 + ' days remaining</span>' : '') + '</div>';
    }
    return '<div class="card card-pad mb-16" style="border-left:3px solid ' + s.col + '">'
      + '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">'
      + '<span style="font-size:16px">' + s.icon + '</span>'
      + '<span style="font-weight:700;font-size:14px;color:' + s.col + '">' + s.label + '</span>'
      + '</div>'
      + dateInfo
      + (sub.is_read_only ? '<div style="margin-top:8px;padding:6px 10px;background:rgba(239,68,68,0.08);border-radius:6px;font-size:11px;color:var(--red)">🔒 Read-only mode active — contact your FuelBunk Pro admin to renew</div>' : '')
      + '</div>';
  })() : '';

  return `
    <div class="page-hdr"><h3>⚙️ Settings</h3></div>
    ${subCard}
    <div class="g g-auto gap-16 mb-24">
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">⛽ Fuel Prices</h4>
        ${priceCards}
        <button class="btn btn-accent btn-block mt-12" onclick="openPriceModal()">&#9881;&#65039; Update Selling Prices</button>
        <!-- Purchase price button removed - admin manages COGS separately -->
        ${(() => {
          const hist = (D.priceHistory || []).slice(0, 8);
          if (!hist.length) return '';
          return `<div style="margin-top:14px;border-top:1px solid var(--border-light);padding-top:10px">
            <div style="font-size:10px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">📋 Price Revision History</div>
            ${hist.map(h => `<div style="padding:5px 0;border-bottom:1px solid var(--border-light);font-size:11px">
              <div style="display:flex;justify-content:space-between">
                <span style="color:var(--text-2)">${h.date} ${h.time}</span>
                <span style="color:var(--text-3);font-size:10px">${sanitize(h.changedBy||'')}</span>
              </div>
              <div style="margin-top:2px">${(h.changes||[]).map(c => `<span style="color:var(--text-1);font-size:11px">${sanitize(getFuel(c.fuel).short||c.fuel)}: <span style="color:var(--red)">₹${c.oldPrice}</span> → <span style="color:var(--green)">₹${c.newPrice}</span></span>`).join(' · ')}</div>
            </div>`).join('')}
          </div>`;
        })()}
      </div>
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">🏢 Station Information</h4>
        ${info}
        <button class="btn btn-ghost btn-block mt-12" onclick="openChangeMyPasswordModal()" style="font-size:12px">🔑 Change My Password</button>
      </div>
    </div>
    <div class="g g-2 gap-16">
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">📱 UPI Payment Settings</h4>
        <div class="form-group">
          <label class="form-label">UPI VPA (Your payment address)</label>
          <input class="form-input" id="upiVPA" value="${D.upiVPA || ''}" placeholder="e.g. station@okaxis" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">Your UPI ID — customers pay to this</div>
        </div>
        <div class="form-group">
          <label class="form-label">Station / Merchant Name</label>
          <input class="form-input" id="upiName" value="${D.upiName || APP.tenant?.name || ''}" placeholder="e.g. Sri Lakshmi Fuel Station" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">This name appears on all reports and receipts</div>
        </div>
        <div class="form-group">
          <label class="form-label">Station Code (for reports)</label>
          <input class="form-input" id="stationCode" value="${D.stationCode || ''}" placeholder="e.g. KA/TUM/FSL/2024/0142" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">OMC assigned station code — printed on DSR</div>
        </div>
        <div class="form-group">
          <label class="form-label">Oil Company (OMC) Name</label>
          <input class="form-input" id="omcName" value="${D.omcName || ''}" placeholder="e.g. Bharat Petroleum Corporation Ltd." />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">Printed on report footer</div>
        </div>
        <div class="form-group" style="margin-top:16px;padding-top:16px;border-top:1px solid var(--border-light)">
          <label class="form-label" style="display:flex;align-items:center;gap:6px">
            <span>📱 WhatsApp Number</span>
            <span style="font-size:10px;background:rgba(34,197,94,0.12);color:var(--green);padding:1px 6px;border-radius:4px;font-weight:700">FREE</span>
          </label>
          <div style="display:flex;gap:8px">
          <input class="form-input" id="waPhoneCC" type="tel" inputmode="numeric" maxlength="4" placeholder="+91" value="${D.waPhoneCC || '+91'}" style="width:72px;flex-shrink:0" />
          <input class="form-input" id="waPhone" type="tel" inputmode="numeric" maxlength="10" minlength="10" oninput="this.value=this.value.replace(/[^0-9]/g,'')" placeholder="10-digit number" value="${D.waPhone || ''}" style="flex:1" />
        </div>
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">Your WhatsApp number — receives low-tank, mismatch & daily summary alerts</div>
        </div>
        <div class="form-group">
          <label class="form-label" style="display:flex;align-items:center;gap:6px">
            CallMeBot API Key
            <a href="https://www.callmebot.com/blog/free-api-whatsapp-messages/" target="_blank" style="font-size:10px;color:var(--accent-light)">How to get →</a>
          </label>
          <input class="form-input" id="waApiKey" value="${D.waApiKey || ''}" placeholder="Paste API key from CallMeBot" autocomplete="off" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">
            <strong>Free silent delivery:</strong> Send <em>"I allow callmebot to send me messages"</em> to <strong>+34 644 21 65 38</strong> on WhatsApp → get API key → paste here.
            Without key, alerts open WhatsApp with message pre-filled (you tap Send).
          </div>
        </div>
        <div class="form-group">
          <label class="form-label" style="display:flex;align-items:center;gap:6px">
            Razorpay Key ID <span style="font-size:10px;background:rgba(59,130,246,0.12);color:var(--blue);padding:1px 6px;border-radius:4px;font-weight:700">AUTO-CONFIRM</span>
          </label>
          <input class="form-input" id="rzpKey" value="${D.razorpayKey || ''}" placeholder="rzp_live_XXXXXXXXXX" autocomplete="off" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">
            Get from <a href="https://dashboard.razorpay.com/app/keys" target="_blank" style="color:var(--accent-light)">dashboard.razorpay.com → Settings → API Keys</a>. 
            Enables auto-confirmation of payments (2% fee per txn).
          </div>
        </div>
        <button class="btn btn-accent btn-block" onclick="saveUPISettings()">💾 Save UPI Settings</button>
        <div id="upiQRPreview" class="text-center mt-16"></div>
      </div>
      <div class="card card-pad">
        <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">📱 WhatsApp Alerts</h4>
        ${(() => {
          const phone = D.waPhone || '';
          const apiKey = D.waApiKey || '';
          const mode = apiKey ? 'CallMeBot (silent)' : phone ? 'wa.me (tap to send)' : 'Not configured';
          const modeColor = apiKey ? 'var(--green)' : phone ? 'var(--accent-light)' : 'var(--text-3)';
          const modeBg = apiKey ? 'rgba(34,197,94,0.08)' : phone ? 'rgba(212,148,15,0.08)' : 'var(--bg-0)';

          const alertRows = [
            { label: '⚠️ Low Tank', desc: 'When any tank < 20%', active: !!phone },
            { label: '🚨 Meter Mismatch', desc: 'When variance ≥ 0.5L flagged', active: !!phone },
            { label: '📊 Daily Summary', desc: 'Send from Reports page manually', active: !!phone },
            { label: '💳 Credit Reminder', desc: 'From Credit Mgmt customer card', active: !!phone },
            { label: '🧾 Credit Bill', desc: 'After credit sale (customer phone)', active: !!phone },
          ].map(r => `<div class="flex-between" style="padding:8px 0;border-bottom:1px solid var(--border-light)">
            <div><div class="fw-600" style="font-size:12px;color:var(--text-1)">${r.label}</div><div style="font-size:10px;color:var(--text-3)">${r.desc}</div></div>
            ${r.active ? badge('ACTIVE','badge-green') : badge('OFF','badge-red')}
          </div>`).join('');

          const recentLog = (window._waLog || []).slice(0,5);
          const logRows = recentLog.length > 0
            ? recentLog.map(e => `<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--border-light)">
                <div style="font-size:10px;color:var(--text-3);flex:1">${e.type}</div>
                <div style="font-size:10px;color:var(--text-3)">${e.ts}</div>
                <div style="font-size:10px;margin-left:8px">${badge(e.status,'badge-blue')}</div>
              </div>`).join('')
            : '<div style="font-size:11px;color:var(--text-3);padding:8px 0">No alerts sent yet</div>';

          return `
            <div style="padding:12px 14px;background:${modeBg};border-radius:8px;margin-bottom:14px;border:1px solid ${apiKey?'rgba(34,197,94,0.2)':phone?'rgba(212,148,15,0.2)':'var(--border)'}">
              <div class="fw-700" style="font-size:13px;color:${modeColor}">${apiKey?'✅':'📱'} ${mode}</div>
              ${phone ? `<div style="font-size:11px;color:var(--text-3);margin-top:2px">→ +${phone}</div>` : `<div style="font-size:11px;color:var(--text-3);margin-top:2px">Add WhatsApp number above to enable alerts</div>`}
            </div>
            ${alertRows}
            <button class="btn btn-accent btn-block mt-12" onclick="wa_sendTest()">📱 Send Test Message</button>
            <h4 class="mt-16 mb-10 fw-700" style="color:var(--text-0);font-size:12px">Recent Alerts</h4>
            ${logRows}
          `;
        })()}

        <h4 class="mt-20 mb-14 fw-700" style="color:var(--text-0);font-size:13px">🔔 Push Notifications</h4>
        <div class="flex-between mb-10" style="padding:10px;background:var(--bg-0);border-radius:var(--radius-sm)">
          <div><div class="fw-600" style="font-size:12px;color:var(--text-0)">Browser Push</div><div style="font-size:11px;color:var(--text-3)">Low tanks & credit alerts</div></div>
          <button class="btn btn-ghost btn-sm" onclick="enableNotifications()">Enable</button>
        </div>
        <h4 class="mt-16 mb-14 fw-700" style="color:var(--text-0);font-size:13px">💾 Data Management</h4>
        <div class="flex" style="gap:8px">
          <button class="btn btn-ghost" style="flex:1" onclick="exportAllData()">↓ Export All Data</button>
          <button class="btn btn-ghost" style="flex:1;border-color:rgba(239,68,68,0.25);color:var(--red)" onclick="confirmResetData()">⚠ Reset Data</button>
        </div>
      </div>
    </div>

    <!-- Fuel Tax Rates Card -->
    <div class="card card-pad mt-16">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px">
        <h4 class="fw-700" style="color:var(--text-0);font-size:13px">🧾 Fuel Tax Rates (ZLST / VAT / GST)</h4>
        <button class="btn btn-accent btn-sm" onclick="openAddTaxRateModal()">＋ Add Tax</button>
      </div>
      ${(D.fuelTaxRates && D.fuelTaxRates.length > 0) ? `
      <div style="overflow-x:auto">
        <table style="width:100%;border-collapse:collapse;font-size:13px">
          <thead>
            <tr style="background:var(--bg-0);border-bottom:2px solid var(--border)">
              <th style="padding:8px 12px;text-align:left;color:var(--text-3);font-size:11px;font-weight:700;text-transform:uppercase">Fuel Type</th>
              <th style="padding:8px 12px;text-align:left;color:var(--text-3);font-size:11px;font-weight:700;text-transform:uppercase">Tax Name</th>
              <th style="padding:8px 12px;text-align:right;color:var(--text-3);font-size:11px;font-weight:700;text-transform:uppercase">Rate %</th>
              <th style="padding:8px 12px;text-align:center;color:var(--text-3);font-size:11px;font-weight:700;text-transform:uppercase">Actions</th>
            </tr>
          </thead>
          <tbody>
            ${D.fuelTaxRates.map((t, idx) => {
              const fi = getFuel(t.fuelType) || { name: t.fuelType, color: 'var(--text-2)' };
              return `<tr style="border-bottom:1px solid var(--border-light)">
                <td style="padding:10px 12px"><span style="font-weight:700;color:${fi.color}">${fi.name || t.fuelType}</span></td>
                <td style="padding:10px 12px;color:var(--text-1);font-weight:600">${sanitize(t.taxName)}</td>
                <td style="padding:10px 12px;text-align:right;font-family:var(--mono);font-weight:800;color:var(--accent-light)">${t.rate.toFixed(2)}%</td>
                <td style="padding:10px 12px;text-align:center">
                  <button class="btn btn-ghost btn-sm" onclick="openEditTaxRateModal(${idx})" style="margin-right:4px">✏️ Edit</button>
                  <button class="btn btn-sm" style="background:rgba(239,68,68,0.08);color:var(--red);border:none" onclick="deleteTaxRate(${idx})">🗑</button>
                </td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>
      </div>
      <div style="margin-top:10px;padding:8px 12px;background:rgba(212,148,15,0.06);border-radius:6px;font-size:11px;color:var(--text-3)">
        💡 These rates auto-fill when you record a fuel purchase. You can still edit per invoice.
      </div>
      ` : `<div style="padding:20px;text-align:center;color:var(--text-3);font-size:13px">No tax rates configured. Click <strong>＋ Add Tax</strong> to set up ZLST/VAT rates.</div>`}
    </div>

    <!-- Tenant Admin Users Management -->
    <div class="card card-pad mt-16">
      <h4 class="mb-16 fw-700" style="color:var(--text-0);font-size:13px">👤 Admin Users — ${sanitize((_t.name||'Station'))}</h4>
      <div style="margin-bottom:12px">
        ${((_t.adminUsers||[]).map((u,i) => `
          <div style="display:flex;align-items:center;justify-content:space-between;padding:10px 0;border-bottom:1px solid var(--border-light)">
            <div>
              <div class="fw-700" style="color:var(--text-0);font-size:13px">${sanitize(u.name)}</div>
              <div style="font-size:11px;color:var(--text-3)">${sanitize(u.username)} · ${badge(u.role,'badge-accent')}</div>
            </div>
            <button class="btn btn-ghost btn-sm" onclick="openChangeAdminPassModal(${i})">🔑 Change Password</button>
          </div>`).join('')) || '<div style="color:var(--text-3);font-size:13px">No admin users found</div>'}
      </div>
      <button class="btn btn-ghost btn-sm btn-block" onclick="openAddAdminUserModal()">+ Add Admin User</button>
    </div>

    <!-- Switch Station -->
    <div class="card card-pad mt-16" style="text-align:center">
      <div style="font-size:11px;color:var(--text-3);margin-bottom:12px">You are managing: <strong style="color:var(--accent-light)">${sanitize(_t.name||'Demo')}</strong></div>
      <button class="btn btn-ghost btn-block" onclick="mt_switchStation()">🏪 Switch to a Different Station</button>
    </div>

    <!-- User Management (Role-Based Access) Card -->
    <div class="g g-2 gap-16 mt-16">
      <div class="card card-pad">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px">
          <h4 class="fw-700" style="color:var(--text-0);font-size:13px">🔒 User Management & Roles</h4>
          ${rbac_can('add_admin_user') ? `<button class="btn btn-accent btn-sm" onclick="openAddAdminUserModal()">＋ Add User</button>` : ''}
        </div>
        <div style="margin-bottom:14px;padding:10px;background:var(--bg-0);border-radius:8px;font-size:11px;color:var(--text-3)">
          <div class="fw-700" style="color:var(--text-1);margin-bottom:6px">Role Permissions</div>
          ${[
            { role:'Owner',      color:'var(--accent-light)', desc:'Full access — all pages, all actions' },
            { role:'Manager',    color:'var(--blue)',          desc:'Full operational access — Staff, Payroll, Lubes & Finance. Cannot reset data or manage admin users' },
            { role:'Accountant', color:'#a855f7',             desc:'Finance & reports only — no operations' },
            { role:'Cashier',    color:'var(--green)',         desc:'Dashboard, tanks, pumps, sales, lubes only' },
          ].map(r=>`<div class="flex-between" style="padding:5px 0;border-bottom:1px solid var(--border-light)">
            <span>${badge(r.role, r.role==='Owner'?'badge-accent':r.role==='Manager'?'badge-blue':r.role==='Accountant'?'badge-purple':'badge-green')}</span>
            <span style="font-size:11px;color:var(--text-3);text-align:right;max-width:200px">${r.desc}</span>
          </div>`).join('')}
        </div>
        ${(() => {
          const admins = APP.tenant?.adminUsers || [];
          if (!admins.length) return '<div style="text-align:center;padding:20px;color:var(--text-3);font-size:12px">No admin users configured</div>';
          return admins.map((u,i) => `<div class="flex-between" style="padding:9px 0;border-bottom:1px solid var(--border-light)">
            <div>
              <div class="fw-700" style="font-size:13px;color:var(--text-0)">${sanitize(u.name||u.username)}</div>
              <div style="font-size:11px;color:var(--text-3)">@${sanitize(u.username)}</div>
            </div>
            <div style="display:flex;align-items:center;gap:8px">
              ${roleBadge(u.role||'Manager')}
              ${(rbac_can('add_admin_user') && APP.adminUser?.id !== u.id) ? `<button class="btn btn-ghost btn-sm" onclick="openEditAdminUserRoleModal(${i})">✏️</button>` : ''}
            </div>
          </div>`).join('');
        })()}
      </div>

      <!-- Loyalty Points Settings Card -->
      <div class="card card-pad">
        <h4 class="fw-700 mb-16" style="color:var(--text-0);font-size:13px">⭐ Loyalty Points Settings</h4>
        <div style="padding:12px;background:rgba(212,148,15,0.07);border-radius:8px;margin-bottom:14px;font-size:12px;color:var(--text-2)">
          Earn points on every credit sale. Customers can redeem points for discounts on outstanding balance.
        </div>
        <div class="form-group">
          <label class="form-label">Earn Rate (points per ₹100 spent)</label>
          <input class="form-input" type="number" id="ly_earnRate" value="${D.loyaltyEarnRate||1}" min="1" max="10" step="1" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">Default: 1 point per ₹100</div>
        </div>
        <div class="form-group">
          <label class="form-label">Redemption Rate (₹ per 100 points)</label>
          <input class="form-input" type="number" id="ly_redeemRate" value="${D.loyaltyRedeemRate||50}" min="10" max="200" step="10" />
          <div style="font-size:11px;color:var(--text-3);margin-top:3px">Default: ₹50 per 100 points</div>
        </div>
        <div class="form-group">
          <label class="form-label">Minimum Points to Redeem</label>
          <input class="form-input" type="number" id="ly_minRedeem" value="${D.loyaltyMinRedeem||100}" min="100" step="100" />
        </div>
        <button class="btn btn-accent btn-block mt-4" onclick="saveLoyaltySettings()">💾 Save Loyalty Settings</button>
        <div style="margin-top:14px;padding:10px;background:var(--bg-0);border-radius:8px">
          <div class="fw-700" style="font-size:11px;color:var(--text-3);margin-bottom:6px">CURRENT STATS</div>
          ${(() => {
            const totalPts = (D.creditCustomers||[]).reduce((a,c)=>a+(c.loyaltyPoints||0),0);
            const customersWithPts = (D.creditCustomers||[]).filter(c=>(c.loyaltyPoints||0)>0).length;
            return `<div class="flex-between" style="font-size:12px;padding:4px 0"><span style="color:var(--text-3)">Total Points Issued</span><span class="mono fw-700 " style="color:var(--accent-light)">⭐ ${totalPts.toLocaleString('en-IN')}</span></div>
            <div class="flex-between" style="font-size:12px;padding:4px 0"><span style="color:var(--text-3)">Customers with Points</span><span class="mono fw-700">${customersWithPts}</span></div>
            <div class="flex-between" style="font-size:12px;padding:4px 0"><span style="color:var(--text-3)">Redeemable Value</span><span class="mono fw-700" style="color:var(--green)">${cur(Math.floor(totalPts/100)*(D.loyaltyRedeemRate||50))}</span></div>`;
          })()}
        </div>
      </div>
    </div>

    <!-- ── Day-Lock: Close the Books ─────────────────────────────────────── -->
    <div class="card card-pad mt-16" id="dayLockCard">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px">
        <h4 class="fw-700" style="color:var(--text-0);font-size:13px">🔒 Day-Lock — Close the Books</h4>
        ${rbac_can('close_books') ? '' : `<span style="font-size:11px;color:var(--text-3)">Owner only</span>`}
      </div>
      <p style="font-size:12px;color:var(--text-3);margin-bottom:14px">
        Locking a day prevents any edits to sales, expenses, purchases, dip readings, and credit transactions for that date.
        Required before GST filing and audit. Unlock is available only to the <strong>Owner</strong> role.
      </p>
      ${(() => {
        const todayStr = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
        const lockedDays = Object.keys(D.dayLocks || {}).filter(k => (D.dayLocks||{})[k]).sort().reverse().slice(0, 5);
        const todayLocked = (D.dayLocks||{})[todayStr];
        const canLock = rbac_can('close_books');
        return `
          <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px">
            <div style="flex:1;min-width:160px;padding:14px;background:${todayLocked?'rgba(34,197,94,0.07)':'rgba(212,148,15,0.07)'};border:1px solid ${todayLocked?'rgba(34,197,94,0.25)':'rgba(212,148,15,0.25)'};border-radius:10px;text-align:center">
              <div style="font-size:22px;margin-bottom:4px">${todayLocked?'✅':'📖'}</div>
              <div class="fw-700" style="font-size:13px;color:var(--text-0)">Today — ${todayStr}</div>
              <div style="font-size:11px;color:${todayLocked?'var(--green)':'var(--accent-light)'};font-weight:700;margin-top:2px">${todayLocked?'LOCKED':'OPEN'}</div>
            </div>
            <div style="flex:1;min-width:160px;display:flex;flex-direction:column;gap:8px;justify-content:center">
              ${canLock ? `
                ${!todayLocked ? `<button class="btn btn-accent btn-block" onclick="closeDayLock('${todayStr}')">🔒 Close Today's Books</button>` : ''}
                ${todayLocked ? `<button class="btn btn-ghost btn-block" style="border-color:rgba(239,68,68,0.3);color:var(--red)" onclick="openDayLock('${todayStr}')">🔓 Unlock Today</button>` : ''}
                <button class="btn btn-ghost btn-block btn-sm" onclick="openDayLockPicker()">📅 Lock/Unlock Specific Date</button>
              ` : `<div style="font-size:12px;color:var(--text-3);text-align:center;padding:12px">Switch to <strong>Owner</strong> role to lock/unlock books</div>`}
            </div>
          </div>
          ${lockedDays.length > 0 ? `
          <div style="margin-top:4px">
            <div style="font-size:10px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Recent Locked Days</div>
            ${lockedDays.map(d => `
              <div class="flex-between" style="padding:6px 0;border-bottom:1px solid var(--border-light);font-size:12px">
                <span class="mono" style="color:var(--text-1)">${d}</span>
                <div style="display:flex;align-items:center;gap:8px">
                  ${badge('LOCKED','badge-green')}
                  ${canLock ? `<button class="btn btn-ghost btn-sm" style="font-size:10px;padding:2px 8px;color:var(--red)" onclick="openDayLock('${d}')">Unlock</button>` : ''}
                </div>
              </div>`).join('')}
          </div>` : ''}
        `;
      })()}
    </div>

    <div class="card card-pad mt-16" style="border:1px solid rgba(212,148,15,0.25);background:rgba(212,148,15,0.04)">
      <h4 class="mb-14 fw-700" style="color:var(--text-0);font-size:13px">🗺️ Suggested Build Order — Roadmap</h4>
      <div style="display:flex;flex-direction:column;gap:8px">
        ${[
          { tier:'✅ Live', color:'var(--green)', items:['Fuel Tax Rates (ZLST/GST)', 'Purchase density + IS-1460 check', 'Payroll Run + bulk calculate', 'Salary Advances + EMI plan', 'Employee Performance leaderboard', 'Vehicle-wise Fuel Report', 'Bank Reconciliation (Cash/UPI/Card)', 'Hourly Sales Pattern chart', 'Analytics page (Vehicle / Density / Bank Recon)', '📟 Nozzle Meter Log — shift open/close with variance flagging', '💬 WhatsApp Alerts — wa.me + CallMeBot free API', '🛢️ Lubes & Products — catalogue, HSN, GST%, stock, sales, restock', '📤 Exports — Daily CSV/Print, Payslips, Credit Statements, Lubes Report', '🧾 GST Module — GSTR-1 JSON, Tally XML, HSN-wise summary, GSTR-3B', '🔒 Day-Lock — Close books & prevent retroactive edits', '🔒 Role-based access — Owner/Manager/Accountant/Cashier', '📊 Advanced Analytics — Monthly Trends, Fuel P&L, Top Customers', '⭐ Loyalty Points — earn on credit sales, redeem for discounts', '📱 PWA Full Offline — admin add sales, edit tanks, queue + sync on reconnect', '🏢 Multi-station Compare — revenue, litres, tanks across all stations', '🤖 AI Insights — 9-rule anomaly engine with severity-ranked alerts'] },
          { tier:'🔜 Next', color:'var(--accent-light)', items:['📲 MSG91 SMS Alerts — low stock & day-close summary', '📋 Leave Request & Approval Workflow', '📦 Supplier PO / Indent Workflow', '🧾 E-Invoice (IRN) Generation'] },
          { tier:'🔮 Later', color:'#a855f7', items:['Claude API narrative insights — AI explains anomalies in plain language', 'Dexie.js deep offline — full IndexedDB sync', 'PDF Payslips & PO generation', 'Khata-style mobile app'] },
        ].map(section => `
          <div style="margin-bottom:4px">
            <div class="fw-700" style="color:${section.color};font-size:11px;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:6px">${section.tier}</div>
            <div style="display:flex;flex-wrap:wrap;gap:5px">
              ${section.items.map(item => `<span style="font-size:11px;padding:3px 10px;border-radius:20px;background:var(--bg-0);border:1px solid var(--border);color:var(--text-2)">${item}</span>`).join('')}
            </div>
          </div>
        `).join('')}
      </div>
    </div>
  `;
}

