// ── Employee Balance Modal — admin review & settle ────────────
function openEmpBalanceModal(empId) {
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) return;

  const pending = (emp.balanceEntries || []).filter(b => b.status === 'pending');
  if (!pending.length) { toast('No pending balances', 'info'); return; }

  const totalLiters = pending.reduce((a, b) => a + b.totalDiffLiters, 0);
  const totalAmount = pending.reduce((a, b) => a + b.totalDiffAmount, 0);

  const entryRows = pending.map((b, idx) => {
    const rows = b.entries.map(e =>
      `<tr style="font-size:11px">
        <td style="padding:5px 8px;color:var(--text-3)">${e.pump} · N${e.nozzle}</td>
        <td style="padding:5px 8px"><span style="font-size:10px;font-weight:700;color:var(--accent-light)">${e.fuelName}</span></td>
        <td style="padding:5px 8px;text-align:right;font-family:var(--mono)">${fmt(e.meterSold)} L</td>
        <td style="padding:5px 8px;text-align:right;font-family:var(--mono)">${fmt(e.salesSold)} L</td>
        <td style="padding:5px 8px;text-align:right;font-family:var(--mono);color:var(--red);font-weight:700">${fmt(Math.abs(e.diffLiters))} L</td>
        <td style="padding:5px 8px;text-align:right;font-family:var(--mono);color:var(--red);font-weight:700">${cur(e.diffAmount)}</td>
      </tr>`
    ).join('');
    return `<div style="background:var(--bg-0);border:1px solid var(--border);border-radius:8px;margin-bottom:10px;overflow:hidden">
      <div style="padding:10px 14px;background:rgba(239,68,68,0.05);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
        <div>
          <span style="font-size:12px;font-weight:700;color:var(--text-0)">📅 ${b.date}</span>
          ${b.shift ? `<span style="font-size:11px;color:var(--text-3);margin-left:8px">${b.shift} Shift</span>` : ''}
        </div>
        <div style="text-align:right">
          <div style="font-size:13px;font-weight:800;color:var(--red)">${cur(b.totalDiffAmount)}</div>
          <div style="font-size:10px;color:var(--text-3)">${fmt(b.totalDiffLiters)} L unaccounted</div>
        </div>
      </div>
      <table style="width:100%;border-collapse:collapse">
        <thead><tr style="background:var(--bg-2)">
          <th style="padding:5px 8px;text-align:left;font-size:9px;color:var(--text-3);font-weight:700;text-transform:uppercase">Nozzle</th>
          <th style="padding:5px 8px;text-align:left;font-size:9px;color:var(--text-3);font-weight:700;text-transform:uppercase">Fuel</th>
          <th style="padding:5px 8px;text-align:right;font-size:9px;color:var(--text-3);font-weight:700;text-transform:uppercase">Meter</th>
          <th style="padding:5px 8px;text-align:right;font-size:9px;color:var(--text-3);font-weight:700;text-transform:uppercase">Sales</th>
          <th style="padding:5px 8px;text-align:right;font-size:9px;color:var(--text-3);font-weight:700;text-transform:uppercase">Diff (L)</th>
          <th style="padding:5px 8px;text-align:right;font-size:9px;color:var(--text-3);font-weight:700;text-transform:uppercase">Amount</th>
        </tr></thead>
        <tbody>${rows}</tbody>
      </table>
      <div style="padding:8px 14px;display:flex;gap:8px;justify-content:flex-end;border-top:1px solid var(--border)">
        <button class="btn btn-sm" style="background:rgba(34,197,94,0.1);color:var(--green);border:1px solid rgba(34,197,94,0.25);font-size:11px"
          onclick="settleEmpBalance(${empId}, ${b.id}, 'cash', 'Settled in cash')">💵 Settled (Cash)</button>
        <button class="btn btn-sm" style="background:rgba(239,68,68,0.08);color:var(--red);border:1px solid rgba(239,68,68,0.2);font-size:11px"
          onclick="settleEmpBalance(${empId}, ${b.id}, 'deduct', 'Deducted from salary')">✂️ Deduct Salary</button>
        <button class="btn btn-sm" style="background:rgba(100,100,100,0.08);color:var(--text-2);border:1px solid var(--border);font-size:11px"
          onclick="settleEmpBalance(${empId}, ${b.id}, 'waived', 'Waived by manager')">🙏 Waive</button>
      </div>
    </div>`;
  }).join('');

  openModal(`⚠️ Pending Balance — ${sanitize(emp.name)}`,
    `<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px">
       <div style="background:rgba(239,68,68,0.07);border:1px solid rgba(239,68,68,0.2);border-radius:10px;padding:14px;text-align:center">
         <div style="font-size:10px;font-weight:700;color:var(--red);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:4px">Total Balance</div>
         <div style="font-size:26px;font-weight:900;color:var(--red);font-family:var(--mono)">${cur(totalAmount)}</div>
       </div>
       <div style="background:rgba(239,68,68,0.07);border:1px solid rgba(239,68,68,0.2);border-radius:10px;padding:14px;text-align:center">
         <div style="font-size:10px;font-weight:700;color:var(--red);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:4px">Unaccounted</div>
         <div style="font-size:26px;font-weight:900;color:var(--text-0);font-family:var(--mono)">${fmt(totalLiters)} L</div>
       </div>
     </div>
     <div style="font-size:12px;color:var(--text-3);margin-bottom:14px">
       These differences were accepted during shift submission. Choose how to settle each entry.
     </div>
     ${entryRows}`,
    `<button class="btn btn-ghost" onclick="closeModal()">Close</button>
     <button class="btn btn-accent" onclick="settleAllEmpBalance(${empId})">✅ Settle All (Cash)</button>`
  );
}

async function settleEmpBalance(empId, balanceId, method, note) {
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp || !emp.balanceEntries) return;

  const entry = emp.balanceEntries.find(b => b.id === balanceId);
  if (!entry || entry.status !== 'pending') return;

  entry.status    = 'settled';
  entry.settledAt = today() + ' ' + now();
  entry.settledBy = APP.data?.adminUser?.name || 'Admin';
  entry.method    = method;
  entry.note      = note;

  emp.pendingBalance = Math.max(0, (emp.pendingBalance || 0) - entry.totalDiffAmount);
  await db.put('employees', emp);
  APP.data.employees = APP.data.employees.map(e => e.id === empId ? emp : e);
  auditLog('emp_balance_settle', { empId, empName: emp.name, balanceId, method, amount: entry.totalDiffAmount });
  closeModal();
  toast(`✅ Balance of ${cur(entry.totalDiffAmount)} settled (${note})`, 'success');
  renderPage();
}

async function settleAllEmpBalance(empId) {
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp || !emp.balanceEntries) return;

  const pending = emp.balanceEntries.filter(b => b.status === 'pending');
  const totalAmt = pending.reduce((a, b) => a + b.totalDiffAmount, 0);
  pending.forEach(b => {
    b.status    = 'settled';
    b.settledAt = today() + ' ' + now();
    b.settledBy = APP.data?.adminUser?.name || 'Admin';
    b.method    = 'cash';
    b.note      = 'Settled all in cash';
  });
  emp.pendingBalance = 0;
  await db.put('employees', emp);
  APP.data.employees = APP.data.employees.map(e => e.id === empId ? emp : e);
  auditLog('emp_balance_settle_all', { empId, empName: emp.name, totalAmt });
  closeModal();
  toast(`✅ All balances cleared for ${sanitize(emp.name)} — ${cur(totalAmt)} settled`, 'success');
  renderPage();
}

window.openEmpBalanceModal  = openEmpBalanceModal;
window.settleEmpBalance     = settleEmpBalance;
window.settleAllEmpBalance  = settleAllEmpBalance;

window.renderStaff = renderStaff;

// ── SHIFT ROSTER ─────────────────────────────────────────────
function renderRoster(D) {
  const today = new Date();
  // Build a 7-day week view — offset controlled by rosterNavWeek()
  const offset = window._rosterWeekOffset || 0;
  const dayOfWeek = today.getDay() === 0 ? 6 : today.getDay() - 1;
  const weekStart = new Date(today);
  weekStart.setDate(today.getDate() - dayOfWeek + offset * 7);
  weekStart.setHours(0,0,0,0);
  const weekDays = Array.from({length: 7}, (_, i) => {
    const d = new Date(weekStart); d.setDate(weekStart.getDate() + i);
    return d;
  });
  const fmtDate = d => d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  const fmtDay = d => d.toLocaleDateString('en-IN', {weekday:'short'});
  const fmtNum = d => d.getDate();
  const todayStr = fmtDate(today);

  // Past week = the entire week ends before today's Monday
  const thisMonday = new Date(today); thisMonday.setDate(today.getDate() - dayOfWeek); thisMonday.setHours(0,0,0,0);
  const isPastWeek = weekStart < thisMonday;

  const SHIFT_ORDER_ROSTER = ['morning','noon','afternoon','evening','night'];
  const rawShifts = D.shifts && D.shifts.length ? D.shifts : [{name:'Morning',start:'06:00',end:'14:00'},{name:'Afternoon',start:'14:00',end:'22:00'},{name:'Night',start:'22:00',end:'06:00'}];
  const shifts = [...rawShifts].sort((a, b) => {
    const ai = SHIFT_ORDER_ROSTER.findIndex(k => (a.name||'').toLowerCase().includes(k));
    const bi = SHIFT_ORDER_ROSTER.findIndex(k => (b.name||'').toLowerCase().includes(k));
    return (ai < 0 ? 99 : ai) - (bi < 0 ? 99 : bi);
  });
  const emps = D.employees || [];

  // Load saved roster from settings (in-memory for now, persisted via db.setSetting)
  if (!window._rosterData) window._rosterData = {};
  const roster = window._rosterData;

  const shiftColors = ['rgba(212,148,15,0.12)','rgba(59,130,246,0.12)','rgba(139,92,246,0.12)','rgba(34,197,94,0.1)'];
  const shiftBorderColors = ['var(--accent)','#3b82f6','#8b5cf6','#22c55e'];

  // Build week header
  const dayHeaders = weekDays.map(d => {
    const isToday = fmtDate(d) === todayStr;
    const isPast  = fmtDate(d) < todayStr;
    return `<th style="text-align:center;padding:8px 4px;min-width:90px;${isToday?'color:var(--accent-light);font-weight:800':isPast?'opacity:0.4':''}">
      <div style="font-size:11px;font-weight:700;text-transform:uppercase">${fmtDay(d)}</div>
      <div style="font-size:18px;font-weight:800;margin-top:2px${isToday?';color:var(--accent)':''}">${fmtNum(d)}</div>
    </th>`;
  }).join('');

  // Build rows — one per shift
  const shiftRows = shifts.map((shift, si) => {
    const cells = weekDays.map(d => {
      const dateStr = fmtDate(d);
      const key = dateStr + '_' + shift.name;
      const assigned = roster[key] || [];
      const isToday = dateStr === todayStr;
      const isPastDay = dateStr < todayStr; // individual day is before today
      const isReadOnly = isPastWeek || isPastDay;
      const assignedEmps = assigned.map(id => emps.find(e => String(e.id) === String(id))).filter(Boolean);
      // Past days/weeks: read-only chip (no remove button). Current/future: interactive with ✕
      const empChips = assignedEmps.map(e => isReadOnly
        ? `<div style="display:flex;align-items:center;gap:5px;background:var(--bg-1);border:1px solid var(--border-light);border-radius:6px;padding:4px 7px;margin-bottom:3px;opacity:0.72;cursor:default">
            <span style="width:20px;height:20px;border-radius:5px;background:${empColor(e)};display:grid;place-items:center;color:#fff;font-size:8px;font-weight:800;flex-shrink:0">${empInitials(e.name)}</span>
            <span style="font-size:10px;font-weight:700;color:var(--text-1)">${sanitize(e.name)}</span>
          </div>`
        : `<div style="display:flex;align-items:center;gap:5px;background:var(--bg-2);border:1px solid var(--border-light);border-radius:6px;padding:4px 7px;margin-bottom:3px;cursor:pointer"
            title="Click to remove ${sanitize(e.name)}"
            onclick="rosterUnassign('${dateStr}','${shift.name}',${e.id})">
            <span style="width:20px;height:20px;border-radius:5px;background:${empColor(e)};display:grid;place-items:center;color:#fff;font-size:8px;font-weight:800;flex-shrink:0">${empInitials(e.name)}</span>
            <span style="font-size:10px;font-weight:700;color:var(--text-0)">${sanitize(e.name)}</span>
            <span style="margin-left:auto;color:var(--red);font-size:10px;line-height:1;opacity:0.7">✕</span>
          </div>`
      ).join('');
      // Single dropdown replaces per-employee add-buttons
      // Only show employees whose allocated shift matches this row (e.shift is comma-separated)
      const shiftMatch = emps.filter(e => {
        const sh = (e.shift||'').trim();
        if (!sh) return true; // No shift assigned — show in all shifts
        const empShifts = sh.split(',').map(s => s.trim().toLowerCase());
        return empShifts.includes(shift.name.toLowerCase()) || empShifts.includes(shift.name.trim().toLowerCase());
      });
      const unassigned = shiftMatch.filter(e => !assigned.includes(String(e.id)));
      const noEligible = shiftMatch.length === 0;
      const allAssigned = shiftMatch.length > 0 && unassigned.length === 0;
      const addDropdown = isReadOnly ? '' : noEligible ? '' : allAssigned
        ? "<div style='font-size:10px;color:var(--text-3);margin-top:4px;text-align:center'>All assigned</div>"
        :
        `<select style="margin-top:${assignedEmps.length?'5px':'0'};width:100%;background:var(--bg-1);border:1px dashed var(--border);border-radius:6px;padding:4px 6px;color:var(--text-3);font-size:11px;font-family:var(--font);cursor:pointer"
          onchange="if(this.value){rosterAssign('${dateStr}','${shift.name}',this.value);this.value=''}">
          <option value="">+ Assign</option>
          ${unassigned.map(e => `<option value="${e.id}">${sanitize(e.name)}</option>`).join('')}
        </select>`;
      const noStaffHint = !isReadOnly && noEligible
        ? "<div style='font-size:10px;color:var(--text-3);text-align:center;padding:6px 0;opacity:0.5'>No staff</div>"
        : '';
      return `<td style="vertical-align:top;padding:6px;background:${isToday?'rgba(212,148,15,0.04)':'transparent'};border-left:1px solid var(--border-light)">
        ${empChips}${addDropdown}${noStaffHint}
      </td>`;
    }).join('');

    return `<tr>
      <td style="padding:10px 12px;white-space:nowrap;border-right:2px solid ${shiftBorderColors[si%shiftBorderColors.length]};background:${shiftColors[si%shiftColors.length]}">
        <div style="font-size:12px;font-weight:800;color:var(--text-0)">${sanitize(shift.name)}</div>
        <div style="font-size:10px;color:var(--text-3)">${sanitize(shift.start||'')}–${sanitize(shift.end||'')}</div>
      </td>
      ${cells}
    </tr>`;
  }).join('');

  // Navigation buttons
  const prevWeek = new Date(weekStart); prevWeek.setDate(prevWeek.getDate()-7);
  const nextWeek = new Date(weekStart); nextWeek.setDate(nextWeek.getDate()+7);

  return `
    <div class="page-hdr"><h3>🗓️ Shift Roster</h3>
      <div style="display:flex;gap:8px">
        <button class="btn btn-ghost btn-sm" onclick="rosterNavWeek(-1)">◀ Prev Week</button>
        <button class="btn btn-ghost btn-sm" onclick="rosterNavWeek(1)">Next Week ▶</button>
        ${isPastWeek ? '' : `<button class="btn btn-accent btn-sm" onclick="rosterSave()">💾 Save Roster</button>`}
      </div>
    </div>

    <div style="font-size:12px;color:var(--text-3);margin-bottom:${isPastWeek?'8px':'16px'}">
      Week of <strong style="color:var(--text-1)">${weekStart.toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'})}</strong>
      ${isPastWeek
        ? '— <span style="color:var(--text-3)">View only</span>'
        : '— <span style="color:var(--text-3)">Past days are locked.</span> Assign for today and future dates.'}
    </div>
    ${isPastWeek ? `<div style="display:inline-flex;align-items:center;gap:6px;background:rgba(255,255,255,0.04);border:1px solid var(--border);border-radius:6px;padding:5px 10px;margin-bottom:14px;font-size:11px;color:var(--text-3)">
      🔒 <span>Past week — read only. Navigate to current or future week to make changes.</span>
    </div>` : ''}

    <div class="card mb-24" style="overflow-x:auto">
      <table style="border-collapse:collapse;width:100%;min-width:680px">
        <thead style="background:var(--bg-1);border-bottom:2px solid var(--border)">
          <tr>
            <th style="padding:10px 14px;text-align:left;min-width:100px;font-size:11px;text-transform:uppercase;color:var(--text-3)">Shift</th>
            ${dayHeaders}
          </tr>
        </thead>
        <tbody>${shiftRows}</tbody>
      </table>
    </div>

    <div class="card">
      <div class="card-head"><h4>📋 Roster Summary — This Week</h4></div>
      <div class="card-body">
        <div class="g" style="grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:14px">
          ${(D.employees||[]).map(e => {
            // Only count shifts within the currently viewed week
            const weekDateStrs = new Set(weekDays.map(fmtDate));
            const totalAssigned = Object.entries(roster).filter(([k,v]) => {
              const datePart = k.split('_')[0];
              return weekDateStrs.has(datePart) && Array.isArray(v) && v.includes(String(e.id));
            }).length;
            return `<div style="padding:12px;background:var(--bg-1);border-radius:var(--radius);border:1px solid var(--border-light)">
              <div style="font-size:13px;font-weight:700;color:var(--text-0);margin-bottom:4px">${sanitize(e.name)}</div>
              <div style="font-size:11px;color:var(--text-3)">${sanitize(e.role||'')} · <span style="color:var(--accent-light);font-weight:700">${totalAssigned} shift${totalAssigned!==1?'s':''} this week</span></div>
            </div>`;
          }).join('')}
        </div>
      </div>
    </div>`;
}

if (window._rosterWeekOffset === undefined) window._rosterWeekOffset = 0;
function rosterNavWeek(dir) {
  window._rosterWeekOffset = (window._rosterWeekOffset || 0) + dir;
  renderPage();
}
function rosterAssign(date, shiftName, empId) {
  if (!empId) return;
  const key = date + '_' + shiftName;
  if (!window._rosterData) window._rosterData = {};
  if (!window._rosterData[key]) window._rosterData[key] = [];
  if (!window._rosterData[key].includes(String(empId))) {
    window._rosterData[key].push(String(empId));
  }
  renderPage();
}
function rosterUnassign(date, shiftName, empId) {
  const key = date + '_' + shiftName;
  if (!window._rosterData || !window._rosterData[key]) return;
  window._rosterData[key] = window._rosterData[key].filter(id => String(id) !== String(empId));
  renderPage();
}
async function rosterSave() {
  try {
    await db.setSetting('shift_roster', window._rosterData || {});
    toast('Roster saved successfully', 'success');
  } catch(e) {
    toast('Failed to save roster: ' + (e.message||e), 'error');
  }
}
window.renderRoster = renderRoster;
window.rosterNavWeek = rosterNavWeek;
window.rosterAssign = rosterAssign;
window.rosterUnassign = rosterUnassign;
window.rosterSave = rosterSave;

// ── ATTENDANCE ────────────────────────────────────────────────
function renderAttendance(D) {
  const today = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
  if (!window._attendanceData) window._attendanceData = {};
  const att = window._attendanceData;
  const emps = (D.employees || []).filter(e => e.status !== 'inactive');
  const shifts = D.shifts && D.shifts.length ? D.shifts : [{name:'Morning'},{name:'Afternoon'},{name:'Night'}];

  // Date picker — default today
  if (!window._attDate) window._attDate = today;
  const attDate = window._attDate;
  const dateKey = attDate;
  if (!att[dateKey]) att[dateKey] = {};

  const statusOpts = ['present','absent','half-day','leave','holiday'];
  const statusColor = { present:'var(--green)', absent:'var(--red)', 'half-day':'var(--orange)', leave:'#8b5cf6', holiday:'#3b82f6' };
  const statusEmoji = { present:'✅', absent:'❌', 'half-day':'🌓', leave:'🏖️', holiday:'🎉' };

  // Summary counts
  const counts = statusOpts.reduce((a,s) => { a[s]=0; return a; }, {});
  emps.forEach(e => { const s = (att[dateKey]?.[e.id]?.status||'absent'); counts[s] = (counts[s]||0)+1; });

  // Attendance rows
  const rows = emps.map(e => {
    const rec = att[dateKey]?.[e.id] || {};
    const status = rec.status || '';
    const note = rec.note || '';
    return `<tr>
      <td style="padding:10px 12px">
        <div style="font-weight:700;color:var(--text-0);font-size:13px">${sanitize(e.name)}</div>
        <div style="font-size:10px;color:var(--text-3)">${sanitize(e.role||'')} · ${sanitize((e.shift||'').split(',')[0]||'—')} shift</div>
      </td>
      <td style="padding:10px 12px">
        <select class="form-input" style="padding:6px 10px;font-size:12px;width:130px" onchange="attSetStatus(${e.id},'${dateKey}',this.value)">
          <option value="">Mark status</option>
          ${statusOpts.map(s => `<option value="${s}" ${status===s?'selected':''} style="color:${statusColor[s]}">${statusEmoji[s]} ${s.charAt(0).toUpperCase()+s.slice(1)}</option>`).join('')}
        </select>
      </td>
      <td style="padding:10px 12px">
        ${status ? `<span style="padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;background:${statusColor[status]}22;color:${statusColor[status]};border:1px solid ${statusColor[status]}44">${statusEmoji[status]} ${status.charAt(0).toUpperCase()+status.slice(1)}</span>` : '<span style="font-size:11px;color:var(--text-3)">Not marked</span>'}
      </td>
      <td style="padding:10px 12px">
        <input style="background:var(--bg-1);border:1px solid var(--border);border-radius:6px;padding:5px 8px;font-size:11px;color:var(--text-1);width:160px" placeholder="Note (optional)" value="${sanitize(note)}" oninput="attSetNote(${e.id},'${dateKey}',this.value)" />
      </td>
    </tr>`;
  }).join('');

  // Monthly summary for selected employee
  const monthStr = attDate.slice(0,7);
  const monthlyRows = emps.map(e => {
    const pres = Object.entries(att).filter(([d]) => d.startsWith(monthStr) && att[d]?.[e.id]?.status==='present').length;
    const abs = Object.entries(att).filter(([d]) => d.startsWith(monthStr) && att[d]?.[e.id]?.status==='absent').length;
    const half = Object.entries(att).filter(([d]) => d.startsWith(monthStr) && att[d]?.[e.id]?.status==='half-day').length;
    const leave = Object.entries(att).filter(([d]) => d.startsWith(monthStr) && att[d]?.[e.id]?.status==='leave').length;
    return `<tr>
      <td style="padding:8px 12px;font-weight:600;color:var(--text-0)">${sanitize(e.name)}</td>
      <td style="padding:8px 12px;color:var(--green);font-weight:700;text-align:center">${pres}</td>
      <td style="padding:8px 12px;color:var(--red);font-weight:700;text-align:center">${abs}</td>
      <td style="padding:8px 12px;color:var(--orange);font-weight:700;text-align:center">${half}</td>
      <td style="padding:8px 12px;color:#8b5cf6;font-weight:700;text-align:center">${leave}</td>
      <td style="padding:8px 12px;text-align:center;font-size:11px;color:var(--text-3)">${Math.round((pres + half*0.5)/(pres+abs+half+leave||1)*100)||0}%</td>
    </tr>`;
  }).join('');

  return `
    <div class="page-hdr"><h3>✅ Attendance</h3>
      <div style="display:flex;gap:8px;align-items:center">
        <input type="date" class="form-input" style="padding:6px 12px;font-size:13px;width:160px" value="${attDate}" onchange="window._attDate=this.value;renderPage()" />
        <button class="btn btn-accent btn-sm" onclick="attSave()">💾 Save</button>
        <button class="btn btn-ghost btn-sm" onclick="attMarkAllPresent('${dateKey}')">✅ All Present</button>
      </div>
    </div>

    <!-- Summary pills -->
    <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:20px">
      ${statusOpts.map(s => `<div style="padding:6px 14px;border-radius:20px;font-size:12px;font-weight:700;background:${statusColor[s]}18;color:${statusColor[s]};border:1px solid ${statusColor[s]}33">${statusEmoji[s]} ${s.charAt(0).toUpperCase()+s.slice(1)}: ${counts[s]}</div>`).join('')}
    </div>

    <!-- Daily attendance table -->
    <div class="card mb-24">
      <div class="card-head"><h4>📅 Daily Attendance — ${new Date(attDate+'T00:00:00').toLocaleDateString('en-IN',{weekday:'long',day:'numeric',month:'long',year:'numeric'})}</h4></div>
      <div class="card-body" style="padding:0">
        <div class="tbl-wrap">
          <table>
            <thead><tr><th>Employee</th><th>Mark Status</th><th>Status</th><th>Note</th></tr></thead>
            <tbody>${rows || '<tr><td colspan="4" style="text-align:center;color:var(--text-3);padding:24px">No employees found. Add staff in Staff &amp; Allocation.</td></tr>'}</tbody>
          </table>
        </div>
      </div>
    </div>

    <!-- Monthly summary -->
    <div class="card">
      <div class="card-head"><h4>📊 Monthly Summary — ${new Date(attDate+'-01').toLocaleDateString('en-IN',{month:'long',year:'numeric'})}</h4></div>
      <div class="card-body" style="padding:0">
        <div class="tbl-wrap">
          <table>
            <thead><tr><th>Employee</th><th style="text-align:center;color:var(--green)">✅ Present</th><th style="text-align:center;color:var(--red)">❌ Absent</th><th style="text-align:center;color:var(--orange)">🌓 Half-Day</th><th style="text-align:center;color:#8b5cf6">🏖️ Leave</th><th style="text-align:center">Attendance %</th></tr></thead>
            <tbody>${monthlyRows || '<tr><td colspan="6" style="text-align:center;color:var(--text-3);padding:24px">No data</td></tr>'}</tbody>
          </table>
        </div>
      </div>
    </div>`;
}

function attSetStatus(empId, dateKey, status) {
  if (!window._attendanceData) window._attendanceData = {};
  if (!window._attendanceData[dateKey]) window._attendanceData[dateKey] = {};
  window._attendanceData[dateKey][empId] = { ...(window._attendanceData[dateKey][empId]||{}), status };
  renderPage();
}
function attSetNote(empId, dateKey, note) {
  if (!window._attendanceData) window._attendanceData = {};
  if (!window._attendanceData[dateKey]) window._attendanceData[dateKey] = {};
  window._attendanceData[dateKey][empId] = { ...(window._attendanceData[dateKey][empId]||{}), note };
}
function attMarkAllPresent(dateKey) {
  const emps = APP.data?.employees || [];
  if (!window._attendanceData) window._attendanceData = {};
  if (!window._attendanceData[dateKey]) window._attendanceData[dateKey] = {};
  emps.forEach(e => { window._attendanceData[dateKey][e.id] = { ...(window._attendanceData[dateKey][e.id]||{}), status:'present' }; });
  renderPage();
}
async function attSave() {
  try {
    await db.setSetting('attendance_data', window._attendanceData || {});
    toast('Attendance saved', 'success');
  } catch(e) {
    toast('Failed to save: ' + (e.message||e), 'error');
  }
}
window.renderAttendance = renderAttendance;
window.attSetStatus = attSetStatus;
window.attSetNote = attSetNote;
window.attMarkAllPresent = attMarkAllPresent;
