// ═══════════════════════════════════════════════════════════════════════════════
// ── ANALYTICS PAGE (Vehicle Report + Density Variance + Bank Reconciliation) ──
// ═══════════════════════════════════════════════════════════════════════════════

let _analyticsTab = 'vehicle';
let _bankReconData = {}; // { 'YYYY-MM-DD': { cash, phonepe, gpay, paytm, card, notes } }

function renderAnalytics(D) {
  if (!D) return '<div style="padding:40px;text-align:center;color:var(--text-3)">Loading...</div>';
  if (!window._analyticsTab) window._analyticsTab = 'vehicle';
  const _analyticsTab = window._analyticsTab;

  const tabs = [
    { id: 'vehicle',   icon: '🚗', label: 'Vehicle Report' },
    { id: 'density',   icon: '⚗️', label: 'Density Variance' },
    { id: 'bankrecon', icon: '🏦', label: 'Bank Reconciliation' },
    { id: 'monthly',   icon: '📅', label: 'Monthly Trends' },
    { id: 'fuelpnl',   icon: '⛽', label: 'Fuel P&L' },
    { id: 'topcust',   icon: '🏆', label: 'Top Customers' },
    { id: 'pumps',     icon: '⛽', label: 'Pump Performance' },
  ];

  const tabBar = `<div style="display:flex;gap:6px;margin-bottom:20px;flex-wrap:wrap">
    ${tabs.map(t => `<button onclick="window._analyticsTab='${t.id}';renderPage()" style="padding:8px 16px;border-radius:8px;border:1px solid var(--border);background:${_analyticsTab===t.id?'var(--accent-light)':'var(--bg-1)'};color:${_analyticsTab===t.id?'#000':'var(--text-2)'};font-weight:700;cursor:pointer;font-size:12px">${t.icon} ${t.label}</button>`).join('')}
  </div>`;

  let body = '';

  if (_analyticsTab === 'vehicle') {
    // ── Vehicle Report ──────────────────────────────────────────────────────
    const vFrom = window._vFrom || new Date(Date.now()-30*86400000).toISOString().slice(0,10);
    const vTo   = window._vTo   || (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
    const vFuel = window._vFuel || '';
    const vNum  = (window._vNum || '').trim().toUpperCase();

    let filtered = D.sales.filter(s => {
      const d = (s.date||'').slice(0,10);
      return d >= vFrom && d <= vTo && (s.vehicle||'').trim() !== '';
    });
    if (vFuel) filtered = filtered.filter(s => s.fuelType === vFuel);
    if (vNum)  filtered = filtered.filter(s => (s.vehicle||'').toUpperCase().includes(vNum));

    // Group by vehicle
    const byVehicle = {};
    filtered.forEach(s => {
      const vno = (s.vehicle||'').trim().toUpperCase() || '—';
      if (!byVehicle[vno]) byVehicle[vno] = { txns:0, liters:0, amount:0, lastDate:'', fuelTypes:new Set(), customer: s.customer||'' };
      byVehicle[vno].txns++;
      byVehicle[vno].liters += s.liters||0;
      byVehicle[vno].amount += s.amount||0;
      if ((s.date||'') > byVehicle[vno].lastDate) byVehicle[vno].lastDate = s.date||'';
      byVehicle[vno].fuelTypes.add(s.fuelType);
    });

    const rows = Object.entries(byVehicle).sort((a,b) => b[1].amount - a[1].amount);
    const totalVehicles = rows.length;
    const totalLiters   = rows.reduce((a,[,v]) => a + v.liters, 0);
    const totalAmt      = rows.reduce((a,[,v]) => a + v.amount, 0);

    const fuelOpts = ['petrol','diesel','premium_petrol'].map(id => {
      const f = getFuel(id);
      return `<option value="${id}" ${vFuel===id?'selected':''}>${f.short}</option>`;
    }).join('');

    body = `
      <div class="g g-auto-sm gap-12 mb-16">
        ${statCard('Vehicles', totalVehicles, 'in date range', '🚗')}
        ${statCard('Fuel Dispensed', fmt(totalLiters) + ' L', 'all vehicles', '⛽')}
        ${statCard('Revenue', cur(totalAmt), 'from vehicles', '💰')}
      </div>
      <div class="card card-pad mb-16">
        <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:flex-end">
          <div class="form-group" style="margin:0;flex:1;min-width:130px">
            <label class="form-label">From</label>
            <input type="date" class="form-input" value="${vFrom}" max="${vTo}" onchange="window._vFrom=this.value;renderPage()" />
          </div>
          <div class="form-group" style="margin:0;flex:1;min-width:130px">
            <label class="form-label">To</label>
            <input type="date" class="form-input" value="${vTo}" max="${(()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})()}" onchange="window._vTo=this.value;renderPage()" />
          </div>
          <div class="form-group" style="margin:0;flex:1;min-width:120px">
            <label class="form-label">Fuel</label>
            <select class="form-input" onchange="window._vFuel=this.value;renderPage()">
              <option value="">All</option>${fuelOpts}
            </select>
          </div>
          <div class="form-group" style="margin:0;flex:1;min-width:130px">
            <label class="form-label">Vehicle No.</label>
            <input class="form-input" placeholder="e.g. KA01" value="${window._vNum||''}" oninput="window._vNum=this.value" onchange="renderPage()" style="text-transform:uppercase" />
          </div>
        </div>
      </div>
      ${rows.length > 0 ? `<div class="card card-pad" style="padding:0;overflow:hidden">
        <div class="tbl-wrap"><table>
          <thead><tr><th>Vehicle No</th><th>Fuel Types</th><th>Txns</th><th>Litres</th><th>Amount</th><th>Last Visit</th><th>Customer</th></tr></thead>
          <tbody>
            ${rows.map(([vno, v]) => `<tr>
              <td class="fw-700" style="color:var(--text-0)">${sanitize(vno)}</td>
              <td>${[...v.fuelTypes].map(f => { const fi=getFuel(f); return `<span style="font-size:10px;font-weight:700;color:${fi.color};background:${fi.color}20;padding:1px 6px;border-radius:4px">${fi.short}</span>`; }).join(' ')}</td>
              <td class="mono">${v.txns}</td>
              <td class="mono fw-700">${fmt(v.liters)} L</td>
              <td class="mono fw-700" style="color:var(--green)">${cur(v.amount)}</td>
              <td style="font-size:11px;color:var(--text-3)">${v.lastDate||'—'}</td>
              <td style="font-size:11px;color:var(--text-3)">${sanitize(v.customer||'—')}</td>
            </tr>`).join('')}
          </tbody>
        </table></div>
      </div>` : `<div class="card card-pad" style="text-align:center;padding:40px;color:var(--text-3)">
        <div style="font-size:32px;margin-bottom:12px">🚗</div>
        <div class="fw-600">No vehicle data found</div>
        <div style="font-size:12px;margin-top:6px">Vehicle numbers are captured during sales recording</div>
      </div>`}`;

  } else if (_analyticsTab === 'density') {
    // ── Density Variance Analysis ──────────────────────────────────────────
    const DENSITY_RANGES = {
      petrol:         { min: 0.720, max: 0.775, name: 'Petrol (MS)' },
      diesel:         { min: 0.820, max: 0.860, name: 'Diesel (HSD)' },
      premium_petrol: { min: 0.720, max: 0.775, name: 'Premium (XP95)' },
    };

    const purchases = (D.fuelPurchases||[]).filter(p => p.density != null);
    const allPurchases = D.fuelPurchases||[];

    const flagPurchase = p => {
      if (p.density == null) return 'missing';
      const r = DENSITY_RANGES[p.fuelType];
      if (!r) return 'ok';
      return (p.density < r.min || p.density > r.max) ? 'anomaly' : 'ok';
    };

    const stats = { total: allPurchases.length, ok:0, anomalies:0, missing:0 };
    allPurchases.forEach(p => {
      const fl = flagPurchase(p);
      if (fl==='ok') stats.ok++;
      else if (fl==='anomaly') stats.anomalies++;
      else stats.missing++;
    });

    const flagColor = f => f==='ok'?'var(--green)':f==='missing'?'var(--text-3)':'var(--red)';
    const flagBadge = f => f==='ok'
      ? badge('✅ In Range','badge-green')
      : f==='missing'
      ? badge('❓ Not Recorded','badge-blue')
      : badge('🚨 Anomaly','badge-red');

    body = `
      <div class="g g-auto-sm gap-12 mb-16">
        ${statCard('Total Purchases', stats.total, 'all time', '🛢️')}
        ${statCard('In Range', stats.ok, 'IS-1460 compliant', '✅')}
        ${statCard('Anomalies', stats.anomalies, 'outside standard', '🚨')}
        ${statCard('Not Recorded', stats.missing, 'density missing', '❓')}
      </div>
      <div class="card card-pad mb-16" style="background:rgba(59,130,246,0.05);border-color:rgba(59,130,246,0.2)">
        <div style="font-size:12px;color:var(--text-2);line-height:1.8">
          <strong style="color:var(--text-1)">IS-1460 Standard Density Ranges:</strong>
          ${Object.entries(DENSITY_RANGES).map(([,r]) => `<span style="margin-left:12px">${r.name}: <strong>${r.min}–${r.max} kg/L</strong></span>`).join('')}
          <br><span style="font-size:11px;color:var(--text-3)">Density outside these ranges may indicate adulteration or measurement error. Add density when recording fuel purchases.</span>
        </div>
      </div>
      ${allPurchases.length > 0 ? `<div class="card card-pad" style="padding:0;overflow:hidden">
        <div class="tbl-wrap"><table>
          <thead><tr><th>Date</th><th>Fuel</th><th>Qty (L)</th><th>Supplier</th><th>Invoice</th><th>Density (kg/L)</th><th>Status</th></tr></thead>
          <tbody>
            ${[...allPurchases].sort((a,b)=>(b.id||0)-(a.id||0)).map(p => {
              const fi = getFuel(p.fuelType);
              const fl = flagPurchase(p);
              return `<tr>
                <td style="font-size:12px">${p.date||'—'}</td>
                <td style="color:${fi.color}" class="fw-700">${fi.short}</td>
                <td class="mono">${fmt(p.liters||0)}</td>
                <td style="font-size:11px;color:var(--text-3)">${sanitize(p.supplier||'—')}</td>
                <td style="font-size:11px;color:var(--text-3)">${sanitize(p.invoice||'—')}</td>
                <td class="mono fw-700" style="color:${flagColor(fl)}">${p.density != null ? p.density : '—'}</td>
                <td>${flagBadge(fl)}</td>
              </tr>`;
            }).join('')}
          </tbody>
        </table></div>
      </div>` : `<div class="card card-pad" style="text-align:center;padding:40px;color:var(--text-3)">
        <div style="font-size:32px;margin-bottom:12px">🛢️</div>
        <div class="fw-600">No fuel purchases recorded yet</div>
      </div>`}`;

  } else if (_analyticsTab === 'bankrecon') {
    // ── Bank Reconciliation ────────────────────────────────────────────────
    if (!window._bankReconData) window._bankReconData = {};
    const recon = window._bankReconData;

    const today = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
    const selDate = window._brSelDate || today;
    const D2 = APP.data;

    // System totals for selected date
    const daySales = D2.sales.filter(s => (s.date||'').slice(0,10) === selDate);
    const sysCash  = daySales.filter(s=>s.mode==='cash').reduce((a,s)=>a+s.amount,0);
    const sysUpi   = daySales.filter(s=>s.mode==='upi').reduce((a,s)=>a+s.amount,0);
    const sysCard  = daySales.filter(s=>s.mode==='card').reduce((a,s)=>a+s.amount,0);

    const entry = recon[selDate] || {};

    // Month summary
    const month = selDate.slice(0,7);
    const monthDays = Object.entries(recon).filter(([d]) => d.startsWith(month));

    const diff = (bank, sys) => {
      const d = (bank||0) - sys;
      if (d === 0) return `<span style="color:var(--green)" class="fw-700">✓ Match</span>`;
      return `<span style="color:${d<0?'var(--red)':'var(--orange)'}" class="fw-700">${d>0?'+':''}${cur(Math.abs(d))}</span>`;
    };

    body = `
      <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px">
        <div class="card card-pad" style="flex:1;min-width:200px">
          <div class="fw-700 mb-10" style="font-size:13px;color:var(--text-0)">✏️ Enter Bank Data</div>
          <div class="form-group" style="margin-bottom:10px">
            <label class="form-label">Date</label>
            <input type="date" class="form-input" value="${selDate}" max="${today}" onchange="window._brSelDate=this.value;renderPage()" />
          </div>
          <div class="g g-2 gap-10">
            <div class="form-group" style="margin-bottom:8px">
              <label class="form-label" style="font-size:11px">💵 Cash Deposited (₹)</label>
              <input type="number" class="form-input" id="br_cash" placeholder="0" value="${entry.cash||''}" style="font-size:13px" />
            </div>
            <div class="form-group" style="margin-bottom:8px">
              <label class="form-label" style="font-size:11px">📱 UPI Settled (₹)</label>
              <input type="number" class="form-input" id="br_upi" placeholder="0" value="${entry.upi||''}" style="font-size:13px" />
            </div>
            <div class="form-group" style="margin-bottom:8px">
              <label class="form-label" style="font-size:11px">💳 Card/POS (₹)</label>
              <input type="number" class="form-input" id="br_card" placeholder="0" value="${entry.card||''}" style="font-size:13px" />
            </div>
            <div class="form-group" style="margin-bottom:8px">
              <label class="form-label" style="font-size:11px">📝 Notes</label>
              <input class="form-input" id="br_notes" placeholder="e.g. T+1 settlement" value="${sanitize(entry.notes||'')}" style="font-size:13px" />
            </div>
          </div>
          <button class="btn btn-accent btn-block mt-8" onclick="saveBankReconEntry('${selDate}')">💾 Save Bank Entry</button>
        </div>
        <div class="card card-pad" style="flex:2;min-width:260px">
          <div class="fw-700 mb-14" style="font-size:13px;color:var(--text-0)">📊 Comparison — ${selDate}</div>
          <table style="width:100%;border-collapse:collapse;font-size:13px">
            <thead>
              <tr style="background:var(--bg-0);font-size:11px;color:var(--text-3)">
                <th style="padding:8px 10px;text-align:left">Mode</th>
                <th style="padding:8px 10px;text-align:right">System</th>
                <th style="padding:8px 10px;text-align:right">Bank</th>
                <th style="padding:8px 10px;text-align:right">Diff</th>
              </tr>
            </thead>
            <tbody>
              <tr style="border-bottom:1px solid var(--border-light)">
                <td style="padding:10px">💵 Cash</td>
                <td style="padding:10px;text-align:right" class="mono">${cur(sysCash)}</td>
                <td style="padding:10px;text-align:right" class="mono">${cur(entry.cash||0)}</td>
                <td style="padding:10px;text-align:right">${diff(entry.cash, sysCash)}</td>
              </tr>
              <tr style="border-bottom:1px solid var(--border-light)">
                <td style="padding:10px">📱 UPI</td>
                <td style="padding:10px;text-align:right" class="mono">${cur(sysUpi)}</td>
                <td style="padding:10px;text-align:right" class="mono">${cur(entry.upi||0)}</td>
                <td style="padding:10px;text-align:right">${diff(entry.upi, sysUpi)}</td>
              </tr>
              <tr>
                <td style="padding:10px">💳 Card</td>
                <td style="padding:10px;text-align:right" class="mono">${cur(sysCard)}</td>
                <td style="padding:10px;text-align:right" class="mono">${cur(entry.card||0)}</td>
                <td style="padding:10px;text-align:right">${diff(entry.card, sysCard)}</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      ${monthDays.length > 0 ? `<div class="card card-pad" style="padding:0;overflow:hidden">
        <div style="padding:12px 16px;font-size:12px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.6px;border-bottom:1px solid var(--border-light)">📅 Past Entries — ${month}</div>
        <div class="tbl-wrap"><table>
          <thead><tr><th>Date</th><th>Cash</th><th>UPI</th><th>Card</th><th>Notes</th></tr></thead>
          <tbody>
            ${monthDays.sort((a,b)=>b[0]<a[0]?-1:1).map(([d,e]) => `<tr onclick="window._brSelDate='${d}';renderPage()" style="cursor:pointer">
              <td class="fw-600">${d}</td>
              <td class="mono">${e.cash ? cur(e.cash) : '—'}</td>
              <td class="mono">${e.upi  ? cur(e.upi)  : '—'}</td>
              <td class="mono">${e.card ? cur(e.card) : '—'}</td>
              <td style="font-size:11px;color:var(--text-3)">${sanitize(e.notes||'')}</td>
            </tr>`).join('')}
          </tbody>
        </table></div>
      </div>` : `<div class="card card-pad" style="text-align:center;padding:30px;color:var(--text-3);font-size:12px">No bank entries for ${month} yet</div>`}`;
  } else if (_analyticsTab === 'monthly') {
    body = renderAnalyticsMonthly(D);
  } else if (_analyticsTab === 'fuelpnl') {
    body = renderAnalyticsFuelPL(D);
  } else if (_analyticsTab === 'topcust') {
    body = renderAnalyticsTopCustomers(D);
  } else if (_analyticsTab === 'pumps') {
    body = renderAnalyticsPumpPerformance(D);
  }

  return `<div class="page-hdr"><h3>🔍 Analytics</h3></div>${tabBar}${body}`;
}

function saveBankReconEntry(date) {
  if (!window._bankReconData) window._bankReconData = {};
  const cash  = parseFloat(document.getElementById('br_cash')?.value) || 0;
  const upi   = parseFloat(document.getElementById('br_upi')?.value)  || 0;
  const card  = parseFloat(document.getElementById('br_card')?.value) || 0;
  const notes = document.getElementById('br_notes')?.value || '';
  window._bankReconData[date] = { cash, upi, card, notes };
  // Persist
  db.setSetting('bank_recon_data', window._bankReconData).catch(()=>{});
  toast('✅ Bank entry saved for ' + date, 'success');
  renderPage();
}
window.saveBankReconEntry = saveBankReconEntry;
window.renderAnalytics = renderAnalytics;

// ═══════════════════════════════════════════════════════════════════════════════
// ── PAYROLL PAGE ──────────────────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════════

function renderPayroll(D) {
  if (!D) return '<div style="padding:40px;text-align:center;color:var(--text-3)">Loading...</div>';

  const payTab = window._payTab || 'run';
  const tabs = [
    { id: 'run',      icon: '💰', label: 'Payroll Run' },
    { id: 'advances', icon: '💸', label: 'Salary Advances' },
    { id: 'perf',     icon: '📈', label: 'Performance' },
  ];
  const tabBar = `<div style="display:flex;gap:6px;margin-bottom:20px;flex-wrap:wrap">
    ${tabs.map(t => `<button onclick="window._payTab='${t.id}';renderPage()" style="padding:8px 16px;border-radius:8px;border:1px solid var(--border);background:${payTab===t.id?'var(--accent-light)':'var(--bg-1)'};color:${payTab===t.id?'#000':'var(--text-2)'};font-weight:700;cursor:pointer;font-size:12px">${t.icon} ${t.label}</button>`).join('')}
  </div>`;

  // ── Shared data ──────────────────────────────────────────────────────────
  const today = new Date();
  const payMonth = window._payMonth || (today.getMonth()+1);
  const payYear  = window._payYear  || today.getFullYear();
  const monthLabel = new Date(payYear, payMonth-1, 1).toLocaleString('en-IN',{month:'long', year:'numeric'});

  // Attendance for this month
  const att = window._attendanceData || {};
  const monthPrefix = payYear + '-' + String(payMonth).padStart(2,'0');

  // Working days in the month (Mon-Sat = 26 typical; we count actual calendar days Mon-Sat)
  const daysInMonth = new Date(payYear, payMonth, 0).getDate();
  let workingDays = 0;
  for (let d=1; d<=daysInMonth; d++) {
    const dow = new Date(payYear, payMonth-1, d).getDay();
    if (dow !== 0) workingDays++; // count Mon-Sat (exclude Sun)
  }

  const emps = (D.employees||[]).filter(e => e.status !== 'inactive');

  // Build per-employee attendance summary for the month
  const empAttSummary = empId => {
    let present=0, absent=0, halfDay=0, leave=0, otHours=0;
    for (let d=1; d<=daysInMonth; d++) {
      const dateKey = payYear + '-' + String(payMonth).padStart(2,'0') + '-' + String(d).padStart(2,'0');
      const rec = att[dateKey]?.[empId];
      const status = rec?.status || '';
      if (status==='present') present++;
      else if (status==='half-day') halfDay++;
      else if (status==='leave') leave++;
      else if (status==='holiday') { present++; } // holiday counts as present
      else if (dateKey <= today.toISOString().slice(0,10)) absent++;
    }
    otHours = parseInt((att[monthPrefix]?.[empId]?.otHours || 0));
    const effectiveDays = present + halfDay*0.5;
    return { present, absent, halfDay, leave, otHours, effectiveDays, workingDays };
  };

  if (payTab === 'run') {
    // ── Payroll Run ──────────────────────────────────────────────────────────
    const advances = window._advancesData || [];
    const payrollSaved = window._payrollSaved || {}; // { empId: { net, status } }

    const totalPayroll = emps.reduce((a, e) => a + (e.salary||0), 0);
    const paidCount = Object.values(payrollSaved).filter(p=>p.status==='paid').length;

    const empCards = emps.map(e => {
      const s = empAttSummary(e.id);
      const baseSalary = e.salary || 0;
      const grossEarned = baseSalary > 0 ? (baseSalary / workingDays) * s.effectiveDays : 0;
      const otPay = s.otHours * 50; // ₹50/hr overtime rate
      const grossSalary = grossEarned + otPay;
      const activeAdvances = advances.filter(a => a.empId === e.id && a.status === 'active');
      const advDeduction = activeAdvances.reduce((a, adv) => a + (adv.monthlyEmi || 0), 0);
      const savedPayroll = payrollSaved[e.id] || {};
      const netSalary = Math.max(0, grossSalary - advDeduction - (savedPayroll.otherDeductions||0));
      const statusColor = {draft:'var(--orange)', approved:'var(--accent-light)', paid:'var(--green)'}[savedPayroll.status] || 'var(--text-3)';
      const ini = sanitize(e.name||'').charAt(0).toUpperCase();

      return `<div class="card card-pad mb-12">
        <div class="flex-between mb-10">
          <div style="display:flex;align-items:center;gap:10px">
            <div style="width:36px;height:36px;border-radius:50%;background:rgba(212,148,15,0.12);border:2px solid rgba(212,148,15,0.3);display:grid;place-items:center;font-size:14px;font-weight:800;color:var(--accent-light)">${ini}</div>
            <div>
              <div class="fw-700" style="color:var(--text-0);font-size:14px">${sanitize(e.name)}</div>
              <div style="font-size:11px;color:var(--text-3)">${sanitize(e.role||'')} · Base ₹${fmt(baseSalary)}/mo</div>
            </div>
          </div>
          ${savedPayroll.status ? `<span style="font-size:11px;font-weight:700;color:${statusColor};text-transform:uppercase">${savedPayroll.status}</span>` : `<span style="font-size:11px;color:var(--text-3)">Not calculated</span>`}
        </div>
        <div class="g" style="grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:12px">
          <div class="dbox text-center"><div class="fw-800 mono" style="color:var(--green)">${s.present}</div><div style="font-size:10px;color:var(--text-3)">Present</div></div>
          <div class="dbox text-center"><div class="fw-800 mono" style="color:var(--red)">${s.absent}</div><div style="font-size:10px;color:var(--text-3)">Absent</div></div>
          <div class="dbox text-center"><div class="fw-800 mono" style="color:var(--orange)">${s.halfDay}</div><div style="font-size:10px;color:var(--text-3)">Half Day</div></div>
          <div class="dbox text-center"><div class="fw-800 mono" style="color:var(--accent-light)">${s.otHours}h</div><div style="font-size:10px;color:var(--text-3)">Overtime</div></div>
        </div>
        ${savedPayroll.net != null ? `<div style="display:flex;align-items:center;justify-content:space-between;padding:10px 12px;background:var(--bg-0);border-radius:8px;margin-bottom:10px">
          <div style="font-size:12px;color:var(--text-2)">
            <div>Gross: <span class="mono fw-700">₹${fmt(savedPayroll.gross||grossSalary)}</span></div>
            ${advDeduction>0?`<div style="color:var(--red)">Advance EMI: -₹${fmt(advDeduction)}</div>`:''}
          </div>
          <div class="mono fw-800" style="font-size:20px;color:var(--accent-light)">₹${fmt(savedPayroll.net||netSalary)}</div>
        </div>` : ''}
        <div style="display:flex;gap:6px">
          <button onclick="calcPayrollSlip(${e.id},'${sanitize(e.name)}',${payMonth},${payYear})" style="flex:2;padding:8px;background:var(--bg-0);border:1px solid var(--border);border-radius:8px;cursor:pointer;font-size:12px;font-weight:600;color:var(--text-1)">🧮 Calculate</button>
          ${savedPayroll.net != null && savedPayroll.status !== 'paid' ? `<button onclick="markPayrollPaid(${e.id})" style="flex:1;padding:8px;background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.3);color:var(--green);border-radius:8px;cursor:pointer;font-size:12px;font-weight:600">✓ Mark Paid</button>` : ''}
        </div>
      </div>`;
    }).join('');

    return `<div class="page-hdr"><h3>💸 Payroll</h3></div>
      ${tabBar}
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:16px">
        <button onclick="prevPayMonth()" style="background:var(--bg-1);border:1px solid var(--border);color:var(--text-2);padding:6px 14px;border-radius:8px;cursor:pointer">‹</button>
        <span class="fw-700" style="flex:1;text-align:center;font-size:14px;color:var(--text-0)">${monthLabel}</span>
        <button onclick="nextPayMonth()" style="background:var(--bg-1);border:1px solid var(--border);color:var(--text-2);padding:6px 14px;border-radius:8px;cursor:pointer">›</button>
      </div>
      <div class="g g-auto-sm gap-12 mb-16">
        ${statCard('Employees', emps.length, 'active staff', '👥')}
        ${statCard('Total Payroll', cur(totalPayroll), 'base salaries', '💰')}
        ${statCard('Working Days', workingDays, 'in ' + monthLabel, '📅')}
        ${statCard('Paid', paidCount + '/' + emps.length, 'processed', '✅')}
      </div>
      <div style="display:flex;gap:8px;margin-bottom:16px">
        <button onclick="bulkCalcPayroll()" class="btn btn-accent">⚡ Calculate All</button>
      </div>
      ${empCards || '<div class="card card-pad" style="text-align:center;padding:40px;color:var(--text-3)">No active employees</div>'}`;

  } else if (payTab === 'advances') {
    // ── Salary Advances ──────────────────────────────────────────────────────
    if (!window._advancesData) window._advancesData = [];
    const advances = window._advancesData;
    const activeAdv = advances.filter(a => a.status==='active');
    const totalBalance = activeAdv.reduce((a,adv) => a + (adv.balance||0), 0);

    const advCards = advances.map((adv, idx) => {
      const emp = emps.find(e => e.id === adv.empId);
      const ini = (emp?.name||adv.empName||'?').charAt(0).toUpperCase();
      return `<div class="card card-pad mb-10">
        <div class="flex-between mb-8">
          <div style="display:flex;align-items:center;gap:10px">
            <div style="width:32px;height:32px;border-radius:50%;background:rgba(168,85,247,0.12);display:grid;place-items:center;font-weight:800;color:#a855f7">${ini}</div>
            <div>
              <div class="fw-700" style="color:var(--text-0)">${sanitize(emp?.name||adv.empName||'Unknown')}</div>
              <div style="font-size:11px;color:var(--text-3)">${sanitize(adv.reason||'Advance')} · ${adv.date||''}</div>
            </div>
          </div>
          <div style="text-align:right">
            <div class="mono fw-800" style="color:${adv.status==='active'?'var(--red)':'var(--green)'}">₹${fmt(adv.balance||0)}</div>
            ${adv.status==='active' ? badge('Active','badge-red') : badge('Cleared','badge-green')}
          </div>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-3);margin-bottom:10px">
          <span>Original: ₹${fmt(adv.amount)}</span>
          <span>Monthly EMI: ₹${fmt(adv.monthlyEmi)}</span>
          <span>${adv.repayMonths} month${adv.repayMonths>1?'s':''}</span>
        </div>
        ${adv.status==='active' ? `<button onclick="clearAdvance(${idx})" style="width:100%;padding:7px;background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.25);color:var(--green);border-radius:8px;cursor:pointer;font-size:12px;font-weight:600">✓ Mark Cleared</button>` : ''}
      </div>`;
    }).join('') || `<div class="card card-pad" style="text-align:center;padding:40px;color:var(--text-3)">
      <div style="font-size:32px;margin-bottom:12px">💸</div>
      <div class="fw-600">No advances recorded</div>
    </div>`;

    return `<div class="page-hdr">
      <h3>💸 Payroll</h3>
      <button class="btn btn-accent" onclick="openAddAdvanceModal()">＋ New Advance</button>
    </div>
    ${tabBar}
    <div class="g g-auto-sm gap-12 mb-16">
      ${statCard('Active Advances', activeAdv.length, 'ongoing', '💸')}
      ${statCard('Total Balance', cur(totalBalance), 'outstanding', '💰')}
      ${statCard('Cleared', advances.filter(a=>a.status==='cleared').length, 'all time', '✅')}
    </div>
    ${advCards}`;

  } else if (payTab === 'perf') {
    // ── Performance Report ───────────────────────────────────────────────────
    const medals = ['🥇','🥈','🥉'];

    // Per-employee: litres, txns, attendance %, avg cash variance
    const empPerf = emps.map(e => {
      const attS = empAttSummary(e.id);
      const empSales = D.sales.filter(s => {
        const d = (s.date||'');
        return d.startsWith(monthPrefix) && (s.employeeId === e.id || String(s.employeeId) === String(e.id));
      });
      const liters = empSales.reduce((a,s) => a+(s.liters||0), 0);
      const txns   = empSales.length;
      const attRate = attS.workingDays > 0 ? Math.round((attS.effectiveDays / attS.workingDays)*100) : null;
      const advances = (window._advancesData||[]).filter(a=>a.empId===e.id&&a.status==='active');
      const totalAdv = advances.reduce((a,adv)=>a+(adv.balance||0),0);
      return { emp: e, liters, txns, attRate, totalAdv, effectiveDays: attS.effectiveDays };
    }).sort((a,b) => b.liters - a.liters);

    const perfCards = empPerf.map((ep, i) => {
      const medalBorder = i < 3 ? ['rgba(255,215,0,0.4)','rgba(192,192,192,0.4)','rgba(205,127,50,0.4)'][i] : 'var(--border)';
      const ini = sanitize(ep.emp.name||'').charAt(0).toUpperCase();
      return `<div class="card card-pad mb-10" style="border-color:${medalBorder}">
        <div class="flex-between mb-10">
          <div style="display:flex;align-items:center;gap:10px">
            <div style="font-size:24px;width:36px;text-align:center">${medals[i]||'#'+(i+1)}</div>
            <div style="width:34px;height:34px;border-radius:50%;background:rgba(212,148,15,0.12);display:grid;place-items:center;font-size:13px;font-weight:800;color:var(--accent-light)">${ini}</div>
            <div>
              <div class="fw-700" style="color:var(--text-0)">${sanitize(ep.emp.name)}</div>
              <div style="font-size:11px;color:var(--text-3)">${sanitize(ep.emp.role||'')}${ep.emp.empCode?' · #'+ep.emp.empCode:''}</div>
            </div>
          </div>
          <div style="text-align:right">
            <div class="mono fw-800" style="font-size:18px;color:var(--accent-light)">${fmt(ep.liters)} L</div>
            <div style="font-size:10px;color:var(--text-3)">dispensed</div>
          </div>
        </div>
        <div class="g" style="grid-template-columns:repeat(4,1fr);gap:8px">
          <div class="dbox text-center" style="padding:8px">
            <div class="fw-800 mono" style="color:var(--accent-light);font-size:14px">${ep.txns}</div>
            <div style="font-size:10px;color:var(--text-3)">Sales</div>
          </div>
          <div class="dbox text-center" style="padding:8px">
            <div class="fw-800 mono" style="color:${ep.attRate!=null?(ep.attRate>=80?'var(--green)':'var(--orange)'):'var(--text-3)'};font-size:14px">${ep.attRate!=null?ep.attRate+'%':'—'}</div>
            <div style="font-size:10px;color:var(--text-3)">Attendance</div>
          </div>
          <div class="dbox text-center" style="padding:8px">
            <div class="fw-800 mono" style="color:var(--green);font-size:14px">${ep.effectiveDays.toFixed(1)}</div>
            <div style="font-size:10px;color:var(--text-3)">Eff. Days</div>
          </div>
          <div class="dbox text-center" style="padding:8px">
            <div class="fw-800 mono" style="color:${ep.totalAdv>0?'var(--orange)':'var(--green)'};font-size:14px">${ep.totalAdv>0?'₹'+fmt(ep.totalAdv):'—'}</div>
            <div style="font-size:10px;color:var(--text-3)">Adv. Bal</div>
          </div>
        </div>
      </div>`;
    }).join('') || `<div class="card card-pad" style="text-align:center;padding:40px;color:var(--text-3)">No employee data for ${monthLabel}</div>`;

    return `<div class="page-hdr"><h3>💸 Payroll</h3></div>
      ${tabBar}
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:16px">
        <button onclick="prevPayMonth()" style="background:var(--bg-1);border:1px solid var(--border);color:var(--text-2);padding:6px 14px;border-radius:8px;cursor:pointer">‹</button>
        <span class="fw-700" style="flex:1;text-align:center;font-size:14px;color:var(--text-0)">${monthLabel}</span>
        <button onclick="nextPayMonth()" style="background:var(--bg-1);border:1px solid var(--border);color:var(--text-2);padding:6px 14px;border-radius:8px;cursor:pointer">›</button>
      </div>
      ${perfCards}`;
  }

  return `<div class="page-hdr"><h3>💸 Payroll</h3></div>${tabBar}`;
}

// ── Payroll helper functions ─────────────────────────────────────────────────
function prevPayMonth() {
  const m = window._payMonth || (new Date().getMonth()+1);
  const y = window._payYear  || new Date().getFullYear();
  window._payMonth = m===1 ? 12 : m-1;
  window._payYear  = m===1 ? y-1 : y;
  renderPage();
}
function nextPayMonth() {
  const m = window._payMonth || (new Date().getMonth()+1);
  const y = window._payYear  || new Date().getFullYear();
  window._payMonth = m===12 ? 1 : m+1;
  window._payYear  = m===12 ? y+1 : y;
  renderPage();
}

function calcPayrollSlip(empId, empName, month, year) {
  const D = APP.data;
  const emps = D.employees||[];
  const emp = emps.find(e => e.id === empId);
  if (!emp) return;

  const today2 = new Date();
  const daysInMonth = new Date(year, month, 0).getDate();
  let workingDays = 0;
  for (let d=1; d<=daysInMonth; d++) { if (new Date(year,month-1,d).getDay()!==0) workingDays++; }

  const att = window._attendanceData || {};
  let present=0, absent=0, halfDay=0, leave=0, otHours=0;
  for (let d=1; d<=daysInMonth; d++) {
    const dateKey = year+'-'+String(month).padStart(2,'0')+'-'+String(d).padStart(2,'0');
    const rec = att[dateKey]?.[empId];
    const status = rec?.status || '';
    if (status==='present'||status==='holiday') present++;
    else if (status==='half-day') halfDay++;
    else if (status==='leave') leave++;
    else if (dateKey <= today2.toISOString().slice(0,10)) absent++;
  }
  const effectiveDays = present + halfDay*0.5;
  const baseSalary = emp.salary||0;
  const grossEarned = baseSalary > 0 ? (baseSalary / workingDays) * effectiveDays : 0;
  const otPay = otHours * 50;
  const grossSalary = grossEarned + otPay;
  const activeAdv = (window._advancesData||[]).filter(a=>a.empId===empId&&a.status==='active');
  const totalAdvBalance = activeAdv.reduce((a,adv)=>a+(adv.balance||adv.amount||0),0);
  const defaultAdvDeduction = activeAdv.reduce((a,adv)=>a+(adv.monthlyEmi||0),0);

  openModal(`🧮 Salary Preview — ${sanitize(empName)}`, `
    <div class="card card-pad mb-12" style="background:var(--bg-0)">
      <div style="font-size:12px;font-weight:700;color:var(--text-3);margin-bottom:10px">Attendance — ${new Date(year,month-1,1).toLocaleString('en-IN',{month:'long',year:'numeric'})}</div>
      <div class="g" style="grid-template-columns:repeat(3,1fr);gap:8px">
        <div class="dbox text-center" style="padding:8px"><div class="fw-800 mono" style="color:var(--green)">${present}</div><div style="font-size:10px;color:var(--text-3)">Present</div></div>
        <div class="dbox text-center" style="padding:8px"><div class="fw-800 mono" style="color:var(--red)">${absent}</div><div style="font-size:10px;color:var(--text-3)">Absent</div></div>
        <div class="dbox text-center" style="padding:8px"><div class="fw-800 mono" style="color:var(--orange)">${halfDay}</div><div style="font-size:10px;color:var(--text-3)">Half Day</div></div>
        <div class="dbox text-center" style="padding:8px"><div class="fw-800 mono" style="color:#a855f7">${leave}</div><div style="font-size:10px;color:var(--text-3)">Leave</div></div>
        <div class="dbox text-center" style="padding:8px"><div class="fw-800 mono" style="color:var(--accent-light)">${otHours}h</div><div style="font-size:10px;color:var(--text-3)">OT Hours</div></div>
        <div class="dbox text-center" style="padding:8px"><div class="fw-800 mono" style="color:var(--text-1)">${effectiveDays.toFixed(1)}</div><div style="font-size:10px;color:var(--text-3)">Eff. Days</div></div>
      </div>
    </div>
    <div class="card card-pad mb-12" style="background:var(--bg-0)">
      <div style="font-size:12px;font-weight:700;color:var(--text-3);margin-bottom:8px">Earnings & Deductions</div>
      <div class="flex-between" style="font-size:13px;padding:6px 0;border-bottom:1px solid var(--border-light)"><span style="color:var(--text-3)">Base Salary</span><span class="mono fw-700">₹${fmt(baseSalary)}</span></div>
      <div class="flex-between" style="font-size:13px;padding:6px 0;border-bottom:1px solid var(--border-light)"><span style="color:var(--text-3)">Earned (${effectiveDays.toFixed(1)}/${workingDays} days)</span><span class="mono fw-700">₹${fmt(grossEarned)}</span></div>
      ${otPay>0?`<div class="flex-between" style="font-size:13px;padding:6px 0;border-bottom:1px solid var(--border-light)"><span style="color:var(--green)">Overtime (${otHours}h × ₹50)</span><span class="mono fw-700" style="color:var(--green)">+₹${fmt(otPay)}</span></div>`:''}
      <div class="flex-between" style="font-size:13px;padding:6px 0;border-bottom:1px solid var(--border-light)"><span class="fw-600">Gross Salary</span><span class="mono fw-800">₹${fmt(grossSalary)}</span></div>
      ${totalAdvBalance>0?`
      <div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.2);border-radius:8px;padding:10px 14px;margin:8px 0">
        <div style="font-size:11px;color:var(--text-3);font-weight:700;text-transform:uppercase;margin-bottom:6px">Salary Advance</div>
        <div class="flex-between mb-6"><span style="font-size:13px;color:var(--text-2)">Total Outstanding Balance</span><span class="mono fw-700" style="color:var(--red)">₹${fmt(totalAdvBalance)}</span></div>
        <label class="form-label" style="margin-top:4px">Deduct this month (₹) — default: ₹${fmt(defaultAdvDeduction)}</label>
        <input class="form-input" type="number" id="advDedInput" value="${defaultAdvDeduction}" min="0" max="${totalAdvBalance}" oninput="updateNetPreview(${grossSalary})" />
      </div>`:''}
      <div class="form-group mt-10"><label class="form-label">Other Deductions (₹)</label><input class="form-input" type="number" id="otherDed" value="0" min="0" oninput="updateNetPreview(${grossSalary})" /></div>
    </div>
    <div style="background:rgba(212,148,15,0.08);border:2px solid rgba(212,148,15,0.3);border-radius:12px;padding:18px;text-align:center">
      <div style="font-size:11px;color:var(--text-3);margin-bottom:6px;text-transform:uppercase;letter-spacing:0.8px">Net Salary</div>
      <div class="mono fw-900" style="font-size:32px;color:var(--accent-light)" id="netSalaryPreview">₹${fmt(grossSalary - defaultAdvDeduction)}</div>
    </div>
  `, `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn btn-accent" onclick="savePayrollSlip(${empId},${month},${year},${grossSalary})">💾 Save Payroll</button>`);
}

function updateNetPreview(gross) {
  const advDed = parseFloat(document.getElementById('advDedInput')?.value) || 0;
  const otherDed = parseFloat(document.getElementById('otherDed')?.value) || 0;
  const net = Math.max(0, gross - advDed - otherDed);
  const el = document.getElementById('netSalaryPreview');
  if (el) el.textContent = '₹' + net.toLocaleString('en-IN', {maximumFractionDigits:2});
}

function savePayrollSlip(empId, month, year, gross) {
  const advDed = parseFloat(document.getElementById('advDedInput')?.value) || 0;
  const otherDed = parseFloat(document.getElementById('otherDed')?.value) || 0;
  const net = Math.max(0, gross - advDed - otherDed);
  if (!window._payrollSaved) window._payrollSaved = {};
  window._payrollSaved[empId] = { gross, advDed, otherDeductions: otherDed, net, status:'draft', month, year };
  db.setSetting('payroll_' + year + '_' + month, window._payrollSaved).catch(()=>{});
  closeModal();
  toast(`✅ Payroll saved — Net: ₹${fmt(net)}`, 'success');
  renderPage();
}

function markPayrollPaid(empId) {
  if (!window._payrollSaved?.[empId]) return;
  window._payrollSaved[empId].status = 'paid';
  const m = window._payMonth||(new Date().getMonth()+1);
  const y = window._payYear||new Date().getFullYear();
  db.setSetting('payroll_' + y + '_' + m, window._payrollSaved).catch(()=>{});
  toast('✅ Marked as paid', 'success');
  renderPage();
}

function bulkCalcPayroll() {
  const D = APP.data;
  const emps = (D.employees||[]).filter(e=>e.status!=='inactive');
  const m = window._payMonth||(new Date().getMonth()+1);
  const y = window._payYear||new Date().getFullYear();
  const today2 = new Date();
  const daysInMonth = new Date(y, m, 0).getDate();
  let workingDays = 0;
  for (let d=1; d<=daysInMonth; d++) { if (new Date(y,m-1,d).getDay()!==0) workingDays++; }
  const att = window._attendanceData||{};
  if (!window._payrollSaved) window._payrollSaved = {};
  emps.forEach(e => {
    let present=0, halfDay=0, leave=0;
    for (let d=1; d<=daysInMonth; d++) {
      const dk = y+'-'+String(m).padStart(2,'0')+'-'+String(d).padStart(2,'0');
      const rec = att[dk]?.[e.id];
      const status = rec?.status||'';
      if (status==='present'||status==='holiday') present++;
      else if (status==='half-day') halfDay++;
      else if (status==='leave') leave++;
    }
    const effectiveDays = present + halfDay*0.5;
    const baseSalary = e.salary||0;
    const grossEarned = baseSalary > 0 ? (baseSalary/workingDays)*effectiveDays : 0;
    const activeAdv = (window._advancesData||[]).filter(a=>a.empId===e.id&&a.status==='active');
    const advDed = activeAdv.reduce((a,adv)=>a+(adv.monthlyEmi||0),0);
    const net = Math.max(0, grossEarned - advDed);
    window._payrollSaved[e.id] = { gross: grossEarned, advDed, otherDeductions:0, net, status:'draft', month:m, year:y };
  });
  db.setSetting('payroll_'+y+'_'+m, window._payrollSaved).catch(()=>{});
  toast(`✅ Payroll calculated for ${emps.length} employees`, 'success');
  renderPage();
}

function openAddAdvanceModal() {
  const D = APP.data;
  const emps = (D.employees||[]).filter(e=>e.status!=='inactive');
  const empOpts = emps.map(e=>`<option value="${e.id}">${sanitize(e.name)}</option>`).join('');
  openModal('💸 New Salary Advance', `
    <div class="form-group"><label class="form-label">Employee *</label><select class="form-input" id="advEmp">${empOpts}</select></div>
    <div class="form-row">
      <div class="form-group"><label class="form-label">Amount (₹) *</label><input class="form-input" type="number" id="advAmt" placeholder="e.g. 5000" oninput="updateAdvPreview()" /></div>
      <div class="form-group"><label class="form-label">Repay in months</label>
        <select class="form-input" id="advMonths" onchange="updateAdvPreview()">
          ${[1,2,3,4,5,6].map(n=>`<option value="${n}">${n} month${n>1?'s':''}</option>`).join('')}
          <option value="custom">Custom</option>
        </select>
        <input class="form-input mt-6" type="number" id="advMonthsCustom" min="1" max="60" placeholder="Enter number of months" style="display:none;margin-top:6px" oninput="updateAdvPreview()" />
      </div>
    </div>
    <div class="form-group"><label class="form-label">Reason</label><input class="form-input" id="advReason" placeholder="Medical / Personal / Other" /></div>
    <div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="advDate" value="${(()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})()}" /></div>
    <div id="advPreview" style="padding:10px 14px;background:var(--bg-0);border-radius:8px;font-size:13px;color:var(--text-3)">Monthly EMI: —</div>
  `, `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="saveAdvance()">Record Advance</button>`);
}

function updateAdvPreview() {
  const amt      = parseFloat(document.getElementById('advAmt')?.value||0);
  const selVal   = document.getElementById('advMonths')?.value;
  const customEl = document.getElementById('advMonthsCustom');
  if (customEl) customEl.style.display = selVal === 'custom' ? '' : 'none';
  const months   = selVal === 'custom'
    ? parseInt(customEl?.value||0)
    : parseInt(selVal||1);
  const prev = document.getElementById('advPreview');
  if (!prev) return;
  if (amt > 0 && months > 0) {
    const emi = (amt/months).toFixed(2);
    prev.innerHTML = `<span style="color:var(--text-1)">Monthly EMI: <strong class="mono">₹${fmt(parseFloat(emi))}</strong> × ${months} month${months>1?'s':''}</span>`;
  } else {
    prev.innerHTML = 'Monthly EMI: —';
  }
}

function saveAdvance() {
  const empId = parseInt(document.getElementById('advEmp')?.value);
  const amount = parseFloat(document.getElementById('advAmt')?.value);
  const reason = (document.getElementById('advReason')?.value||'').trim();
  const advMonthsVal = document.getElementById('advMonths')?.value;
  const repayMonths = advMonthsVal === 'custom'
    ? parseInt(document.getElementById('advMonthsCustom')?.value||1)
    : parseInt(advMonthsVal||1);
  if (!repayMonths || repayMonths < 1) { toast('Enter valid number of months', 'error'); return; }
  const date = document.getElementById('advDate')?.value || (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
  if (!empId || isNaN(amount) || amount <= 0) { toast('Please enter a valid amount', 'error'); return; }
  const monthlyEmi = Math.ceil(amount / repayMonths);
  const emp = APP.data.employees.find(e => e.id === empId);
  if (!window._advancesData) window._advancesData = [];
  window._advancesData.unshift({ id: Date.now(), empId, empName: emp?.name||'', amount, reason, repayMonths, monthlyEmi, balance: amount, date, status:'active' });
  db.setSetting('advances_data', window._advancesData).catch(()=>{});
  closeModal();
  toast(`✅ Advance ₹${fmt(amount)} recorded. EMI ₹${fmt(monthlyEmi)}/mo`, 'success');
  renderPage();
}

function clearAdvance(idx) {
  if (!window._advancesData?.[idx]) return;
  window._advancesData[idx].status = 'cleared';
  window._advancesData[idx].balance = 0;
  db.setSetting('advances_data', window._advancesData).catch(()=>{});
  toast('✅ Advance cleared', 'success');
  renderPage();
}

window.renderPayroll = renderPayroll;
window.calcPayrollSlip = calcPayrollSlip;
window.savePayrollSlip = savePayrollSlip;
window.markPayrollPaid = markPayrollPaid;
window.bulkCalcPayroll = bulkCalcPayroll;
window.openAddAdvanceModal = openAddAdvanceModal;
window.updateAdvPreview = updateAdvPreview;
window.saveAdvance = saveAdvance;
window.clearAdvance = clearAdvance;
window.prevPayMonth = prevPayMonth;
window.nextPayMonth = nextPayMonth;


// ═══════════════════════════════════════════════════════════════════════════════
// ── NOZZLE METER READINGS — SHIFT OPEN/CLOSE LOG ─────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════════
// Data model: window._nozzleMeterLog = [
//   { id, date, shift, employee, pumpId, pumpName, nozzle, fuelType,
//     openReading, closeReading, meterSold, systemSold, variance,
//     source: 'employee' | 'admin', timestamp }
// ]

function _nozzleLogKey() { return 'nozzle_meter_log'; }

function nozzleLog_load() {
  if (!window._nozzleMeterLog) window._nozzleMeterLog = [];
  return window._nozzleMeterLog;
}

function nozzleLog_save() {
  db.setSetting(_nozzleLogKey(), window._nozzleMeterLog || []).catch(() => {});
}

// Called from emp_submit — auto-captures all nozzle readings for the shift
function nozzleLog_recordFromShift(empName, shiftName, pumps, openReadings, closeReadings, sales) {
  if (!window._nozzleMeterLog) window._nozzleMeterLog = [];
  // FIX 31: use IST today()
  const today = (typeof window.today === 'function') ? window.today() : new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10);
  const nowTs = Date.now();

  pumps.forEach(pump => {
    const nozzleFuels = pump.nozzleFuels || {};
    (pump.nozzles || []).forEach(n => {
      const k = emp_key(pump.id, n);
      const openRaw  = openReadings[k];
      const closeRaw = closeReadings[k];
      if (openRaw === undefined && closeRaw === undefined) return; // no data for this nozzle
      const open  = openRaw  !== undefined ? parseFloat(openRaw)  : null;
      const close = closeRaw !== undefined ? parseFloat(closeRaw) : null;
      const ft    = nozzleFuels[n] || pump.fuelType;
      const meterSold = (open !== null && close !== null && close > open) ? +(close - open).toFixed(3) : 0;
      // System sold = sum of sales for this pump/nozzle this session
      const nozzleSales = (sales || []).filter(s => String(s.pump) === String(pump.id) && (s.nozzle === n || s.nozzle === String(n)));
      const systemSold  = +nozzleSales.reduce((a, s) => a + (s.liters || 0), 0).toFixed(3);
      const variance    = +(meterSold - systemSold).toFixed(3);
      const flagged     = Math.abs(variance) >= 0.5; // flag if ≥0.5L gap

      // Remove any existing entry for same date+shift+pump+nozzle (deduplication)
      window._nozzleMeterLog = window._nozzleMeterLog.filter(e =>
        !(e.date === today && e.shift === shiftName && String(e.pumpId) === String(pump.id) && e.nozzle === n)
      );

      window._nozzleMeterLog.unshift({
        id: nowTs + Math.random(),
        date: today,
        shift: shiftName || '—',
        employee: empName || '—',
        pumpId: pump.id,
        pumpName: pump.name,
        nozzle: n,
        fuelType: ft,
        openReading: open !== null ? open : 0,
        closeReading: close !== null ? close : 0,
        meterSold,
        systemSold,
        variance,
        flagged,
        source: 'employee',
        timestamp: nowTs,
      });
    });
  });

  nozzleLog_save();
}
window.nozzleLog_recordFromShift = nozzleLog_recordFromShift;

// Admin manual entry modal
function openNozzleMeterModal(pumpId, nozzleLabel) {
  const D = APP.data;
  const pump = D.pumps.find(p => String(p.id) === String(pumpId));
  if (!pump) return;
  const nozzleLabels = pump.nozzleLabels || (pump.nozzles === 1 ? ['A'] : pump.nozzles === 2 ? ['A','B'] : ['A','B','C'].slice(0, pump.nozzles));
  const nozzleFuels  = pump.nozzleFuels || {};

  const nozzleOpts = nozzleLabels.map(n => {
    const ft = getFuel(nozzleFuels[n] || pump.fuelType);
    return `<option value="${n}" ${n===nozzleLabel?'selected':''}>${pump.name} · N${n}: ${ft.short}</option>`;
  }).join('');

  const shifts = (D.shifts && D.shifts.length) ? D.shifts : [{name:'Morning'},{name:'Afternoon'},{name:'Night'}];
  const shiftOpts = shifts.map(s => `<option value="${sanitize(s.name)}">${sanitize(s.name)}</option>`).join('');
  const today = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();

  openModal('📟 Record Nozzle Meter Reading', `
    <div class="g g-2 gap-12">
      <div class="form-group"><label class="form-label">Date</label>
        <input type="date" class="form-input" id="nm_date" value="${today}" max="${today}" />
      </div>
      <div class="form-group"><label class="form-label">Shift</label>
        <select class="form-input" id="nm_shift">${shiftOpts}</select>
      </div>
    </div>
    <div class="g g-2 gap-12">
      <div class="form-group"><label class="form-label">Pump · Nozzle</label>
        <select class="form-input" id="nm_nozzle" onchange="nmUpdatePrev()">${nozzleOpts}</select>
      </div>
      <div class="form-group"><label class="form-label">Employee</label>
        <select class="form-input" id="nm_emp">
          <option value="">— Select —</option>
          ${(D.employees||[]).filter(e=>e.status!=='inactive').map(e=>`<option value="${sanitize(e.name)}">${sanitize(e.name)}</option>`).join('')}
        </select>
      </div>
    </div>
    <div class="g g-2 gap-12">
      <div class="form-group"><label class="form-label">Opening Reading</label>
        <input type="number" class="form-input" id="nm_open" step="0.01" placeholder="e.g. 12345.6" oninput="nmCalcVariance()" style="font-family:var(--mono);font-size:16px;font-weight:700" />
        <div id="nm_prev_reading" style="font-size:11px;color:var(--text-3);margin-top:3px"></div>
      </div>
      <div class="form-group"><label class="form-label">Closing Reading</label>
        <input type="number" class="form-input" id="nm_close" step="0.01" placeholder="e.g. 12567.3" oninput="nmCalcVariance()" style="font-family:var(--mono);font-size:16px;font-weight:700" />
      </div>
    </div>
    <div id="nm_preview" style="padding:12px 14px;background:var(--bg-0);border-radius:8px;font-size:13px;color:var(--text-3)">
      Enter both readings to see variance preview
    </div>
  `, `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn btn-accent" onclick="saveNozzleMeterEntry(${pumpId})">💾 Save Entry</button>`);

  // Pre-fill opening reading from last close
  setTimeout(() => nmUpdatePrev(), 50);
}
window.openNozzleMeterModal = openNozzleMeterModal;

function nmUpdatePrev() {
  const sel = document.getElementById('nm_nozzle');
  if (!sel) return;
  const [pumpIdStr, nozzle] = sel.value.split ? [sel.value.split('|')[0], sel.value.split('|')[1]] : [null, null];
  // Find last close reading for this nozzle from log
  const log = window._nozzleMeterLog || [];
  const nozzleVal = sel.options[sel.selectedIndex]?.text;
  const prevEl = document.getElementById('nm_prev_reading');
  if (prevEl) {
    const pump = APP.data.pumps.find(p => {
      const labels = p.nozzleLabels || ['A','B'];
      return labels.some(n => sel.value === n && (p.name + ' · N' + n) === nozzleVal);
    });
    if (pump) {
      const last = log.find(e => String(e.pumpId) === String(pump.id) && e.nozzle === sel.value);
      if (last) {
        prevEl.textContent = 'Last close: ' + last.closeReading + ' (' + last.date + ')';
        const openEl = document.getElementById('nm_open');
        if (openEl && !openEl.value) openEl.value = last.closeReading;
      }
    }
  }
  nmCalcVariance();
}
window.nmUpdatePrev = nmUpdatePrev;

function nmCalcVariance() {
  const open  = parseFloat(document.getElementById('nm_open')?.value);
  const close = parseFloat(document.getElementById('nm_close')?.value);
  const prev  = document.getElementById('nm_preview');
  if (!prev) return;
  if (isNaN(open) || isNaN(close)) { prev.innerHTML = 'Enter both readings to see variance preview'; prev.style.background = 'var(--bg-0)'; return; }
  if (close < open) { prev.innerHTML = '<span style="color:var(--red);font-weight:700">⚠️ Closing reading cannot be less than opening reading</span>'; prev.style.background = 'rgba(239,68,68,0.05)'; return; }
  const meterSold = +(close - open).toFixed(3);
  const sel = document.getElementById('nm_nozzle');
  const nozzle = sel?.value;
  // find pump
  let systemSold = 0, pumpId = null;
  APP.data.pumps.forEach(p => {
    const labels = p.nozzleLabels || (p.nozzles===1?['A']:p.nozzles===2?['A','B']:['A','B','C'].slice(0,p.nozzles));
    if (labels.includes(nozzle)) {
      pumpId = p.id;
      const today = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
      systemSold = APP.data.sales.filter(s => String(s.pump)===String(p.id) && (s.nozzle===nozzle||s.nozzle===String(nozzle)) && (s.date||'').slice(0,10)===today).reduce((a,s)=>a+(s.liters||0),0);
    }
  });
  const variance = +(meterSold - systemSold).toFixed(3);
  const flagged  = Math.abs(variance) >= 0.5;
  const varColor = flagged ? 'var(--red)' : Math.abs(variance) > 0 ? 'var(--orange)' : 'var(--green)';
  const varIcon  = flagged ? '🚨' : Math.abs(variance) > 0 ? '⚠️' : '✅';
  prev.style.background = flagged ? 'rgba(239,68,68,0.07)' : 'var(--bg-0)';
  prev.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;text-align:center">
      <div><div class="mono fw-800" style="font-size:18px;color:var(--accent-light)">${fmt(meterSold)} L</div><div style="font-size:10px;color:var(--text-3)">Meter Sold</div></div>
      <div><div class="mono fw-800" style="font-size:18px;color:var(--text-2)">${fmt(systemSold)} L</div><div style="font-size:10px;color:var(--text-3)">System Sales</div></div>
      <div><div class="mono fw-800" style="font-size:18px;color:${varColor}">${varIcon} ${variance > 0 ? '+' : ''}${fmt(variance)} L</div><div style="font-size:10px;color:var(--text-3)">Variance</div></div>
    </div>
    ${flagged ? `<div style="margin-top:8px;font-size:11px;font-weight:700;color:var(--red);text-align:center">🚨 Significant variance — verify readings before saving</div>` : ''}
  `;
}
window.nmCalcVariance = nmCalcVariance;

function saveNozzleMeterEntry(pumpId) {
  const date     = document.getElementById('nm_date')?.value;
  const shift    = document.getElementById('nm_shift')?.value;
  const nozzle   = document.getElementById('nm_nozzle')?.value;
  const empName  = document.getElementById('nm_emp')?.value || 'Admin';
  const open     = parseFloat(document.getElementById('nm_open')?.value);
  const close    = parseFloat(document.getElementById('nm_close')?.value);
  if (!date || !nozzle || isNaN(open) || isNaN(close)) { toast('Please fill all required fields', 'error'); return; }
  if (close < open) { toast('Closing reading must be ≥ opening reading', 'error'); return; }

  const pump = APP.data.pumps.find(p => String(p.id) === String(pumpId));
  if (!pump) return;
  const nozzleFuels = pump.nozzleFuels || {};
  const ft          = nozzleFuels[nozzle] || pump.fuelType;
  const meterSold   = +(close - open).toFixed(3);
  const nozzleSales = APP.data.sales.filter(s => String(s.pump)===String(pumpId) && (s.nozzle===nozzle||s.nozzle===String(nozzle)) && (s.date||'').slice(0,10)===date);
  const systemSold  = +nozzleSales.reduce((a,s) => a+(s.liters||0), 0).toFixed(3);
  const variance    = +(meterSold - systemSold).toFixed(3);
  const flagged     = Math.abs(variance) >= 0.5;

  if (!window._nozzleMeterLog) window._nozzleMeterLog = [];
  // Deduplicate
  window._nozzleMeterLog = window._nozzleMeterLog.filter(e =>
    !(e.date === date && e.shift === shift && String(e.pumpId) === String(pumpId) && e.nozzle === nozzle && e.source !== 'employee')
  );
  window._nozzleMeterLog.unshift({
    id: Date.now() + Math.random(),
    date, shift, employee: empName,
    pumpId: pump.id, pumpName: pump.name, nozzle, fuelType: ft,
    openReading: open, closeReading: close,
    meterSold, systemSold, variance, flagged,
    source: 'admin', timestamp: Date.now(),
  });
  nozzleLog_save();
  closeModal();
  auditLog('nozzle_meter_entry', { pump: pump.name, nozzle, open, close, meterSold, variance, date, shift });
  // WhatsApp alert for flagged variance
  if (flagged && typeof wa_alertMeterMismatch === 'function') {
    wa_alertMeterMismatch({ pumpName: pump.name, nozzle, fuelType: ft, meterSold, systemSold, variance }).catch(()=>{});
  }
  toast(flagged ? `⚠️ Saved with ${Math.abs(variance).toFixed(2)}L variance — flag raised` : `✅ Meter reading saved — ${fmt(meterSold)} L`, flagged ? 'warning' : 'success');
  renderPage();
}
window.saveNozzleMeterEntry = saveNozzleMeterEntry;


// ═══════════════════════════════════════════════════════════════════════════════
// ── WHATSAPP NOTIFICATION ENGINE — FREE (wa.me + CallMeBot) ──────────────────
// ═══════════════════════════════════════════════════════════════════════════════
//
// DELIVERY MODES (auto-selected based on what's configured in Settings):
//   1. wa.me link  — always free, opens WhatsApp with message pre-filled. User taps Send.
//   2. CallMeBot   — free API for personal WhatsApp numbers. Register once, then silent delivery.
//   3. Log-only    — console + in-app notification log (no WA configured yet)
//
// CallMeBot registration (one-time):
//   Send  "I allow callmebot to send me messages"  to +34 644 21 65 38 on WhatsApp
//   Wait for API key reply, paste it in Settings.

function wa_phone() { return (APP.data?.waPhone || '').replace(/\D/g,''); }
function wa_apiKey() { return (APP.data?.waApiKey || '').trim(); }
function wa_stationName() { return APP.data?.upiName || APP.tenant?.name || 'Fuel Station'; }

// Normalise Indian phone to international (91XXXXXXXXXX)
function wa_normalise(num) {
  let n = String(num || '').replace(/\D/g,'');
  if (n.length === 10) n = '91' + n;
  if (n.length === 11 && n.startsWith('0')) n = '91' + n.slice(1);
  return n;
}

// In-app notification log (ring-buffer of last 50)
if (!window._waLog) window._waLog = [];
function wa_log(type, message, status) {
  window._waLog.unshift({ id: Date.now(), type, message: message.slice(0,200), status, ts: new Date().toLocaleString('en-IN') });
  if (window._waLog.length > 50) window._waLog.length = 50;
  db.setSetting('wa_log', window._waLog).catch(()=>{});
}

// Core send function — tries CallMeBot first if key set, else opens wa.me
async function wa_send(toNum, message, alertType) {
  const phone = wa_normalise(toNum || wa_phone());
  if (!phone || phone.length < 10) {
    wa_log(alertType || 'manual', message, 'no_phone');
    console.log('[WA] No phone configured — message logged only');
    return { mode: 'log', reason: 'no phone' };
  }

  const apiKey = wa_apiKey();

  if (apiKey) {
    // ── CallMeBot silent delivery ─────────────────────────────────────────
    const encoded = encodeURIComponent(message);
    const url = `https://api.callmebot.com/whatsapp.php?phone=${phone}&text=${encoded}&apikey=${apiKey}`;
    try {
      const resp = await fetch(url, { mode: 'no-cors' });
      wa_log(alertType || 'manual', message, 'callmebot_sent');
      return { mode: 'callmebot', phone };
    } catch(e) {
      // Fallback to wa.me if callmebot fails
      wa_log(alertType || 'manual', message, 'callmebot_error_fallback_wame');
    }
  }

  // ── wa.me click-to-send (always works, always free) ──────────────────────
  const waUrl = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;
  window.open(waUrl, '_blank');
  wa_log(alertType || 'manual', message, 'wame_opened');
  return { mode: 'wame', phone, url: waUrl };
}
window.wa_send = wa_send;

// ── Message Templates ─────────────────────────────────────────────────────────
const wa_templates = {
  lowTank(stationName, fuelType, tankId, current, capacity) {
    const pct = capacity > 0 ? Math.round((current/capacity)*100) : 0;
    const fi = getFuel(fuelType);
    return `⚠️ *LOW FUEL ALERT*\n\n🏪 ${stationName}\n⛽ Tank ${tankId} — *${fi.name}*\n📉 Stock: *${Math.round(current).toLocaleString('en-IN')} L* (${pct}%)\n🚨 Below 20% threshold\n\nPlease arrange refill immediately.\n\n_— FuelBunk Pro_`;
  },
  dailySummary(stationName, date, stats) {
    const r = v => '₹' + Math.round(v||0).toLocaleString('en-IN');
    const l = v => (v||0).toFixed(1) + ' L';
    return `📊 *DAILY SUMMARY — ${date}*\n\n🏪 ${stationName}\n\n💰 Revenue: *${r(stats.revenue)}*\n⛽ Litres: *${l(stats.litres)}*\n🔢 Transactions: *${stats.txns||0}*\n\n💵 Cash: ${r(stats.cash)}\n📱 UPI: ${r(stats.upi)}\n💳 Card: ${r(stats.card)}\n🏢 Credit: ${r(stats.credit)}\n\n_— FuelBunk Pro_`;
  },
  creditReminder(stationName, customerName, outstanding, stationPhone) {
    return `💳 *PAYMENT REMINDER*\n\n🏪 ${stationName}\n🏢 Dear *${customerName}*,\n\nYour fuel credit outstanding:\n*₹${Math.round(outstanding).toLocaleString('en-IN')}*\n\nKindly settle your dues to continue availing credit.\n\n📞 ${stationPhone||'Contact station'}\n\n_— FuelBunk Pro_`;
  },
  meterMismatch(stationName, pumpName, nozzle, fuelType, meterL, systemL, variance) {
    const fi = getFuel(fuelType);
    return `🚨 *METER MISMATCH ALERT*\n\n🏪 ${stationName}\n⛽ ${pumpName} · N${nozzle} (${fi.short})\n\nMeter sold: *${meterL.toFixed(2)} L*\nSystem sales: *${systemL.toFixed(2)} L*\nGap: *${Math.abs(variance).toFixed(2)} L* ⚠️\n\nPlease verify dispenser readings and investigate.\n\n_— FuelBunk Pro_`;
  },
  test(stationName) {
    return `✅ *WhatsApp Test — FuelBunk Pro*\n\n🏪 Station: ${stationName}\n⏰ ${new Date().toLocaleString('en-IN',{dateStyle:'medium',timeStyle:'short'})}\n\nYour WhatsApp notifications are working! 🎉\n\n_— FuelBunk Pro_`;
  },
  creditBill(stationName, customerName, fuelType, qty, rate, amount, outstanding, stationPhone) {
    const fi = getFuel(fuelType);
    const r  = v => '₹' + (v||0).toLocaleString('en-IN',{maximumFractionDigits:2});
    return `🧾 *FUEL CREDIT BILL*\n\n🏪 ${stationName}\n🏢 Customer: *${customerName}*\n\n⛽ ${fi.name} × ${qty.toFixed(2)} L @ ${r(rate)}/L\n💰 Bill: *${r(amount)}*\n📊 Total Outstanding: *${r(outstanding)}*\n\nKindly settle dues at earliest.\n📞 ${stationPhone||'Contact station'}\n\n_— FuelBunk Pro_`;
  },
};
window.wa_templates = wa_templates;

// ── Trigger functions (called from various events) ────────────────────────────

// 1. Tank low alert — called from checkTankAlerts
async function wa_alertLowTank(tank) {
  const phone = wa_phone();
  if (!phone && !wa_apiKey()) return; // skip silently if not configured
  const msg = wa_templates.lowTank(wa_stationName(), tank.fuelType, tank.id, tank.current, tank.capacity);
  return wa_send(phone, msg, 'low_tank');
}
window.wa_alertLowTank = wa_alertLowTank;

// 2. Daily summary — called manually from Reports or automatically
async function wa_sendDailySummary(dateStr) {
  const D = APP.data;
  const date = dateStr || (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
  const daySales = D.sales.filter(s => (s.date||'').slice(0,10) === date);
  const stats = {
    revenue: daySales.reduce((a,s)=>a+s.amount,0),
    litres:  daySales.reduce((a,s)=>a+s.liters,0),
    txns:    daySales.length,
    cash:    daySales.filter(s=>s.mode==='cash').reduce((a,s)=>a+s.amount,0),
    upi:     daySales.filter(s=>s.mode==='upi').reduce((a,s)=>a+s.amount,0),
    card:    daySales.filter(s=>s.mode==='card').reduce((a,s)=>a+s.amount,0),
    credit:  daySales.filter(s=>s.mode==='credit').reduce((a,s)=>a+s.amount,0),
  };
  const msg = wa_templates.dailySummary(wa_stationName(), date, stats);
  const res = await wa_send(wa_phone(), msg, 'daily_summary');
  if (res.mode !== 'wame') toast('📱 Daily summary sent via WhatsApp', 'success');
  return res;
}
window.wa_sendDailySummary = wa_sendDailySummary;

// 3. Credit reminder — called from credit customer card
async function wa_sendCreditReminder(customer) {
  if (!customer.phone) {
    toast('No phone number on this customer record', 'error');
    return;
  }
  const stationPhone = wa_phone();
  const msg = wa_templates.creditReminder(wa_stationName(), customer.name, customer.outstanding, stationPhone);
  const res = await wa_send(customer.phone, msg, 'credit_reminder');
  if (res.mode !== 'wame') toast(`📱 Reminder sent to ${sanitize(customer.name)}`, 'success');
  return res;
}
window.wa_sendCreditReminder = wa_sendCreditReminder;

// 4. Meter mismatch — called automatically when nozzle log flags a variance
async function wa_alertMeterMismatch(entry) {
  const phone = wa_phone();
  if (!phone && !wa_apiKey()) return;
  const msg = wa_templates.meterMismatch(wa_stationName(), entry.pumpName, entry.nozzle, entry.fuelType, entry.meterSold, entry.systemSold, entry.variance);
  return wa_send(phone, msg, 'meter_mismatch');
}
window.wa_alertMeterMismatch = wa_alertMeterMismatch;

// 5. Credit sale bill — send to customer after credit sale
async function wa_sendCreditBill(sale, customer) {
  if (!customer?.phone) return;
  const outstanding = customer.outstanding || 0;
  const msg = wa_templates.creditBill(wa_stationName(), customer.name, sale.fuelType, sale.liters, sale.liters > 0 ? sale.amount/sale.liters : 0, sale.amount, outstanding, wa_phone());
  return wa_send(customer.phone, msg, 'credit_bill');
}
window.wa_sendCreditBill = wa_sendCreditBill;

// Hook meter mismatch into nozzle log save
const _origSaveNozzleMeterEntry = typeof saveNozzleMeterEntry === 'function' ? saveNozzleMeterEntry : null;

// Test function
async function wa_sendTest() {
  const msg = wa_templates.test(wa_stationName());
  const phone = wa_phone();
  if (!phone) { toast('Enter your WhatsApp number in Settings first', 'error'); return; }
  const res = await wa_send(phone, msg, 'test');
  if (res.mode === 'callmebot') toast('✅ Test message sent via CallMeBot', 'success');
  else if (res.mode === 'wame') toast('📱 WhatsApp opened — tap Send to deliver', 'success');
  else toast('Test logged (no phone configured)', 'warning');
}
window.wa_sendTest = wa_sendTest;


