window.printPayslip = printPayslip;

function printAllPayslips(month, year) {
  const D = APP.data;
  const now3 = new Date();
  D.employees.filter(e=>e.status!=='inactive').forEach((e,i) => {
    const attKey = year+'-'+String(month).padStart(2,'0');
    const att    = (window._attendanceData||{})[attKey] || {};
    const empAtt = Object.entries(att).filter(([k])=>k.startsWith(e.id+'_'));
    const present  = empAtt.filter(([,v])=>v==='P').length;
    const absent   = empAtt.filter(([,v])=>v==='A').length;
    const halfDay  = empAtt.filter(([,v])=>v==='H').length;
    const effDays  = present + halfDay*0.5;
    const daysInMonth = new Date(year, month, 0).getDate();
    const perDay   = daysInMonth>0 ? (e.salary||0)/daysInMonth : 0;
    const earned   = effDays>0 ? +(perDay*effDays).toFixed(2) : (e.salary||0);
    const advances = (window._advancesData||[]).filter(a=>a.empId===e.id&&!a.cleared);
    const advDeduct = advances.reduce((x,a)=>{ const emi=a.emi||Math.ceil(a.amount/(a.months||1)); return (a.paidMonths||0)<(a.months||1)?x+emi:x; },0);
    const net = Math.max(0,earned-advDeduct);
    setTimeout(()=>printPayslip(e.id,e.name,month,year,earned,advDeduct,net,present,absent,halfDay), i*300);
  });
}
window.printAllPayslips = printAllPayslips;

function exportPayslipCSV(empId, empName, month, year, earned, advDeduct, net) {
  const monthName = new Date(year,month-1).toLocaleString('en-IN',{month:'long'});
  exportCSV(`payslip-${empName.replace(/\s/g,'-')}-${monthName}-${year}.csv`,
    ['Employee','Month','Year','Earned','Advance Deduction','Net Payable'],
    [[empName, monthName, year, earned.toFixed(2), advDeduct.toFixed(2), net.toFixed(2)]]);
}
window.exportPayslipCSV = exportPayslipCSV;

function wa_sendPayslip(empId, empName, month, year, earned, advDeduct, net) {
  const D = APP.data;
  const emp = D.employees.find(e=>e.id===empId);
  if (!emp?.phone) { toast('No phone number for this employee','error'); return; }
  const monthName = new Date(year,month-1).toLocaleString('en-IN',{month:'long'});
  const stationName = D.upiName || APP.tenant?.name || 'Fuel Station';
  const msg = `💸 *SALARY PAYSLIP — ${monthName.toUpperCase()} ${year}*\n\n🏪 ${stationName}\n👤 Employee: *${empName}*\n\n💰 Earned: ₹${earned.toFixed(2)}\n${advDeduct>0?`✂️ Advance: -₹${advDeduct.toFixed(2)}\n`:''}✅ Net Payable: *₹${net.toFixed(2)}*\n\nKindly contact station for queries.\n\n_— FuelBunk Pro_`;
  wa_send(emp.phone, msg, 'payslip').catch(()=>{});
}
window.wa_sendPayslip = wa_sendPayslip;

// ── CREDIT STATEMENT PRINT + CSV ─────────────────────────────────────────────
function printCreditStatement(custId) {
  const D = APP.data;
  const c = D.creditCustomers.find(x=>x.id===custId);
  if (!c) return;
  const txns = D.sales.filter(s=>s.customer===c.name&&s.mode==='credit').sort((a,b)=>b.id-a.id);
  const stationName = D.upiName || APP.tenant?.name || 'Fuel Station';
  const rows = txns.map(s=>`<tr><td>${s.date||''}</td><td>${s.time||''}</td><td>${sanitize(s.vehicle||'')}</td><td>${sanitize(s.fuelType||'').toUpperCase()}</td><td style="text-align:right">${(s.liters||0).toFixed(2)}</td><td style="text-align:right">₹${(s.amount||0).toFixed(2)}</td></tr>`).join('');
  const total = txns.reduce((a,s)=>a+s.amount,0);
  const html = `<!DOCTYPE html><html><head><title>Credit Statement</title><style>
    body{font-family:Arial,sans-serif;margin:24px;font-size:12px}
    h2{font-size:16px;margin-bottom:4px} table{width:100%;border-collapse:collapse;margin-top:12px}
    th,td{border:1px solid #ddd;padding:6px 8px} th{background:#f5f5f5;font-weight:700}
    .summary{display:flex;gap:16px;margin:12px 0} .sum-box{border:1px solid #ddd;padding:8px 14px;border-radius:4px}
    @media print{body{margin:0 16px}}
  </style></head><body>
    <h2>💳 Credit Statement — ${sanitize(c.name)}</h2>
    <div style="color:#555;margin-bottom:8px">Station: ${sanitize(stationName)} · Generated: ${new Date().toLocaleString('en-IN')}</div>
    <div class="summary">
      <div class="sum-box"><div style="font-size:10px;color:#888">TOTAL TRANSACTIONS</div><div style="font-weight:700;font-size:15px">${txns.length}</div></div>
      <div class="sum-box"><div style="font-size:10px;color:#888">TOTAL CREDIT</div><div style="font-weight:700;font-size:15px">₹${total.toFixed(2)}</div></div>
      <div class="sum-box"><div style="font-size:10px;color:#888">OUTSTANDING</div><div style="font-weight:700;font-size:15px;color:#dc2626">₹${c.outstanding.toFixed(2)}</div></div>
    </div>
    <table><thead><tr><th>Date</th><th>Time</th><th>Vehicle</th><th>Fuel</th><th style="text-align:right">Litres</th><th style="text-align:right">Amount</th></tr></thead><tbody>${rows}</tbody></table>
    <div style="margin-top:16px;font-size:11px;color:#aaa">— FuelBunk Pro · ${sanitize(stationName)}</div>
  </body></html>`;
  _openPrint(html, 'credit-statement');
}
