function exportTallyXML(month, year) {
  const D = APP.data;
  const startDate = `${year}-${String(month).padStart(2,'0')}-01`;
  const endDate   = new Date(year, month, 0).toISOString().slice(0,10);
  const fuelSales = D.sales.filter(s=>{ const d=(s.date||'').slice(0,10); return d>=startDate&&d<=endDate; });
  const lubeSales = (window._lubesSales||[]).filter(s=>s.date>=startDate&&s.date<=endDate);
  const stationName = D.legalName || D.upiName || APP.tenant?.name || 'Fuel Station';
  const taxRates = D.fuelTaxRates || [];
  const monthName = new Date(year,month-1).toLocaleString('en-IN',{month:'long'});

  function tallyDate(iso) {
    const [y,m,d] = iso.split('-');
    return `${d}-${m}-${y}`; // DD-MM-YYYY for Tally
  }

  let vouchers = '';

  // Fuel sales vouchers
  fuelSales.forEach(s => {
    const tr = taxRates.find(t=>t.fuelType===s.fuelType)||{};
    const gstPct = tr.rate ? parseFloat(tr.rate) : 0;
    const taxable = gstPct>0 ? s.amount/(1+gstPct/100) : s.amount;
    const gstAmt  = s.amount - taxable;
    const ledger  = getFuel(s.fuelType).name + ' Sales';
    const dateStr = tallyDate((s.date||startDate));
    const modeMap = {cash:'Cash',upi:'UPI',card:'Card/Bank',credit:'Sundry Debtors'};
    const drLedger = modeMap[s.mode] || 'Cash';
    vouchers += `<TALLYMESSAGE>
  <VOUCHER VCHTYPE="Sales" ACTION="Create">
    <DATE>${dateStr}</DATE>
    <VOUCHERTYPENAME>Sales</VOUCHERTYPENAME>
    <NARRATION>${sanitize(s.vehicle||'')}</NARRATION>
    <ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>${drLedger}</LEDGERNAME>
      <ISDEEMEDPOSITIVE>Yes</ISDEEMEDPOSITIVE>
      <AMOUNT>-${s.amount.toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>
    <ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>${ledger}</LEDGERNAME>
      <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
      <AMOUNT>${taxable.toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>
    ${gstAmt>0?`<ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>Output CGST</LEDGERNAME>
      <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
      <AMOUNT>${(gstAmt/2).toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>
    <ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>Output SGST</LEDGERNAME>
      <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
      <AMOUNT>${(gstAmt/2).toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>`:''}
  </VOUCHER>
</TALLYMESSAGE>\n`;
  });

  // Lube sales vouchers
  lubeSales.forEach(s => {
    const prod = (window._lubesProducts||[]).find(p=>p.id===s.productId);
    const gstPct = prod?.gstPct||18;
    const taxable = gstPct>0 ? s.amount/(1+gstPct/100) : s.amount;
    const gstAmt  = s.amount - taxable;
    const dateStr = tallyDate(s.date||startDate);
    const drLedger = s.mode==='credit'?'Sundry Debtors':s.mode==='upi'?'UPI':s.mode==='card'?'Card/Bank':'Cash';
    vouchers += `<TALLYMESSAGE>
  <VOUCHER VCHTYPE="Sales" ACTION="Create">
    <DATE>${dateStr}</DATE>
    <VOUCHERTYPENAME>Sales</VOUCHERTYPENAME>
    <NARRATION>Lube sale: ${sanitize(s.productName||'')} to ${sanitize(s.customer||'Walk-in')}</NARRATION>
    <ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>${drLedger}</LEDGERNAME>
      <ISDEEMEDPOSITIVE>Yes</ISDEEMEDPOSITIVE>
      <AMOUNT>-${s.amount.toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>
    <ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>Lubes &amp; Products Sales</LEDGERNAME>
      <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
      <AMOUNT>${taxable.toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>
    ${gstAmt>0?`<ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>Output CGST</LEDGERNAME>
      <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
      <AMOUNT>${(gstAmt/2).toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>
    <ALLLEDGERENTRIES.LIST>
      <LEDGERNAME>Output SGST</LEDGERNAME>
      <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
      <AMOUNT>${(gstAmt/2).toFixed(2)}</AMOUNT>
    </ALLLEDGERENTRIES.LIST>`:''}
  </VOUCHER>
</TALLYMESSAGE>\n`;
  });

  const xml = `<?xml version="1.0" encoding="UTF-8"?>
<ENVELOPE>
  <HEADER>
    <TALLYREQUEST>Import Data</TALLYREQUEST>
  </HEADER>
  <BODY>
    <IMPORTDATA>
      <REQUESTDESC>
        <REPORTNAME>Vouchers</REPORTNAME>
        <STATICVARIABLES>
          <SVCURRENTCOMPANY>${sanitize(stationName)}</SVCURRENTCOMPANY>
        </STATICVARIABLES>
      </REQUESTDESC>
      <REQUESTDATA>
${vouchers}
      </REQUESTDATA>
    </IMPORTDATA>
  </BODY>
</ENVELOPE>`;

  const blob = new Blob([xml], {type:'application/xml'});
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href = url; a.download = `Tally-${monthName}-${year}.xml`;
  document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
  toast(`Tally XML downloaded — ${fuelSales.length + lubeSales.length} vouchers`, 'success');
}
window.exportTallyXML = exportTallyXML;


// ═══════════════════════════════════════════════════════════════════════════════
// ── ROLE-BASED ACCESS CONTROL ────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════════
// Admin user roles: Owner | Manager | Accountant | Cashier
// APP.adminUser.role controls what pages/actions are visible

const ROLE_PAGES = {
  Owner:      null,  // null = all pages
  Manager:    null,  // null = all pages (same as Owner — full operational access)
  Accountant: ['dashboard','finance','credit','exports','reports','analytics','lubes','insights'],
  Cashier:    ['dashboard','tanks','pumps','sales','lubes'],
};

// Actions blocked per role (used by rbac_can())
const ROLE_BLOCKED_ACTIONS = {
  Owner:      [],
  Manager:    ['reset_data','add_admin_user','close_books'],
  Accountant: ['delete_employee','payroll_pay','reset_data','add_admin_user','add_employee','edit_employee','save_prices','add_tank','delete_tank','add_pump','delete_pump','close_books'],
  Cashier:    ['delete_employee','payroll_pay','reset_data','add_admin_user','add_employee','edit_employee','save_prices','add_tank','delete_tank','add_pump','delete_pump','view_finance','view_payroll','view_staff','credit_edit','view_exports','view_analytics','close_books'],
};

function rbac_role() {
  return APP.adminUser?.role || 'Owner';
}

function rbac_can(action) {
  const blocked = ROLE_BLOCKED_ACTIONS[rbac_role()] || [];
  return !blocked.includes(action);
}

function rbac_pages() {
  const allowed = ROLE_PAGES[rbac_role()];
  return allowed === null ? PAGES.map(p => p.id) : (allowed || []);
}

function rbac_canPage(pageId) {
  return rbac_pages().includes(pageId);
}

// Role badge helper
function roleBadge(role) {
  const map = {
    Owner:      'badge-accent',
    Manager:    'badge-blue',
    Accountant: 'badge-purple',
    Cashier:    'badge-green',
  };
  return badge(role, map[role] || 'badge-blue');
}
window.rbac_can = rbac_can;
window.rbac_canPage = rbac_canPage;
window.roleBadge = roleBadge;
window.rbac_role = rbac_role;


