function navigate(pageId) {
  // RBAC: block pages the current role can't see
  if (APP.loggedIn && APP.role === 'admin' && !rbac_canPage(pageId)) {
    toast('Access denied — your role does not have permission for this', 'error');
    return;
  }
  APP.page = pageId;
  APP.salesFilter = 'all';
  APP.salesDate = (typeof window.today === 'function') ? window.today() : new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10); // FIX 31: IST
  APP.salesEmpFilter = 'all';
  window.location.hash = pageId;
  const _pt = document.getElementById('pageTitle'); if (_pt) _pt.textContent = PAGES.find(p => p.id === pageId)?.label || '';
  updateStationBreadcrumb();
  buildNav();
  renderPage();
  // Close mobile sidebar
  const sidebar = document.getElementById('sidebar');
  const overlay = document.getElementById('mobileOverlay');
  sidebar.classList.remove('mobile-open');
  if (overlay) overlay.style.display = 'none';
}

function buildNav() {
  const groups = { main: 'Operations', finance: 'Finance', employee: 'Employee', reports: 'Reports' };
  let html = '';
  let lastGroup = '';
  const allowedPages = (APP.loggedIn && APP.role === 'admin') ? rbac_pages() : PAGES.map(p=>p.id);
  const isSuperAdminUser = APP.isSuperAdmin || APP.role === 'superadmin';
  PAGES.filter(p => allowedPages.includes(p.id) && (!p.superAdminOnly || isSuperAdminUser)).forEach(p => {
    if (p.group !== lastGroup) {
      html += `<div class="nav-group-label">${groups[p.group]}</div>`;
      lastGroup = p.group;
    }
    html += `<button class="nav-btn ${p.id === APP.page ? 'active' : ''}" onclick="navigate('${p.id}')">
      <span class="nav-icon">${p.icon}</span><span class="nav-label">${p.label}</span>
    </button>`;
  });
  // Role badge in nav footer
  if (APP.loggedIn && APP.role === 'admin' && APP.adminUser?.role) {
    html += `<div style="padding:8px 14px;margin-top:8px;font-size:11px;color:var(--text-3)">Logged in as <span style="font-weight:700;color:var(--text-1)">${sanitize(APP.adminUser.name||'')}</span> · ${roleBadge(APP.adminUser.role)}</div>`;
  }
  document.getElementById('nav').innerHTML = html;
}

function toggleSidebar() {
  const el = document.getElementById('sidebar');
  const overlay = document.getElementById('mobileOverlay');
  if (window.innerWidth < 769) {
    const isOpen = el.classList.toggle('mobile-open');
    if (overlay) overlay.style.display = isOpen ? 'block' : 'none';
  } else {
    APP.sidebarOpen = !APP.sidebarOpen;
    el.classList.toggle('collapsed', !APP.sidebarOpen);
  }
}

