function openEmployeeModal() {
  openModal('➕ Add Employee', empFormHTML('', {}),
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="addEmployee()">💾 Save Employee</button>`);
}

function readEmpPermissions() {
  const perms = {};
  EMP_OPTIONAL_PERMISSIONS.forEach(p => {
    perms[p.id] = !!(document.getElementById('perm_' + p.id)?.checked);
  });
  return perms;
}

async function addEmployee() {
  const name = document.getElementById('empName')?.value?.trim();
  const role = document.getElementById('empRole')?.value;
  const shift = ''; // Shift assigned via Roster, not at employee creation
  const phone = document.getElementById('empPhone')?.value?.trim();
  const salary = parseInt(document.getElementById('empSalary')?.value) || 12000;
  const empId  = (document.getElementById('empEmpId')?.value || '').trim().toUpperCase();
  const aadhar = (document.getElementById('empAadhar')?.value || '').trim().replace(/\s/g, '');
  if (!name || name.length < 2) { toast('Employee name must be at least 2 characters', 'error'); return; }
  if (!phone || phone.length !== 10 || !/^\d{10}$/.test(phone)) { toast('Phone number must be exactly 10 digits', 'error'); return; }
  if (empId && APP.data.employees.some(e => e.empId && e.empId.toUpperCase() === empId)) {
    toast('Employee ID "' + empId + '" is already taken — use a unique ID', 'error'); return;
  }
  if (aadhar && !/^\d{12}$/.test(aadhar)) { toast('Aadhar must be exactly 12 digits', 'error'); return; }
  const permissions = readEmpPermissions();
  const newEmp = {
    id: Date.now(), name, role, shift, phone: phone || '', salary,
    empId: empId || '', aadhar: aadhar || '',
    permissions,
    color: EMP_COLORS[APP.data.employees.length % EMP_COLORS.length]
  };
  try {
    const insertedId = await db.add('employees', newEmp);
    if (insertedId !== undefined && insertedId !== null) newEmp.id = insertedId;
    APP.data.employees.push(newEmp);
    closeModal();
    const granted = Object.entries(permissions).filter(([,v])=>v).map(([k])=>EMP_OPTIONAL_PERMISSIONS.find(p=>p.id===k)?.label).filter(Boolean);
    toast(`${name} added · ${granted.length ? granted.join(', ') : 'No extra permissions'}`, 'success');
    renderPage();
  } catch (e) {
    toast((e && e.message) ? e.message : 'Failed to save employee', 'error');
  }
}

function openEditEmployeeModal(empId) {
  const D = APP.data;
  const e = D.employees.find(x => x.id === empId);
  if (!e) { toast('Employee not found — please refresh and try again', 'error'); return; }
  openModal('✏️ Edit Employee',
    `<input type="hidden" id="editEmpId" value="${empId}" />` + empFormHTML('', e),
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="saveEditEmployee()">💾 Save Changes</button>`
  );
}

async function saveEditEmployee() {
  const empId = parseInt(document.getElementById('editEmpId')?.value);
  const name = document.getElementById('empName')?.value?.trim();
  const role = document.getElementById('empRole')?.value;
  const phone = document.getElementById('empPhone')?.value?.trim();
  const salary = parseInt(document.getElementById('empSalary')?.value) || 12000;
  const empEmpId = (document.getElementById('empEmpId')?.value || '').trim().toUpperCase();
  const empAadhar = (document.getElementById('empAadhar')?.value || '').trim().replace(/\s/g, '');
  if (!name || name.length < 2) { toast('Name must be at least 2 characters', 'error'); return; }
  if (!phone || phone.length !== 10 || !/^\d{10}$/.test(phone)) { toast('Phone number must be exactly 10 digits', 'error'); return; }
  if (empEmpId && APP.data.employees.some(e => parseInt(e.id) !== empId && e.empId && e.empId.toUpperCase() === empEmpId)) {
    toast('Employee ID "' + empEmpId + '" is already taken — use a unique ID', 'error'); return;
  }
  if (empAadhar && !/^\d{12}$/.test(empAadhar)) { toast('Aadhar must be exactly 12 digits', 'error'); return; }
  if (!name || name.length < 2) { toast('Name must be at least 2 characters', 'error'); return; }
  const D = APP.data;
  const idx = D.employees.findIndex(x => parseInt(x.id) === parseInt(empId));
  if (idx === -1) { toast('Employee not found — please refresh and try again', 'error'); return; }
  const permissions = readEmpPermissions();
  const oldEmp = D.employees[idx];
  const oldName = oldEmp.name;
  const oldShift = oldEmp.shift;

  // Preserve existing shift — shift is managed via Roster, not this form
  D.employees[idx] = { ...oldEmp, name, role, shift: oldShift||'', phone: phone||'', salary, empId: empEmpId||oldEmp.empId||'', aadhar: empAadhar||oldEmp.aadhar||'', permissions };
  try { await db.put('employees', D.employees[idx]); } catch(e) { console.warn('[EditEmployee]', e.message); }

  // FIX 4: propagate name change everywhere
  if (oldName !== name) {
    // Update sales records
    if (D.sales) D.sales.forEach(s => {
      if (s.employee === oldName) { s.employee = name; s.employeeName = name; s.employee_name = name; }
    });
    // Update audit log
    if (APP.auditLog) APP.auditLog.forEach(a => { if (a.user === oldName) a.user = name; if (a.details?.employee === oldName) a.details.employee = name; });
    // Update shift manager names
    if (D.shifts) {
      for (const s of D.shifts) {
        if (s.manager === oldName) { s.manager = name; try { await db.put('shifts', s); } catch(e) {} }
      }
    }
  }

  // FIX 7: if shift changed, de-allocate that employee from all nozzles
  if (oldShift !== newShift) {
    let deallocs = 0;
    Object.keys(allocations).forEach(shiftName => {
      const shiftObj = allocations[shiftName];
      Object.keys(shiftObj).forEach(nozzleKey => {
        if (shiftObj[nozzleKey] === oldEmp.id) {
          delete shiftObj[nozzleKey];
          deallocs++;
        }
      });
    });
    saveAllocations();
    if (deallocs > 0) {
      toast(`${name} moved to ${newShift} shift — ${deallocs} nozzle allocation${deallocs>1?'s':''} cleared. Please re-assign.`, 'warning');
    } else {
      toast(`${name} updated — shift changed to ${newShift}`, 'success');
    }
  } else {
    toast(`${name} updated`, 'success');
  }

  closeModal();
  renderPage();
}

function openSetPINModal(empId) {
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) { toast('Employee not found — please refresh and try again', 'error'); return; }
  const hasPIN = !!getEmpPinHash(empId);
  const bioAlreadyReg = emp_bioIsRegistered(empId);
  const bioSection = window.PublicKeyCredential
    ? '<div style="margin-top:14px;padding-top:14px;border-top:1px solid var(--border)"><div style="font-size:11px;font-weight:700;color:var(--text-3);margin-bottom:8px;text-transform:uppercase">Biometric Login (Optional)</div><button class="btn btn-ghost btn-block" id="bioRegBtn" onclick="emp_bioRegisterFromModal()" style="border:1px dashed var(--border);font-size:13px;padding:10px">' + (bioAlreadyReg ? '✅ Registered — tap to re-register' : '🔒 Register fingerprint / Face ID') + '</button><div style="font-size:10px;color:var(--text-3);margin-top:5px">Employee must be present on their device. Set PIN first.</div></div>'
    : '';
  openModal(`🔑 Set PIN — ${sanitize(emp.name)}`,
    `<div style="margin-bottom:12px;padding:12px;background:var(--bg-0);border-radius:var(--radius-sm);border:1px solid var(--border-light);font-size:12px;color:var(--text-2)">
      ${hasPIN ? '🔄 <strong style="color:var(--accent-light)">A PIN is already set.</strong> Enter a new PIN below to change it.' : '⚠️ <strong style="color:var(--orange)">No PIN set yet.</strong> This employee cannot log in until a PIN is assigned.'}
    </div>
    <div class="form-group"><label class="form-label">New 4-Digit PIN *</label>
      <input class="form-input mono" id="newPIN" type="password" inputmode="numeric" maxlength="4" placeholder="••••" style="font-size:24px;letter-spacing:8px;text-align:center" />
    </div>
    <div class="form-group"><label class="form-label">Confirm PIN *</label>
      <input class="form-input mono" id="confirmPIN" type="password" inputmode="numeric" maxlength="4" placeholder="••••" style="font-size:24px;letter-spacing:8px;text-align:center" />
    </div>
    <input type="hidden" id="setPINEmpId" value="${empId}" />
    ${bioSection}`,
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="saveEmployeePIN()">🔑 Set PIN</button>`
  );
  // Fix (e): auto-focus the new PIN input
  requestAnimationFrame(() => { const el = document.getElementById('newPIN'); if (el) el.focus(); });
}

async function emp_bioRegisterFromModal() {
  const empId = parseInt(document.getElementById('setPINEmpId')?.value);
  if (!empId) { toast('Set and save a PIN before registering biometrics', 'error'); return; }
  const btn = document.getElementById('bioRegBtn');
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Waiting for biometric…'; }
  const ok = await emp_bioRegister(empId);
  if (btn) {
    btn.disabled = false;
    btn.textContent = ok ? '✅ Biometric registered — tap to re-register' : '🔒 Register fingerprint / Face ID for this employee';
  }
}
async function saveEmployeePIN() {
  const empId = parseInt(document.getElementById('setPINEmpId')?.value);
  const pin = document.getElementById('newPIN')?.value?.trim();
  const confirm = document.getElementById('confirmPIN')?.value?.trim();
  if (!pin || pin.length !== 4 || !/^\d{4}$/.test(pin)) { toast('PIN must be exactly 4 digits (numbers only)', 'error'); return; }
  if (pin !== confirm) { toast('PIN MISMATCH — both entries must be identical', 'error'); return; }
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) { toast('Employee not found — please refresh and try again', 'error'); return; }
  try {
    const hash = await sha256(pin);
    emp.pinHash = hash;
    await db.put('employees', emp);
    const pins = loadEmpPins();
    pins[empId] = hash;
    saveEmpPins(pins);
    const freshEmps = await db.getAll('employees').catch(() => null);
    if (freshEmps && freshEmps.length) APP.data.employees = freshEmps;
    // Refresh employee cache so login screen picks up new PIN immediately
    getEmpList(); // triggers cache update
    closeModal();
    toast(`PIN set for ${emp.name}`, 'success');
    renderPage();
  } catch(err) {
    toast('Failed to set PIN: ' + (err.message||err), 'error');
  }
}

async function sha256(str) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('');
}

function confirmDeleteEmployee(empId) {
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) return;
  openModal('🗑 Delete Employee',
    `<div style="text-align:center;padding:20px 0">
      <div style="font-size:40px;margin-bottom:12px">⚠️</div>
      <div style="font-size:16px;font-weight:700;color:var(--text-0);margin-bottom:8px">Delete ${sanitize(emp.name)}?</div>
      <div style="font-size:13px;color:var(--text-2)">This will permanently remove the employee and their login PIN. This cannot be undone.</div>
    </div>
    <input type="hidden" id="deleteEmpId" value="${empId}" />`,
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-red" onclick="deleteEmployee()">🗑 Yes, Delete</button>`
  );
}

async function deleteEmployee() {
  const empId = parseInt(document.getElementById('deleteEmpId')?.value);
  const D = APP.data;
  const emp = D.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) return;
  const name = emp.name;
  D.employees = D.employees.filter(e => e.id !== empId);
  try { await db.delete('employees', empId); } catch(e) { console.warn('[deleteEmployee]', e.message); }
  const pins = loadEmpPins();
  delete pins[empId];
  saveEmpPins(pins);
  closeModal();
  toast(`${name} removed`, 'success');
  renderPage();
}

